window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["backflow"] = window.COURSE_LANG["backflow"] || {};
window.COURSE_LANG["backflow"]["ru"] = [
  {id:1, q:"Что такое перекрёстное соединение?", opts:["Любое фактическое или потенциальное соединение между системой питьевой воды и источником загрязнения или заражения","Стык трубы, который протекает под давлением","Клапан, понижающий давление воды у точки обслуживания","Воздушный разрыв между выпуском и кромкой сантехнического прибора"], re:"Руководство EPA по контролю перекрёстных соединений и AWWA M14 определяют перекрёстное соединение как любое фактическое или потенциальное соединение между системой питьевой воды и любым источником загрязнения или заражения."},
  {id:2, q:"Садовый шланг, оставленный погружённым в ведро с мыльной водой, является примером:", opts:["Воздушного разрыва, одобренного нормами","Косвенного перекрёстного соединения","Узла изоляции объекта","Только прямого соединения"], re:"Руководство EPA CCC: шланг, погружённый в непитьевой источник, является классическим косвенным (с погружённым впуском) перекрёстным соединением, которое может допустить обратный сифонаж."},
  {id:3, q:"Прямое (со сплошной трубой) перекрёстное соединение — это такое, при котором:", opts:["Всегда присутствует воздушный разрыв","Вода только переливается через воздух в сосуд","Линия питьевой воды физически и постоянно соединена трубой с непитьевой системой","Обратный поток никогда не может возникнуть"], re:"AWWA M14 / Руководство EPA CCC: прямое перекрёстное соединение — это постоянное трубное соединение между питьевой и непитьевой системами, и оно может испытывать как противодавление, так и обратный сифонаж."},
  {id:4, q:"Косвенное перекрёстное соединение (такое как погружённый впуск) обычно подвержено:", opts:["Ни обратному сифонажу, ни противодавлению","Только противодавлению","Только электролизу","Только обратному сифонажу"], re:"USC FCCCHR / Руководство EPA CCC: косвенные перекрёстные соединения (с погружённым впуском), открытые в атмосферу, могут испытывать только обратный сифонаж, тогда как прямые соединения могут видеть оба режима."},
  {id:5, q:"Какая ситуация является опасностью перекрёстного соединения?", opts:["Линия подачи химикатов, прочно соединённая с питьевым водоснабжением","Излив крана, оканчивающийся значительно выше кромки раковины","Воздушный разрыв над кромкой раковины для швабр","Манометр, врезанный через тройник в линию чистой воды"], re:"Руководство EPA CCC: линия подачи химикатов или технологическая линия, соединённая с питьевым трубопроводом, является перекрёстным соединением, поскольку непитьевое вещество может реверсировать в питьевую воду."},
  {id:6, q:"Почему перекрёстные соединения являются проблемой для здоровья населения?", opts:["Они увеличивают счёт за воду","Они могут позволить непитьевым веществам попасть в систему питьевого водоснабжения","Они только понижают давление воды","Они вызывают шум в трубах"], re:"Руководство EPA CCC: в условиях обратного потока перекрёстное соединение может втянуть или протолкнуть заражающие и загрязняющие вещества в питьевое водоснабжение, угрожая здоровью населения."},
  {id:7, q:"Система полива газона, подключённая к питьевой воде здания, считается перекрёстным соединением, потому что:", opts:["Поливочная вода всегда чище водопроводной","Дождеватели не могут удерживать давление","Почва, удобрения и пестициды могут быть втянуты обратно в питьевую воду","Она использует меньше воды, чем сантехнические приборы"], re:"Руководство EPA CCC: системы полива являются распространёнными перекрёстными соединениями; обратный поток может втянуть заражённую воду с почвенными бактериями, удобрениями или пестицидами в питьевое водоснабжение."},
  {id:8, q:"Термин 'питьевая вода' означает воду, которая:", opts:["Хранится в безнапорном резервуаре","Используется только для полива","Переработана из градирни","Безопасна для потребления человеком и соответствует стандартам питьевой воды"], re:"AWWA M14: питьевая вода — это вода, безопасная для потребления человеком и соответствующая применимым стандартам качества питьевой воды."},
  {id:9, q:"'Непитьевая вода' лучше всего описывается как вода, которая:", opts:["Небезопасна или не одобрена для потребления человеком","Всегда заметно грязная","Идентична питьевой воде","Встречается только в противопожарных линиях"], re:"AWWA M14: непитьевая вода — это вода, которую небезопасно пить или которая не имеет одобренного качества питьевой воды, независимо от того, как она выглядит."},
  {id:10, q:"Что из следующего является наиболее распространённым повседневным перекрёстным соединением в доме?", opts:["Закопанная медная линия обслуживания","Садовый шланг","Редукционный клапан давления","Счётчик воды"], re:"Руководство EPA CCC / USC FCCCHR: обычный садовый шланг — самое распространённое бытовое перекрёстное соединение, поскольку он легко погружается в заражённые источники."},
  {id:11, q:"Котёл с химически обработанной водой, подключённый трубой к питьевому водоснабжению для подпитки, представляет собой:", opts:["Безопасную схему, не требующую защиты","Одобренный воздушный разрыв сам по себе","Перекрёстное соединение, которое должно быть защищено от обратного потока","Состояние, влияющее только на вкус горячей воды"], re:"Руководство EPA CCC: линия подпитки обработанного котла является перекрёстным соединением; обработанная котловая вода — это опасность, которую необходимо изолировать соответствующим устройством защиты от обратного потока."},
  {id:12, q:"Что лучше всего отличает прямое перекрёстное соединение от косвенного?", opts:["Реальной разницы нет","Прямые всегда временные","Косвенные всегда являются трубами большего размера","Прямые соединены трубой; косвенные сбрасывают через открытую атмосферу или погружённый впуск"], re:"AWWA M14 / Руководство EPA CCC: прямое перекрёстное соединение — это постоянная трубная связь; косвенное возникает на открытом или погружённом впуске, таком как шланг или наполнение резервуара."},
  {id:13, q:"Умывальник, где выпуск крана находится ниже кромки перелива, создаёт:", opts:["Погружённый впуск, который является перекрёстным соединением","Надлежащий воздушный разрыв","Точку изоляции объекта","Зону пониженного давления"], re:"Руководство EPA CCC: когда выпуск может быть погружён ниже кромки перелива, требуемый воздушный разрыв теряется и возникает перекрёстное соединение с погружённым впуском."},
  {id:14, q:"Контроль перекрёстных соединений в первую очередь занимается защитой:", opts:["Гарантии на водонагреватель клиента","Системы общественного питьевого водоснабжения от заражения","Счётчика воды от замерзания","Канализационных труб от обрушения"], re:"Руководство EPA CCC / Справочник политики контроля перекрёстных соединений SWRCB Калифорнии: цель контроля перекрёстных соединений — защитить систему общественного питьевого водоснабжения от заражения обратным потоком."},
  {id:15, q:"Какое утверждение о перекрёстных соединениях является верным?", opts:["Они могут быть только на промышленных объектах","Они существуют только при активном обратном течении","Потенциальное соединение учитывается, даже если обратный поток в данный момент не происходит","Они всегда видны клиенту"], re:"AWWA M14 / Руководство EPA CCC: перекрёстное соединение включает любое фактическое ИЛИ потенциальное соединение; опасность существует независимо от того, происходит ли обратный поток в данный момент."},
  {id:16, q:"Спринклерная система противопожарной защиты, подключённая к питьевому водоснабжению, является перекрёстным соединением главным образом потому, что:", opts:["Спринклерная вода всегда находится под более высоким давлением, чем магистраль, в любой момент","Она устраняет необходимость в счётчике","Спринклерная труба всегда металлическая","Застойная вода и присадки в системе могут перетечь обратно в питьевое водоснабжение"], re:"Руководство EPA CCC / AWWA M14: противопожарные системы удерживают застойную воду и иногда присадки; без защиты эта вода может перетечь обратно в питьевое водоснабжение."},
  {id:17, q:"Фраза 'вспомогательный источник воды' в работе с перекрёстными соединениями относится к:", opts:["Любому источнику воды, отличному от общественной системы водоснабжения, такому как скважина или хранимая вода","Второму питьевому счётчику","Резервному источнику электропитания","Только подключению пожарной службы"], re:"AWWA M14 / Раздел 17 Калифорнии: вспомогательный источник воды — это любой источник, отличный от общественной системы водоснабжения (скважина, пруд, рекуперированная, хранимая вода), который мог бы перетечь обратно в питьевое водоснабжение."},
  {id:18, q:"Обратный поток лучше всего определяется как:", opts:["Нормальное прямое течение воды в магистрали","Нежелательная реверсия течения от его предполагаемого направления через перекрёстное соединение","Гидравлический удар в закрытой системе","Падение давления на счётчике"], re:"AWWA M14 / Руководство EPA CCC: обратный поток — это нежелательная реверсия нормального направления течения воды или других веществ через перекрёстное соединение в питьевое водоснабжение."},
  {id:19, q:"Обратный сифонаж вызывается:", opts:["Насосом ниже по потоку, проталкивающим воду обратно","Обратным клапаном, удерживаемым открытым мусором","Отрицательным (поднижеатмосферным) давлением в подающем трубопроводе","Тепловым расширением горячей воды"], re:"Руководство EPA CCC / AWWA M14: обратный сифонаж возникает из-за отрицательного или пониженного давления (частичного вакуума) в системе подачи, который засасывает воду обратно через перекрёстное соединение."},
  {id:20, q:"Обратный поток из-за противодавления возникает, когда:", opts:["Давление подачи превышает давление ниже по потоку","Водопроводная магистраль перекрыта","Установлен воздушный разрыв","Давление ниже по потоку становится больше давления подачи"], re:"AWWA M14 / Руководство EPA CCC: обратный поток из-за противодавления происходит, когда давление со стороны клиента (от насоса, котла или поднятого резервуара) превышает давление подачи и преодолевает его."},
  {id:21, q:"Какое событие является типичной причиной обратного сифонажа?", opts:["Разрыв водопроводной магистрали или высокий спрос на пожаротушение поблизости","Подкачивающий насос на стороне клиента","Поднятый накопительный резервуар на крыше","Паровой котёл"], re:"Руководство EPA CCC: разрывы магистрали, промывка гидрантов и высокий спрос на пожаротушение понижают давление подачи и могут создать частичный вакуум, вызывающий обратный сифонаж."},
  {id:22, q:"Какой источник чаще всего создаёт противодавление?", opts:["Открываемый поблизости пожарный гидрант","Насос, котёл или поднятый резервуар на стороне клиента","Разрыв в городской магистрали","Промывка распределительной системы"], re:"AWWA M14 / Руководство EPA CCC: насосы, котлы, напорные сосуды и поднятые трубопроводы или резервуары на стороне клиента повышают давление ниже по потоку выше магистрали и вызывают противодавление."},
  {id:23, q:"Повседневная аналогия 'питья через соломинку' лучше всего описывает:", opts:["Противодавление","Воздушный разрыв","Обратный сифонаж","Гидравлический удар"], re:"Руководство EPA CCC: обратный сифонаж работает как всасывание через соломинку, где пониженное давление (всасывание) тянет жидкость обратно вверх по линии."},
  {id:24, q:"Прямое перекрёстное соединение может испытывать:", opts:["Только обратный сифонаж","Только противодавление","Ни одно из состояний","Как обратный сифонаж, так и противодавление"], re:"AWWA M14 / USC FCCCHR: поскольку прямое перекрёстное соединение прочно соединено трубой, оно может быть подвержено как противодавлению, так и обратному сифонажу."},
  {id:25, q:"Во время крупного разрыва водопроводной магистрали потеря давления в распределительной системе может вызвать:", opts:["Обратный сифонаж, который тянет заражающие вещества к магистрали","Противодавление от котлов","Увеличение остаточного хлора","Гидравлический удар только в противопожарных линиях"], re:"Руководство EPA CCC: разрыв магистрали понижает давление в системе и может создать вакуум, втягивая заражённую воду обратно через незащищённые перекрёстные соединения (обратный сифонаж)."},
  {id:26, q:"Противодавление наиболее вероятно там, где система клиента включает:", opts:["Только самотёчные сантехнические приборы","Источник давления, такой как насос или напорный сосуд","Один шланговый кран","Простой кухонный кран"], re:"AWWA M14: противодавление требует расположенного ниже по потоку источника более высокого давления, такого как подкачивающий насос, циркуляционный насос или напорный резервуар либо котёл."},
  {id:27, q:"Что является распространённой причиной отрицательного давления, ведущего к обратному сифонажу?", opts:["Медленное наполнение накопительного резервуара","Закрытый запорный клапан у одного сантехнического прибора","Событие высокого спроса, такое как пожаротушение, понижающее давление в магистрали","Нормальный низкий ночной спрос"], re:"Руководство EPA CCC: внезапный высокий отбор (пожаротушение, промывка магистрали) или разрыв магистрали может понизить давление ниже атмосферного, вызывая обратный сифонаж."},
  {id:28, q:"Два признанных типа обратного потока — это:", opts:["Статическое и динамическое течение","Обратный поток и перелив","Сифонное и самотёчное течение","Обратный сифонаж и противодавление"], re:"AWWA M14 / Руководство EPA CCC: обратный поток происходит ровно по двум механизмам: обратный сифонаж (пониженное давление подачи) и противодавление (повышенное давление ниже по потоку)."},
  {id:29, q:"Поднятый на крыше резервуар, жёстко соединённый трубой с питьевым водоснабжением, может создать:", opts:["Противодавление от статического напора поднятой воды","Только обратный сифонаж","Воздушный разрыв","Зону пониженного давления"], re:"AWWA M14 / Руководство EPA CCC: статический напор поднятого резервуара или столба воды может превысить давление подачи и протолкнуть воду обратно — состояние противодавления."},
  {id:30, q:"Какое утверждение верно об обратном сифонаже?", opts:["Он требует насоса на стороне клиента","Он вызывается падением давления на стороне подачи","Он не может возникнуть во время разрыва магистрали","Он влияет только на линии горячей воды"], re:"Руководство EPA CCC: обратный сифонаж вызывается исключительно понижением давления на стороне подачи (частичным вакуумом), а не какой-либо перекачкой ниже по потоку."},
  {id:31, q:"Устройство защиты от обратного потока, выбранное для остановки противодавления, должно быть способно:", opts:["Полагаться только на гравитацию","Работать только при наличии вакуума","Удерживать поток, даже когда давление ниже по потоку превышает давление подачи","Устанавливаться без каких-либо обратных клапанов"], re:"AWWA M14: узлы, рассчитанные на противодавление (такие как узлы RP и двойного обратного клапана), должны герметизировать против более высокого давления ниже по потоку, в отличие от вакуумных прерывателей, рассчитанных только на обратный сифонаж."},
  {id:32, q:"Почему важно определить тип обратного потока при выборе защиты?", opts:["Это меняет размер счётчика","Это не влияет на выбор устройства","Это определяет счёт за воду","Некоторые устройства останавливают только обратный сифонаж, тогда как другие также справляются с противодавлением"], re:"AWWA M14 / USC FCCCHR: выбор устройства зависит от режима обратного потока; например, атмосферные вакуумные прерыватели защищают только от обратного сифонажа, но не от противодавления."},
  {id:33, q:"Поднижеатмосферное давление в водяной линии означает, что давление:", opts:["Ниже атмосферного давления (частичный вакуум)","Выше давления подающей магистрали","Точно равно атмосферному давлению","Такое же, как давление ниже по потоку"], re:"Руководство EPA CCC: поднижеатмосферное (отрицательное) давление ниже атмосферного, создавая частичный вакуум, ответственный за обратный сифонаж."},
  {id:34, q:"Подкачивающий насос, поднимающий давление у клиента выше городской магистрали, может создать:", opts:["Обратный сифонаж","Обратный поток из-за противодавления, если обратный клапан подачи отказывает или отсутствует","Воздушный разрыв","Условия меньшей опасности"], re:"AWWA M14 / Руководство EPA CCC: подкачивающий насос клиента может поднять давление выше магистрали и вызвать обратный поток из-за противодавления, если не установлено адекватное устройство защиты."},
  {id:35, q:"В терминологии перекрёстных соединений 'степень опасности' относится к:", opts:["Тому, как далеко узел находится от счётчика","Диаметру трубы","Тому, является ли вещество загрязнителем (не для здоровья) или заражающим веществом (опасность для здоровья)","Давлению воды в psi"], re:"USC FCCCHR / AWWA M14: степень опасности классифицирует перекрёстное соединение по задействованному веществу — либо загрязнитель (опасность не для здоровья), либо заражающее вещество (опасность для здоровья)."},
  {id:36, q:"'Заражающее вещество' в контроле перекрёстных соединений — это вещество, которое:", opts:["Влияет только на вкус, запах или цвет","Безвредно в любом количестве","Всегда понижает давление воды","Может создать опасность для здоровья, вызывая болезнь или смерть, если попадёт в воду"], re:"USC FCCCHR / Руководство EPA CCC: заражающее вещество — это опасность для здоровья; если оно попадёт в питьевое водоснабжение, оно может вызвать болезнь или смерть (например сточные воды или пестициды)."},
  {id:37, q:"'Загрязнитель' в контроле перекрёстных соединений — это вещество, которое:", opts:["Ухудшило бы качество воды или было бы неприемлемым, но не является опасностью для здоровья","Всегда вызывает заболевание","То же самое, что заражающее вещество","Вообще не может повлиять на воду"], re:"USC FCCCHR / AWWA M14: загрязнитель — это опасность не для здоровья (низкая опасность), которая ухудшает качество или эстетически неприемлема, но не угрожает здоровью."},
  {id:38, q:"Что считается перекрёстным соединением ВЫСОКОЙ опасности (для здоровья)?", opts:["Пищевая линия газированного напитка","Соединение с источником сточных или канализационных вод","Линия холодной воды к питьевому фонтанчику","Чистый сборник дождевой воды на крыше только для полива"], re:"USC FCCCHR / Руководство EPA CCC: соединение со сточными или канализационными водами является серьёзной опасностью для здоровья, поскольку патогены могут попасть в питьевое водоснабжение."},
  {id:39, q:"Опасность не для здоровья (загрязнитель) обычно защищается воздушным разрывом, узлом пониженного давления ИЛИ:", opts:["Вообще без защиты","Простым запорным клапаном","Узлом двойного обратного клапана","Манометром"], re:"USC FCCCHR / AWWA M14: низкие опасности (не для здоровья) могут защищаться воздушным разрывом, узлом RP или узлом двойного обратного клапана; высокие опасности требуют воздушного разрыва или узла RP."},
  {id:40, q:"Перекрёстное соединение ВЫСОКОЙ опасности (для здоровья) должно быть защищено по меньшей мере:", opts:["Только вакуумным прерывателем шлангового крана","Только обратным клапаном","Только узлом двойного обратного клапана","Воздушным разрывом или узлом принципа пониженного давления"], re:"USC FCCCHR / Раздел 17 Калифорнии: перекрёстные соединения с опасностью для здоровья требуют наивысшей защиты — воздушного разрыва или узла принципа пониженного давления (RP)."},
  {id:41, q:"Кто обычно определяет степень опасности на объекте клиента?", opts:["Поставщик воды или его программа контроля перекрёстных соединений посредством обследования","Только сам клиент","Сантехник, установивший приборы","Пожарная служба"], re:"Раздел 17 Калифорнии / Справочник политики CCC SWRCB: поставщик воды оценивает степень опасности посредством обследований и назначает требуемый уровень защиты."},
  {id:42, q:"Какой класс веществ обычно рассматривается как заражающее вещество (опасность для здоровья)?", opts:["Эстетическое обесцвечивание от безвредных минералов","Сточные воды, химикаты или пестициды","Пузырьки воздуха в линии","Слегка тёплая вода"], re:"USC FCCCHR / Руководство EPA CCC: сточные воды, токсичные химикаты и пестициды являются заражающими веществами, поскольку они представляют прямую опасность для здоровья при обратном потоке."},
  {id:43, q:"Выбор устройства защиты от обратного потока должен быть 'соразмерным степени опасности', что означает:", opts:["Использовать самое дешёвое доступное устройство","Всегда использовать самое маленькое устройство","Сопоставить уровень защиты с тем, насколько опасно вещество","Уровень защиты не зависит от опасности"], re:"Раздел 17 Калифорнии / AWWA M14: тип защиты должен быть соразмерным степени опасности, поэтому более высокие опасности требуют узлов с более высоким классом."},
  {id:44, q:"Соединение, которое вызвало бы только неприемлемый вкус или запах без риска для здоровья, классифицируется как:", opts:["Опасность для здоровья","Опасность сточных вод","Смертельная опасность","Опасность не для здоровья (загрязнитель)"], re:"USC FCCCHR: вещество, влияющее только на вкус, запах или внешний вид без угрозы для здоровья, является опасностью не для здоровья (загрязнителем)."},
  {id:45, q:"Почему соединение с опасностью для здоровья никогда не должно защищаться устройством, рассчитанным только на загрязнители?", opts:["Устройство с более низким классом может ненадёжно остановить опасное заражающее вещество","Это стоило бы слишком мало","Устройства для загрязнителей незаконны повсюду","Разницы в защите нет"], re:"USC FCCCHR / AWWA M14: недостаточная защита опасности для здоровья рискует допустить опасное заражающее вещество в питьевое водоснабжение, поэтому узел должен соответствовать опасности."},
  {id:46, q:"Что из этого наиболее вероятно является НИЗКОЙ опасностью (не для здоровья)?", opts:["Медицинский аспиратор","Соединение с системой газонных дождевателей без инъекции химикатов","Соединение с химической ванной гальванопокрытия","Стол морга"], re:"Руководство EPA CCC: базовая система газонных дождевателей без добавленных химикатов обычно является низкой опасностью, тогда как медицинские, гальванические и моргевые соединения являются высокими опасностями."},
  {id:47, q:"Когда опасность на объекте неопределённа или может измениться, программа обычно:", opts:["Игнорирует соединение","Удаляет всю защиту","Рассматривает её как более высокую опасность для безопасности","Понижает уровень защиты"], re:"AWWA M14 / Справочник политики CCC SWRCB: когда опасность неизвестна или переменна, консервативный подход — предполагать более высокую опасность и защищать соответственно."},
  {id:48, q:"Система инъекции химикатов (такая как инжектор удобрений в системе полива) повышает опасность, потому что она:", opts:["Понижает давление в линии","Делает воду питьевой","Автоматически добавляет воздушный разрыв","Вводит токсичные химикаты, которые могли бы перетечь обратно в питьевое водоснабжение"], re:"Руководство EPA CCC / USC FCCCHR: добавление инъекции химикатов превращает в остальном низкоопасную систему полива в опасность для здоровья, требуя узел RP или воздушный разрыв."},
  {id:49, q:"Термины 'опасность для здоровья' и 'опасность не для здоровья' соответствуют соответственно:", opts:["Заражающему веществу и загрязнителю","Загрязнителю и заражающему веществу","Прямому и косвенному","Противодавлению и обратному сифонажу"], re:"USC FCCCHR / AWWA M14: опасность для здоровья — это заражающее вещество; опасность не для здоровья — это загрязнитель."},
  {id:50, q:"Назначение степени опасности важно, потому что оно:", opts:["Устанавливает тариф на воду для клиента","Определяет тип и минимальный класс требуемой защиты от обратного потока","Определяет цвет счётчика","Не имеет практического значения"], re:"Раздел 17 Калифорнии / AWWA M14: степень опасности напрямую определяет, какой метод предотвращения обратного потока приемлем для соединения."},
  {id:51, q:"Воздушный разрыв — это:", opts:["Механический обратный клапан","Порт сброса давления","Физическое вертикальное разделение между выпуском воды и кромкой перелива принимающего сосуда","Тип шлангового соединения"], re:"AWWA M14 / Руководство EPA CCC: воздушный разрыв — это беспрепятственное вертикальное физическое разделение между самой нижней точкой выпуска воды и кромкой перелива приёмника под ним."},
  {id:52, q:"Минимальный воздушный разрыв обычно составляет:", opts:["Равен диаметру выпуска","Не менее четырёхкратного диаметра трубы, минимум 3 дюйма","Ровно 1/2 дюйма во всех случаях","Не менее двойного диаметра эффективного отверстия, но никогда не менее 1 дюйма"], re:"AWWA M14 / Единый сантехнический кодекс / CA HSC: минимальный воздушный разрыв — это двойной диаметр эффективного отверстия и ни в коем случае не менее 1 дюйма (правило '2D, никогда не менее 1 дюйма')."},
  {id:53, q:"Воздушный разрыв защищает от:", opts:["Как обратного сифонажа, так и противодавления","Только противодавления","Только обратного сифонажа","Ни одного из типов обратного потока"], re:"AWWA M14 / Руководство EPA CCC: правильно подобранный по размеру воздушный разрыв является наиболее надёжным методом и защищает как от обратного сифонажа, так и от противодавления, поскольку нет физического трубного пути."},
  {id:54, q:"Воздушный разрыв обычно считается:", opts:["Наименее эффективной защитой от обратного потока","Максимальной (самой надёжной) защитой от обратного потока","Равным вакуумному прерывателю шлангового крана","Полезным только для низкого давления"], re:"AWWA M14 / USC FCCCHR: при правильной установке и обслуживании воздушный разрыв обеспечивает наивысшую степень защиты из всех методов."},
  {id:55, q:"Воздушный разрыв измеряется от:", opts:["Верха ручки крана до пола","Центра трубы до стены","Самой нижней точки выпуска воды вниз до кромки перелива сантехнического прибора","Выпуска до дна раковины"], re:"AWWA M14 / UPC: воздушный разрыв — это вертикальное расстояние от самого нижнего отверстия подающего выпуска до кромки перелива принимающего сосуда."},
  {id:56, q:"Ключевое ограничение воздушного разрыва как защиты от обратного потока заключается в том, что он:", opts:["Не может остановить противодавление","Работает только выше 80 psi","Требует ежегодных электрических испытаний","Может быть легко сведён на нет добавлением шланга или удлинителя к выпуску"], re:"Руководство EPA CCC: хотя воздушный разрыв высокоэффективен, он легко обходится (например подсоединением шланга), поэтому он должен поддерживаться и не модифицироваться."},
  {id:57, q:"Если выпуск воды погружается ниже кромки перелива, воздушный разрыв:", opts:["Устраняется, создавая перекрёстное соединение","Увеличивается","Удваивается","Не затрагивается"], re:"AWWA M14 / Руководство EPA CCC: как только выпуск находится на уровне или ниже кромки перелива, это погружённый впуск; воздушный разрыв больше не существует и образуется перекрёстное соединение."},
  {id:58, q:"Для эффективного отверстия 1 дюйм минимальный воздушный разрыв составил бы:", opts:["1/2 дюйма","2 дюйма","1 дюйм","4 дюйма"], re:"AWWA M14 / UPC: двойной размер эффективного отверстия в 1 дюйм равен 2 дюймам, что также удовлетворяет минимуму в 1 дюйм, поэтому требуемый разрыв составляет 2 дюйма."},
  {id:59, q:"Для очень малого выпуска (например 1/4 дюйма) минимальный воздушный разрыв составляет:", opts:["1/2 дюйма (двойной размер отверстия)","1/4 дюйма","1 дюйм, потому что разрыв никогда не бывает менее 1 дюйма","Ноль"], re:"AWWA M14 / UPC: двойной размер 1/4 дюйма составляет только 1/2 дюйма, но правило устанавливает абсолютный минимум 1 дюйм, поэтому действует 1 дюйм."},
  {id:60, q:"Близко расположенная к выпуску стена влияет на требование к воздушному разрыву тем, что:", opts:["Уменьшает требуемый разрыв","Устраняет необходимость в разрыве","Не имеет эффекта","Увеличивает требуемый разрыв, потому что стена может нарушить воздушное разделение"], re:"UPC / сантехнический кодекс: близкая стена может помешать свободному воздушному пути, поэтому нормы требуют большего воздушного разрыва (например 3-кратного диаметра), когда выпуск находится близко к стене."},
  {id:61, q:"Что лучше всего описывает, почему воздушный разрыв не может быть преодолён давлением?", opts:["Нет физической трубы, соединяющей две стороны, поэтому путь давления не существует","Он использует подпружиненный обратный клапан","Он работает на электричестве","Он полагается на предохранительный клапан"], re:"AWWA M14 / Руководство EPA CCC: поскольку воздушный разрыв — это открытый разрыв в атмосферу без трубы поперёк него, ни противодавление, ни обратный сифонаж не могут перенести воду через него."},
  {id:62, q:"Воздушный разрыв наиболее уместен там, где:", opts:["Требуется непрерывный напорный поток ниже разрыва","Приемлем открытый сброс в резервуар или приёмник","Присутствует пламя","Существует только противодавление"], re:"AWWA M14: воздушный разрыв подходит для открытых сбросов (наполнение резервуаров, дренажи, приёмники), где не нужно давление ниже по потоку, поскольку разрыв прерывает линию в атмосферу."},
  {id:63, q:"Кромка перелива, упоминаемая при измерении воздушного разрыва, — это:", opts:["Дно раковины","Выпуск крана","Верхний край, через который вода переливалась бы из сосуда","Отверстие дренажа"], re:"AWWA M14 / UPC: кромка перелива — это верхний край сантехнического прибора или сосуда, с которого вода переливалась бы, и она является точкой отсчёта для воздушного разрыва."},
  {id:64, q:"По сравнению с механическим узлом защиты от обратного потока, воздушный разрыв:", opts:["Имеет внутренние части, которые могут изнашиваться","Требует электричества","Должен ежегодно испытываться манометрами","Не имеет движущихся частей, которые изнашиваются или отказывают"], re:"USC FCCCHR / AWWA M14: воздушный разрыв немеханичен, без движущихся частей, поэтому он не может износиться, хотя его можно свести на нет при физическом изменении."},
  {id:65, q:"Приемлемый воздушный разрыв на подаче раковины для швабр означает, что излив:", opts:["Оканчивается по меньшей мере на требуемом расстоянии выше кромки перелива","Сбрасывает ниже кромки","Подсоединён к шлангу, касающемуся пола","Погружается при наполнении раковины"], re:"AWWA M14 / Руководство EPA CCC: излив должен оканчиваться по меньшей мере на требуемом расстоянии воздушного разрыва выше кромки перелива, чтобы он никогда не мог быть погружён."},
  {id:66, q:"Почему воздушный разрыв считается базовой формой разделения от обратного потока?", opts:["Это новейшая технология","Это самое простое и самое надёжное разделение между питьевой и непитьевой водой","Он требует наибольшего обслуживания","Он работает только с горячей водой"], re:"Руководство EPA CCC / AWWA M14: воздушный разрыв — это первоначальный и самый надёжный метод разделения, эталон, с которым сравниваются механические узлы."},
  {id:67, q:"Если оборудованию требуется напорная вода и открытый воздушный разрыв использовать нельзя, альтернатива — это:", opts:["Оставить соединение без защиты","Понизить давление воды до нуля","Установить соответствующий механический узел предотвращения обратного потока","Погрузить выпуск"], re:"AWWA M14 / USC FCCCHR: там, где необходимо напорное закрытое соединение, одобренный механический узел (такой как RP или двойной обратный клапан) заменяет воздушный разрыв."},
  {id:68, q:"В контроле перекрёстных соединений 'сдерживание' (изоляция объекта) означает установку защиты:", opts:["У каждого сантехнического прибора внутри здания","Только на водонагревателе","Только на линии горячей воды","У точки обслуживания или рядом с ней для защиты общественной водопроводной магистрали"], re:"Руководство EPA CCC / Справочник политики CCC SWRCB Калифорнии: сдерживание (изоляция объекта) размещает устройство защиты от обратного потока у точки обслуживания для защиты общественной магистрали от всего объекта."},
  {id:69, q:"'Изоляция' (защита приборов) в контроле перекрёстных соединений означает защиту:", opts:["Каждого отдельного перекрёстного соединения или прибора внутри объекта","Всего объекта только у счётчика","Только городской магистрали","Пожарного гидранта"], re:"Руководство EPA CCC: изоляция (внутренняя/приборная защита) обращается к каждому перекрёстному соединению в его точке использования внутри водопровода здания."},
  {id:70, q:"Узел сдерживания обычно располагается:", opts:["У самого дальнего от счётчика прибора","Сразу ниже счётчика воды или ввода обслуживания","Внутри водонагревателя","На крыше здания"], re:"Справочник политики CCC SWRCB Калифорнии / Руководство EPA CCC: узел сдерживания (изоляции объекта) располагается непосредственно ниже счётчика или у ввода обслуживания."},
  {id:71, q:"Основная цель сдерживания — защитить:", opts:["Жильцов здания","Бытовые приборы клиента","Общественную распределительную систему водоснабжения от объекта клиента","Канализационную систему"], re:"Руководство EPA CCC: сдерживание защищает общественную систему водоснабжения; само по себе оно не защищает людей внутри здания от внутренних перекрёстных соединений."},
  {id:72, q:"Основная цель изоляции (внутренней защиты) — защитить:", opts:["Только общественную магистраль","Дорожное покрытие улицы","Счётчик воды","Людей и качество воды внутри здания у каждого перекрёстного соединения"], re:"Руководство EPA CCC: изоляция защищает жильцов и качество воды внутри здания, обращаясь к каждому отдельному перекрёстному соединению в его источнике."},
  {id:73, q:"Полный подход к контролю перекрёстных соединений часто использует:", opts:["Как сдерживание у точки обслуживания, так и изоляцию у внутренних опасностей","Только изоляцию","Только сдерживание","Ни то ни другое, полагаясь на очистку воды"], re:"Руководство EPA CCC / AWWA M14: лучшая практика сочетает сдерживание (изоляцию объекта) у точки обслуживания с изоляцией внутренних опасностей для многоуровневой защиты."},
  {id:74, q:"Почему сдерживание само по себе не защищает жильцов здания?", opts:["Потому что оно останавливает только горячую воду","Потому что внутреннее перекрёстное соединение всё ещё может заразить воду внутри здания, ниже устройства сдерживания","Потому что у него нет обратных клапанов","Потому что оно повышает давление"], re:"Руководство EPA CCC: устройство сдерживания у счётчика не останавливает заражение, которое происходит от перекрёстных соединений внутри здания, ниже него."},
  {id:75, q:"Какой подход поставщики воды чаще всего требуют как минимум для защиты общественной магистрали?", opts:["Изоляцию каждого прибора коммунальной службой","Никакой защиты","Сдерживание (изоляцию объекта) у точки обслуживания","Очистку у крана клиента"], re:"Раздел 17 Калифорнии / Справочник политики CCC SWRCB: коммунальные службы обычно требуют сдерживание у точки обслуживания как своё основное средство защиты общественной распределительной системы."},
  {id:76, q:"Изоляция объекта — это другое название для:", opts:["Защиты на уровне прибора","Изоляции канализации","Воздушного разрыва у каждой раковины","Сдерживания у точки обслуживания"], re:"Справочник политики CCC SWRCB Калифорнии: 'изоляция объекта' и 'сдерживание' оба относятся к защите общественной системы узлом у точки обслуживания."},
  {id:77, q:"Внутренняя защита (в точке использования) одного лабораторного крана является примером:", opts:["Изоляции","Сдерживания","Изоляции объекта","Защиты обслуживания"], re:"Руководство EPA CCC: защита одного конкретного прибора, такого как лабораторный кран, в его точке использования является изоляцией (приборной защитой), а не сдерживанием всего объекта."},
  {id:78, q:"Для объекта высокой опасности поставщик воды обычно требует сдерживание И:", opts:["Удаление счётчика","Внутреннюю изоляцию конкретных опасностей владельцем","Более низкое давление воды","Никаких дальнейших действий"], re:"AWWA M14 / Справочник политики CCC SWRCB: объекты высокой опасности обычно нуждаются в сдерживании у точки обслуживания плюс предоставленной владельцем изоляции внутренних опасностей."},
  {id:79, q:"Какое утверждение правильно противопоставляет сдерживание и изоляцию?", opts:["Изоляция устанавливается только у счётчика","Они идентичны","Сдерживание защищает общественную магистраль; изоляция защищает каждое внутреннее перекрёстное соединение","Сдерживание защищает только приборы"], re:"Руководство EPA CCC / AWWA M14: сдерживание — это защита общественной системы на уровне обслуживания, тогда как изоляция — это защита в точке использования каждого внутреннего перекрёстного соединения."},
  {id:80, q:"Узел защиты от обратного потока, установленный сразу после счётчика на целом многоквартирном доме, выполняет:", opts:["Изоляцию","Контроль теплового расширения","Разделение воздушным разрывом","Сдерживание (изоляцию объекта)"], re:"Справочник политики CCC SWRCB Калифорнии: узел, обслуживающий всё здание у счётчика, является сдерживанием (изоляцией объекта) для общественной системы."},
  {id:81, q:"С точки зрения поставщика воды, сдерживание ценно, потому что оно:", opts:["Обеспечивает единый, проверяемый барьер, защищающий общественную систему от всего объекта","Устраняет необходимость в любой проверке внутреннего водопровода","Понижает счёт за воду клиента","Устраняет все внутренние опасности"], re:"Руководство EPA CCC / AWWA M14: сдерживание даёт поставщику один определённый, проверяемый узел для защиты общественной магистрали от всего, что находится за пределами точки обслуживания."},
  {id:82, q:"Защита изоляцией обычно является ответственностью:", opts:["Только поставщика воды","Владельца собственности / клиента для опасностей внутри его водопровода","Пожарной службы","Только штата"], re:"Раздел 17 Калифорнии / Руководство EPA CCC: внутренняя (изоляционная) защита перекрёстных соединений внутри здания является ответственностью клиента/владельца, часто обеспечиваемой через сантехнический кодекс."},
  {id:83, q:"Какой сценарий показывает необходимость КАК сдерживания, ТАК и изоляции?", opts:["Одноквартирный дом только с кухонным краном","Пустой участок","Больница со многими внутренними соединениями высокой опасности, обслуживаемыми от одной магистрали","Питьевой фонтанчик в парке"], re:"AWWA M14 / Руководство EPA CCC: объекты с множественными высокими внутренними опасностями (такие как больницы) нуждаются в сдерживании у точки обслуживания плюс изоляции каждой внутренней опасности."},
  {id:84, q:"'Точка обслуживания' в контроле перекрёстных соединений — это:", opts:["Шланговый кран на задней стороне дома","Прочистка канализации","Впуск водонагревателя","Точка, где общественная система водоснабжения соединяется с трубопроводом клиента"], re:"AWWA M14 / Раздел 17 Калифорнии: точка обслуживания — это точка доставки, где общественная система водоснабжения встречается с водопроводом клиента, часто у счётчика или сразу после него."},
  {id:85, q:"'Поставщик воды' (водоснабжающая организация) — это:", opts:["Агентство или коммунальная служба, которая владеет и управляет общественной системой водоснабжения","Сантехник, устанавливающий приборы","Испытатель обратного потока","Законодательное собрание штата"], re:"AWWA M14 / Раздел 17 Калифорнии: поставщик или водоснабжающая организация — это субъект, который владеет и управляет общественной системой водоснабжения, доставляющей питьевую воду клиентам."},
  {id:86, q:"Согласно Разделу 17 Калифорнии, кто обычно отвечает за защиту общественной системы водоснабжения у точки обслуживания?", opts:["Страховая компания клиента","Поставщик воды (водоснабжающая организация)","Пожарная служба","Окружной оценщик"], re:"Раздел 17 Калифорнии (CCR разделы 7583-7605): поставщику воды поручено защищать общественную систему водоснабжения у каждой точки обслуживания посредством программы контроля перекрёстных соединений."},
  {id:87, q:"Кто обычно оплачивает и устанавливает требуемый узел предотвращения обратного потока у точки обслуживания?", opts:["Всегда производитель","Государственный водный совет штата","Потребитель воды (клиент), за свой счёт","Соседняя собственность"], re:"Раздел 17 Калифорнии: требуемый узел обратного потока устанавливается потребителем воды и за его счёт у каждой точки соединения, где этого требует поставщик."},
  {id:88, q:"Как часто обычно должны испытываться узлы предотвращения обратного потока согласно требованиям Калифорнии?", opts:["Один раз в пять лет","Никогда после установки","Только когда они отказывают","По меньшей мере ежегодно, а также после установки, перемещения или ремонта"], re:"Раздел 17 Калифорнии / Справочник политики CCC SWRCB: узлы обратного потока должны испытываться по меньшей мере один раз в год и при установке, перемещении или ремонте."},
  {id:89, q:"УЗЕЛ предотвращения обратного потока отличается от УСТРОЙСТВА предотвращения обратного потока главным образом тем, что узел:", opts:["Включает запорные клапаны и испытательные краники, чтобы его можно было испытать на месте","Не имеет внутренних частей","Не может быть испытан","Всегда немеханичен"], re:"AWWA M14 / USC FCCCHR: испытываемый 'узел' включает запорные клапаны с эластичным седлом и испытательные краники, что позволяет проводить полевые испытания в линии, в отличие от неиспытываемого 'устройства'."},
  {id:90, q:"Основная роль сертифицированного испытателя узлов обратного потока — это:", opts:["Проектировать водопроводную магистраль","Испытывать узлы обратного потока и составлять отчёты, чтобы проверить их правильную работу","Устанавливать тарифы на воду для клиента","Снимать показания электросчётчика"], re:"AWWA M14 / Раздел 17 Калифорнии: сертифицированный испытатель проводит требуемые периодические испытания и документирует, правильно ли работает каждый узел."},
  {id:91, q:"Общая цель программы контроля перекрёстных соединений — это:", opts:["Увеличить продажи воды","Понизить счёт за отопление здания","Защитить общественное питьевое водоснабжение от заражения обратным потоком","Ускорить течение воды"], re:"Руководство EPA CCC / Справочник политики CCC SWRCB Калифорнии: программа контроля перекрёстных соединений существует для защиты общественного питьевого водоснабжения от заражения обратным потоком."},
  {id:92, q:"'Одобренные' узлы обратного потока в Калифорнии обычно те, которые:", opts:["Выбраны установщиком наугад","Только самодельные блоки","Любое устройство, продаваемое в хозяйственном магазине","Испытаны и внесены в список признанным органом, таким как USC FCCCHR"], re:"Раздел 17 Калифорнии / USC FCCCHR: Калифорния признаёт узлы, прошедшие лабораторную и полевую оценку, такие как из одобренного списка USC FCCCHR."},
  {id:93, q:"Незащищённое перекрёстное соединение с общественным водоснабжением:", opts:["Запрещено согласно правилам контроля перекрёстных соединений","Разрешено, если клиент согласен","Требуется нормами","Является проблемой только для промышленных объектов"], re:"Раздел 17 Калифорнии: незащищённые перекрёстные соединения с общественным водоснабжением запрещены; требуемая защита должна быть установлена и обслуживаться."},
  {id:94, q:"'Обследование' или инспекция контроля перекрёстных соединений используется для:", opts:["Измерения счёта за воду","Выявления перекрёстных соединений и оценки степени опасности на объекте","Испытания почвы","Снятия показаний газосчётчика"], re:"Руководство EPA CCC / Раздел 17 Калифорнии: поставщик проводит обследования для обнаружения перекрёстных соединений и оценки степени опасности, чтобы можно было потребовать надлежащую защиту."},
  {id:95, q:"Записи об испытаниях узлов обратного потока важны, потому что они:", opts:["Устанавливают давление воды","Заменяют необходимость в каком-либо устройстве","Документируют, что каждый узел был испытан и признан работоспособным, как требует регламент","Определяют цвет трубы"], re:"Раздел 17 Калифорнии / AWWA M14: записи об испытаниях демонстрируют соответствие нормам и подтверждают, что каждый узел был испытан и функционировал, и сообщаются поставщику."},
  {id:96, q:"'Точка доставки' обычно отмечает:", opts:["Канализационный выпуск","Станцию водоочистки","Пожарный гидрант","Границу, где заканчивается ответственность поставщика и начинается ответственность клиента"], re:"AWWA M14: точка доставки (точка обслуживания) — это разделительная линия между системами водоснабжения и ответственностью поставщика и клиента."},
  {id:97, q:"Почему испытатель должен быть сертифицирован, прежде чем испытывать узлы в Калифорнии?", opts:["Чтобы обеспечить правильное проведение испытаний, чтобы защита здоровья населения надёжно проверялась","По налоговым причинам","Чтобы устанавливать тарифы на воду","На самом деле это не требуется"], re:"Раздел 17 Калифорнии / AWWA M14: только сертифицированные испытатели могут испытывать узлы, что обеспечивает компетентную, последовательную проверку того, что барьер защиты здоровья населения работает."},
  {id:98, q:"Если узел обратного потока не проходит испытание, правильная реакция — это:", opts:["Игнорировать его до следующего года","Незамедлительно отремонтировать или заменить его и повторно испытать, чтобы восстановить защиту","Удалить всю защиту","Повысить давление воды"], re:"AWWA M14 / Раздел 17 Калифорнии: отказавший узел должен быть отремонтирован или заменён и повторно испытан без промедления, потому что перекрёстное соединение остаётся незащищённым, пока он не пройдёт испытание."},
  {id:99, q:"Основная ответственность клиента в контроле перекрёстных соединений — это:", opts:["Эксплуатировать общественную водопроводную магистраль","Устанавливать политику поставщика","Устанавливать, обслуживать и обеспечивать испытание требуемой защиты от обратного потока на своём объекте","Сертифицировать других испытателей"], re:"Раздел 17 Калифорнии: потребитель воды отвечает за установку, обслуживание и организацию требуемого испытания защиты от обратного потока на своей стороне точки обслуживания."},
  {id:100, q:"Какое агентство приняло общештатный Справочник политики контроля перекрёстных соединений Калифорнии, регулирующий защиту от обратного потока?", opts:["Министерство энергетики США","Местный пожарный маршал","Федеральная комиссия по связи","Государственный совет по контролю водных ресурсов (SWRCB)"], re:"CA SWRCB: Государственный совет по контролю водных ресурсов принял Справочник политики контроля перекрёстных соединений (вступивший в силу 1 июля 2024 года), регулирующий контроль перекрёстных соединений по всему штату."},
  {id:101, q:"Какие два основных внутренних клапанных компонента составляют ядро устройства принципа пониженного давления (RP)?", opts:["Два независимо действующих обратных клапана с дифференциальным предохранительным клапаном между ними","Один обратный клапан и атмосферный воздушный впуск","Один обратный клапан и два предохранительных клапана последовательно","Воздушный впуск с поплавковым приводом и один обратный клапан"], re:"RP состоит из двух независимо действующих обратных клапанов с пружинной нагрузкой и гидравлически работающего, механически независимого дифференциального предохранительного клапана, расположенного между ними. Источник: AWWA M14; USC FCCCHR 10th ed."},
  {id:102, q:"Против каких условий обратного потока эффективно устройство RP?", opts:["Только обратное сифонирование","Только обратное давление","Как обратное давление, так и обратное сифонирование","Ни против чего, оно только понижает давление"], re:"RP эффективно как против обратного потока по обратному давлению, так и против обратного сифонирования. Источник: AWWA M14; USC FCCCHR 10th ed."},
  {id:103, q:"Против какого уровня опасности может использоваться устройство RP для защиты?", opts:["Только опасности, не связанные со здоровьем","Только эстетические опасности (цвет/запах)","Только опасности обратного сифонирования","Опасности для здоровья (и опасности, не связанные со здоровьем)"], re:"RP может использоваться для изоляции опасностей для здоровья (высокий риск), а также опасностей, не связанных со здоровьем, что делает его проверяемым устройством наивысшего уровня. Источник: AWWA M14; CA Title 17 §7603."},
  {id:104, q:"Где расположен дифференциальный предохранительный клапан в устройстве RP?", opts:["Между двумя обратными клапанами (в зоне пониженного давления)","Выше по потоку от обоих обратных клапанов","Ниже по потоку от второго обратного клапана","Внутри корпуса второго обратного клапана"], re:"Предохранительный клапан находится в зоне между двумя обратными клапанами и ниже первого обратного клапана, отслеживая перепад на первом обратном клапане. Источник: AWWA M14; CA Title 17 §7603(c)."},
  {id:105, q:"При нормальной работе давление в зоне между двумя обратными клапанами RP должно быть как минимум насколько ниже давления подачи (на входе)?", opts:["На 2 psi ниже","На 10 psi ниже","Равно давлению подачи","На 0.5 psi ниже"], re:"Зона пониженного давления должна оставаться как минимум на 2 psi ниже давления на стороне подачи при нормальной работе. Источник: AWWA M14; USC FCCCHR 10th ed."},
  {id:106, q:"Сколько испытательных кранов предусмотрено на стандартном устройстве RP?", opts:["Два","Три","Четыре","Один"], re:"Стандартное RP имеет четыре правильно расположенных испытательных крана с эластичным седлом для полевой проверки обратных клапанов и предохранительного клапана. Источник: AWWA M14; USC FCCCHR 10th ed."},
  {id:107, q:"Сколько запорных клапанов с эластичным седлом входят в состав полного устройства RP?", opts:["Один","Четыре","Два (вход и выход)","Ни одного"], re:"Полное RP включает два плотно закрывающихся запорных клапана с эластичным седлом, один на входе и один на выходе. Источник: AWWA M14; USC FCCCHR 10th ed."},
  {id:108, q:"Когда предохранительный клапан RP открывается и сбрасывает воду в атмосферу?", opts:["Только при нормальном прямом потоке","Постоянно, пока устройство находится под давлением","Когда перепад на первом обратном клапане падает примерно до 2 psi или первый обратный клапан протекает","Только когда оба запорных клапана закрыты"], re:"Предохранительный клапан открывается для сброса зоны в атмосферу, когда перепад на первом обратном клапане падает к ~2 psi (например, засорение первого обратного клапана или событие обратного потока), поддерживая зону пониженного давления. Источник: AWWA M14."},
  {id:109, q:"Как должен заканчиваться сброс предохранительного клапана RP?", opts:["Прямое подключение к санитарной канализации","Заглушен для предотвращения любого разлива","Через воздушный зазор к утвержденному дренажу или к уровню земли","Возвращен обратно на вход устройства"], re:"Сброс предохранительного клапана должен заканчиваться через воздушный зазор над утвержденным приемником или к уровню земли; прямое (погруженное) подключение к канализации запрещено. Источник: AWWA M14; CA Title 17."},
  {id:110, q:"Почему устройство RP никогда не должно устанавливаться в приямке или подземном колодце, подверженном затоплению?", opts:["Сброс предохранительного клапана может оказаться погруженным, нарушая воздушный зазор и создавая перекрестное соединение","Испытательные краны замерзали бы быстрее под землей","Пружины обратных клапанов корродируют только ниже уровня земли","Приямки слишком сильно повышают давление подачи"], re:"Если затопленный приямок погружает порт сброса, воздушный зазор теряется, и загрязненная вода может быть втянута обратно; устройства RP не должны располагаться там, где затопление может погрузить предохранительный клапан. Источник: AWWA M14."},
  {id:111, q:"Самая нижняя часть порта сброса предохранительного клапана RP обычно должна находиться как минимум на каком расстоянии над полом/уровнем земли или уровнем затопления?", opts:["12 in","1 in","6 in","36 in"], re:"Порт сброса предохранительного клапана обычно должен находиться на расстоянии не менее 12 in над землей, верхом отверстия корпуса или максимальным уровнем затопления, в зависимости от того, что выше. Источник: руководство по установке AWWA M14."},
  {id:112, q:"Что означает аббревиатура 'RP' в терминологии устройств защиты от обратного потока?", opts:["Предохранитель сброса","Устройство обратного давления","Устройство предотвращения обратного потока принципа пониженного давления","Устройство регулируемой трубы"], re:"RP означает устройство предотвращения обратного потока принципа пониженного давления (также пишется RPZ или RPBA). Источник: AWWA M14; USC FCCCHR 10th ed."},
  {id:113, q:"RPDA (детекторное устройство пониженного давления) в основном используется на каком типе обслуживания?", opts:["Бытовые питьевые фонтанчики","Шланговые краны","Линии противопожарной защиты (спринклеров), где требуется обнаружение утечек/хищения","Атмосферные оросительные выпуски"], re:"RPDA — это устройство на базе RP с измеренным байпасом, используемое на пожарных линиях для обнаружения малых расходов из-за утечек или несанкционированного использования воды. Источник: AWWA M14."},
  {id:114, q:"Измеренная байпасная линия RPDA содержит что из следующего?", opts:["Только второй предохранительный клапан","Атмосферный вакуумный прерыватель","Малое устройство RP (или обратного клапана) со счетчиком-детектором малого расхода","Только редукционный клапан давления"], re:"Байпас RPDA направляет малые расходы через параллельное малое устройство RP, оснащенное счетчиком-детектором (регистрирующим), для улавливания утечек или несанкционированного использования. Источник: AWWA M14."},
  {id:115, q:"По сравнению с устройством двойного обратного клапана, RP обеспечивает что?", opts:["Меньшую защиту","Такую же защиту","Более высокий (больший) уровень защиты","Вообще никакой защиты от обратного потока"], re:"RP обеспечивает более высокий уровень защиты, чем DC, потому что его предохранительный клапан активно сбрасывает зону при отказе обратного клапана; оно рассчитано на опасности для здоровья, тогда как DC — нет. Источник: AWWA M14; ранжирование опасностей CA Title 17."},
  {id:116, q:"Какое утверждение о сбросе предохранительного клапана RP при засоренном первом обратном клапане верно?", opts:["Видимый сброс воды из порта сброса может указывать на засоренный или протекающий первый обратный клапан","Порт сброса никогда не должен сбрасывать ни при каких условиях","Сброс означает, что отказал только второй обратный клапан","Сброс доказывает, что устройство установлено наоборот"], re:"Прерывистый или непрерывный сброс обычно сигнализирует о засоренном/протекающем первом обратном клапане (или о колеблющемся давлении подачи); предохранительный клапан выполняет свою защитную функцию, сбрасывая зону. Источник: AWWA M14; сервисная литература производителя."},
  {id:117, q:"В RP работа предохранительного клапана описывается как что из следующего?", opts:["С электрическим приводом","Открываемый вручную только тестировщиком","Гидравлически работающий и механически независимый от обратных клапанов","Приводимый в действие поплавком в воздушном впуске"], re:"Предохранительный клапан RP — это гидравлически работающий, механически независимый дифференциальный предохранительный клапан, привязанный к давлению подачи. Источник: AWWA M14; CA Title 17 §7603(c)."},
  {id:118, q:"Устройство двойного обратного клапана (DC) состоит из какой компоновки?", opts:["Один обратный клапан и предохранительный клапан","Воздушный впуск и один обратный клапан","Два независимо действующих обратных клапана последовательно","Предохранительный клапан между двумя воздушными впусками"], re:"DC — это два одиночных независимо действующих обратных клапана, расположенных последовательно, с запорными клапанами на каждом конце и испытательными кранами. Источник: AWWA M14; USC FCCCHR 10th ed."},
  {id:119, q:"Для какого уровня опасности одобрено устройство двойного обратного клапана?", opts:["Опасности для здоровья (высокий риск)","Подключения сточных вод","Только опасности, не связанные со здоровьем (низкий риск)","Системы впрыска химикатов"], re:"DC используется для изоляции только опасностей, не связанных со здоровьем (загрязнителей); оно не одобрено для опасностей для здоровья. Источник: AWWA M14; CA Title 17 §7603."},
  {id:120, q:"Против каких условий обратного потока эффективно DC?", opts:["Только обратное сифонирование","Только обратное давление","Как обратное давление, так и обратное сифонирование","Ни против каких условий"], re:"DC эффективно как против обратного давления, так и против обратного сифонирования (для опасностей, не связанных со здоровьем). Источник: AWWA M14; USC FCCCHR 10th ed."},
  {id:121, q:"Сколько испытательных кранов имеет стандартное устройство DC?", opts:["Один","Два","Четыре","Шесть"], re:"DC имеет четыре правильно расположенных испытательных крана, используемых для измерения перепада на каждом обратном клапане. Источник: AWWA M14; ASSE 1015."},
  {id:122, q:"Каков типичный минимально допустимый перепад, который должен удерживать каждый обратный клапан DC при проверке?", opts:["1.0 psid","5.0 psid","0.1 psid","10 psid"], re:"Обычно требуется, чтобы каждый обратный клапан DC удерживал минимум около 1.0 psid в направлении потока, чтобы пройти проверку. Источник: AWWA M14; USC FCCCHR 10th ed."},
  {id:123, q:"Почему в DC используются два обратных клапана последовательно, а не один?", opts:["Чтобы удвоить расход","Чтобы создать воздушный зазор","Чтобы устранить необходимость в запорных клапанах","Чтобы обеспечить резервирование, чтобы второй обратный клапан все еще уплотнял, если первый протекает"], re:"Последовательная компоновка обеспечивает резервирование: если один обратный клапан не уплотняет, другой все равно обеспечивает защиту. Источник: AWWA M14."},
  {id:124, q:"Детекторное устройство двойного обратного клапана (DCDA) чаще всего устанавливается на что?", opts:["Питьевые фонтанчики","Линии питания котлов с химикатами","Посудомоечные машины","Линии подачи противопожарной защиты (спринклеров)"], re:"DCDA — это DC с измеренным байпасом, устанавливаемое на пожарных линиях с опасностью, не связанной со здоровьем, для обнаружения утечек или несанкционированного использования. Источник: AWWA M14."},
  {id:125, q:"Байпас DCDA рассчитан на регистрацию расходов примерно до какой величины, прежде чем откроются основные обратные клапаны?", opts:["Примерно от 2 до 5 gpm (малый расход)","Примерно 50 gpm","Примерно 500 gpm","Только расходы выше 100 gpm"], re:"Счетчик-детектор байпаса улавливает малые расходы (примерно до ~2-5 gpm); большие расходы открывают обратные клапаны основной линии. Источник: AWWA M14 (конструкция байпаса DCDA)."},
  {id:126, q:"В DCDA настройка дифференциального давления байпаса относительно основных обратных клапанов спроектирована так, что:", opts:["Малые расходы сначала проталкиваются через измеренный байпас","Весь поток всегда обходит обратные клапаны основной линии","Основная линия открывается раньше любого потока байпаса","Байпас никогда не регистрирует поток"], re:"Байпас настроен с немного меньшим перепадом, чем обратные клапаны основной линии, так что малые расходы регистрируются на счетчике байпаса до открытия основных обратных клапанов. Источник: AWWA M14."},
  {id:127, q:"Основная цель счетчика-детектора на пожарной линии DCDA/RPDA состоит в том, чтобы:", opts:["Увеличить пропускную способность пожарного расхода","Снизить давление подачи","Заменить необходимость ежегодной проверки","Выявить малые утечки или несанкционированное (неучтенное) использование воды"], re:"Счетчик-детектор предупреждает коммунальную службу об утечках или несанкционированном отводе, которые могли бы остаться незамеченными на пожарной линии, которая в остальном не учитывается. Источник: AWWA M14."},
  {id:128, q:"Сколько запорных клапанов включено в полное устройство DC?", opts:["Ни одного","Один","Два (вход и выход)","Четыре"], re:"DC включает два плотно закрывающихся запорных клапана с эластичным седлом для изоляции во время проверки и обслуживания. Источник: AWWA M14; ASSE 1015."},
  {id:129, q:"Что из следующего является примером опасности, не связанной со здоровьем, которую обычно защищало бы DC?", opts:["Медицинский/стоматологический аспиратор","Подключение эжектора сточных вод","Система подачи (впрыска) химикатов","Система полива газона без впрыска химикатов"], re:"Обычный полив без впрыска химикатов, как правило, является опасностью, не связанной со здоровьем (загрязнитель), подходящей для защиты DC; впрыск химикатов или сточные воды потребовали бы RP или воздушного зазора. Источник: AWWA M14; оценка опасностей CA Title 17."},
  {id:130, q:"В отличие от RP, устройство двойного обратного клапана НЕ включает какой компонент?", opts:["Второй обратный клапан","Запорный клапан на входе","Дифференциальный предохранительный клапан","Испытательные краны"], re:"DC не имеет предохранительного клапана; это определяющее отличие от RP и причина, по которой DC не может сбросить зону при засорении обратного клапана. Источник: AWWA M14."},
  {id:131, q:"Поскольку у DC нет порта сброса, его можно устанавливать в каком месте, где RP установить нельзя?", opts:["Погруженным в канализацию","Непосредственно на линии сточных вод","Внутри напорного химического резервуара","Ниже уровня земли в колодце (где затопление порта сброса не является проблемой), если это иначе разрешено"], re:"Не имея сброса предохранительного клапана, DC можно размещать в колодце/ниже уровня земли, где RP было бы запрещено из-за затопления его порта сброса (с учетом местных правил доступа и дренажа). Источник: AWWA M14."},
  {id:132, q:"Обратные клапаны в DC описываются как:", opts:["Принудительно нагруженные (пружиной) в закрытое положение","Нагруженные в открытое положение","Удерживаемые закрытыми только силой тяжести","Удерживаемые закрытыми электрически"], re:"Каждый обратный клапан DC внутренне принудительно нагружен (пружиной) в закрытое положение, чтобы уплотнять независимо. Источник: AWWA M14; ASSE 1015."},
  {id:133, q:"Что означает аббревиатура 'DCDA'?", opts:["Дренажное устройство двойного обратного клапана","Дифференциальный детекторный массив обратных клапанов","Двухцилиндровый разрядный аппарат","Детекторное устройство двойного обратного клапана"], re:"DCDA означает детекторное устройство двойного обратного клапана (Double Check Detector Assembly). Источник: AWWA M14; USC FCCCHR 10th ed."},
  {id:134, q:"Какой стандарт обычно применяется к устройствам предотвращения обратного потока двойного обратного клапана?", opts:["ASSE 1015 / AWWA C510","Только ASSE 1056","40 CFR Part 82","Котельный кодекс ASME"], re:"Устройства DC обычно соответствуют ASSE 1015 и AWWA C510 (и одобрению USC FCCCHR). Источник: AWWA M14; ASSE 1015; AWWA C510."},
  {id:135, q:"Устройство вакуумного прерывателя давления (PVB) содержит какие два рабочих элемента?", opts:["Два обратных клапана и предохранительный клапан","Предохранительный клапан и воздушный зазор","Два воздушных впуска последовательно","Один обратный клапан с пружинной нагрузкой и принудительно нагруженный воздушный впускной клапан"], re:"PVB имеет один независимо работающий обратный клапан с пружинной нагрузкой (принудительно нагруженный на закрытие) и воздушный впускной клапан ниже по потоку, принудительно нагруженный в открытое положение. Источник: AWWA M14; ASSE 1020."},
  {id:136, q:"Против какого условия обратного потока одобрено PVB?", opts:["Только обратное давление","Ни против чего","Как обратное давление, так и обратное сифонирование","Только обратное сифонирование"], re:"PVB защищает только от обратного сифонирования; его нельзя использовать там, где может возникнуть обратное давление. Источник: AWWA M14; CA Title 17 §7603."},
  {id:137, q:"PVB должно устанавливаться как минимум на каком расстоянии над самым высоким трубопроводом/выпуском ниже по потоку?", opts:["6 in","24 in","1 in","12 in"], re:"PVB должно устанавливаться как минимум на 12 in над всем трубопроводом ниже по потоку и самым высоким выпуском (или ободом уровня затопления). Источник: CA Title 17 §7603(b); AWWA M14; UPC/IPC."},
  {id:138, q:"Сколько испытательных кранов имеет стандартное устройство PVB?", opts:["Один","Ни одного","Четыре","Два"], re:"PVB имеет два испытательных крана (один выше по потоку и один ниже по потоку от обратного клапана), плюс запорные клапаны входа/выхода. Источник: AWWA M14; ASSE 1020."},
  {id:139, q:"Ключевое преимущество PVB перед атмосферным вакуумным прерывателем (AVB) состоит в том, что PVB:", opts:["Может подвергаться непрерывному давлению воды","Обеспечивает защиту от обратного давления","Не нуждается в запорных клапанах","Не требует проверки"], re:"Поскольку его обратный клапан подпружинен и оно имеет испытательные краны/запорные клапаны, PVB может находиться под непрерывным давлением, в отличие от AVB. Источник: AWWA M14; ASSE 1020."},
  {id:140, q:"В PVB воздушный впускной клапан нагружен в какое положение?", opts:["Закрытое (принудительно нагружен на закрытие)","Заблокирован закрытым во время эксплуатации","Плавающее, без пружины","Открытое (принудительно нагружен на открытие)"], re:"Воздушный впуск PVB принудительно нагружен в ОТКРЫТОЕ положение, чтобы открываться для впуска воздуха и нарушения вакуума при падении давления подачи. Источник: AWWA M14; ASSE 1020."},
  {id:141, q:"В PVB одиночный обратный клапан нагружен в какое положение?", opts:["Открытое","Обратное","Нейтральное/сбалансированное","Закрытое (принудительно нагружен на закрытие)"], re:"Обратный клапан PVB принудительно нагружен в закрытое положение, чтобы уплотнять против обратного сифонирования. Источник: AWWA M14; ASSE 1020."},
  {id:142, q:"Основное функциональное отличие вакуумного прерывателя, устойчивого к разливу (SVB), по сравнению с PVB состоит в том, что SVB:", opts:["Обеспечивает защиту от обратного давления","Имеет четыре испытательных крана","Не требует возвышения над трубопроводом ниже по потоку","Спроектирован для минимизации/удержания разлива при открытии воздушного впуска"], re:"SVB использует герметичную/мембранную конструкцию воздушного впуска для минимизации разлива воды при срабатывании, что делает его более подходящим для внутренних помещений. Источник: ASSE 1056; AWWA M14."},
  {id:143, q:"Сколько испытательных кранов обычно имеет SVB, отличая его физически от PVB?", opts:["Один (плюс продувочный/спускной клапан)","Два","Четыре","Три"], re:"SVB обычно имеет один испытательный кран плюс продувочный (спускной) клапан, тогда как PVB имеет два испытательных крана. Источник: ASSE 1056."},
  {id:144, q:"Как и PVB, SVB одобрен против какого условия обратного потока?", opts:["Только обратное давление","Только тепловое расширение","Оба условия","Только обратное сифонирование"], re:"SVB, как и PVB, защищает только от обратного сифонирования и не должен использоваться там, где существует обратное давление. Источник: ASSE 1056; AWWA M14."},
  {id:145, q:"SVB, как и PVB, должно устанавливаться как минимум на каком расстоянии над самым высоким выпуском ниже по потоку?", opts:["12 in","6 in","1 in","Без минимума"], re:"SVB должно устанавливаться как минимум на 12 in над всем трубопроводом/выпусками ниже по потоку, тот же минимум, что и для PVB. Источник: ASSE 1056; AWWA M14; CA Title 17."},
  {id:146, q:"Распространенное и подходящее применение для PVB:", opts:["Котел с химической обработкой под обратным давлением","Линия газированного напитка (карбонатора)","Канализационная насосная станция","Система полива газона без впрыска химикатов и без обратного давления"], re:"PVB широко используются в системах полива, где может возникать только обратное сифонирование; впрыск химикатов (опасность для здоровья) или ситуации с обратным давлением требуют RP. Источник: AWWA M14; CA Title 17."},
  {id:147, q:"Почему PVB/SVB должно устанавливаться в вертикальной (прямостоящей) ориентации?", opts:["Чтобы испытательные краны были обращены к технику","Чтобы допускать только горизонтальный поток","Чтобы увеличить давление ниже по потоку","Чтобы воздушный впуск и обратный клапан правильно работали за счет силы тяжести/действия пружины"], re:"Устройства PVB/SVB спроектированы для работы в вертикальном положении, чтобы поплавковый/тарельчатый воздушный впуск и обратный клапан правильно садились на седло; иные ориентации аннулируют сертификацию. Источник: требования к установке ASSE 1020/1056."},
  {id:148, q:"Какой стандарт физически описывает рабочие характеристики устройств вакуумного прерывателя, устойчивого к разливу?", opts:["ASSE 1056","ASSE 1015","ASSE 1013","AWWA C511"], re:"ASSE 1056 охватывает требования к рабочим характеристикам устройств вакуумного прерывателя, устойчивого к разливу. Источник: ASSE 1056."},
  {id:149, q:"Какой стандарт обычно описывает рабочие характеристики устройств вакуумного прерывателя давления?", opts:["ASSE 1020","ASSE 1056","ASSE 1015","ASSE 1011"], re:"ASSE 1020 охватывает требования к рабочим характеристикам устройств вакуумного прерывателя давления. Источник: ASSE 1020."},
  {id:150, q:"Когда давление подачи в PVB падает ниже атмосферного, воздушный впуск:", opts:["Остается закрытым и удерживает вакуум","Увеличивает давление ниже по потоку","Сбрасывает воду в канализацию","Открывается для впуска воздуха, нарушая сифон"], re:"При потере давления принудительно нагруженный воздушный впуск открывается для впуска воздуха, нарушая вакуум и предотвращая обратное сифонирование за закрытый обратный клапан. Источник: AWWA M14; ASSE 1020."},
  {id:151, q:"Устойчивость к разливу SVB делает его предпочтительнее PVB в какой ситуации?", opts:["Наружный полив в морозном климате","Применения с обратным давлением","Применения со сточными водами","Внутренние установки, где атмосферный разлив недопустим"], re:"Поскольку он удерживает разлив, SVB предпочтительнее для внутренних помещений, где разряд через открытый вентиль PVB был бы недопустим. Источник: ASSE 1056; AWWA M14."},
  {id:152, q:"Атмосферный вакуумный прерыватель (AVB) одобрен для защиты только от какого условия?", opts:["Обратное давление","Тепловое расширение","Оба условия","Обратное сифонирование"], re:"AVB защищает только от обратного сифонирования и никогда от обратного давления. Источник: AWWA M14; CA Title 17 §7603."},
  {id:153, q:"Критическое правило установки для AVB состоит в том, что должно быть:", opts:["Насос ниже по потоку","Непрерывное обратное давление","Четыре испытательных крана","Никакого запорного или регулирующего клапана ниже по потоку от AVB"], re:"Ниже по потоку от AVB не может располагаться никакой запорный или регулирующий клапан, потому что это удерживало бы его под непрерывным давлением и могло бы заклинить воздушный впуск. Источник: AWWA M14; CA Title 17 §7603."},
  {id:154, q:"AVB должно устанавливаться как минимум на каком расстоянии над самым высоким выпуском ниже по потоку или ободом уровня затопления?", opts:["6 in","12 in","1 in","18 in"], re:"AVB должно устанавливаться как минимум на 6 in над всем трубопроводом ниже по потоку и самым высоким выпуском/ободом уровня затопления. Источник: CA Title 17 §7603; AWWA M14; UPC/IPC."},
  {id:155, q:"AVB НЕ может подвергаться непрерывному давлению дольше какого времени в любой 24-часовой период?", opts:["12 часов","24 часа","1 час","Без ограничения"], re:"AVB может находиться под давлением не более 12 часов из любого 24-часового периода; дольше может привести к залипанию диска воздушного впуска. Источник: CA Title 17 §7603; AWWA M14."},
  {id:156, q:"Сколько испытательных кранов имеет стандартный атмосферный вакуумный прерыватель (AVB)?", opts:["Четыре","Два","Ни одного (это непроверяемое приспособление)","Один"], re:"AVB не имеет испытательных кранов или запорных клапанов как части приспособления; его нельзя проверить в поле, как устройство, и оно считается приспособлением, а не проверяемым устройством. Источник: AWWA M14; USC FCCCHR."},
  {id:157, q:"Внутреннюю подвижную часть AVB лучше всего описать как:", opts:["Подпружиненный обратный клапан и предохранительный клапан","Мембранный предохранительный клапан","Два обратных клапана последовательно","Поплавок/тарелка (диск воздушного впуска), который уплотняет воздушный порт при потоке и опускается для впуска воздуха при потере давления"], re:"AVB использует плавающий диск/тарелку, который удерживается вверху для уплотнения атмосферного порта во время потока и опускается для открытия порта (впуская воздух) при потере давления. Источник: AWWA M14; ASME A112.1.3."},
  {id:158, q:"Почему к AVB никогда не должно прикладываться обратное давление ниже по потоку?", opts:["Это создало бы избыточное давление в магистрали подачи","Обратное давление улучшает его работу","Это открыло бы предохранительный клапан","У него нет обратного клапана, чтобы сопротивляться обратному давлению, и это допустило бы обратный поток"], re:"AVB полагается только на свой воздушный впуск для защиты от обратного сифонирования; у него нет нагруженного обратного клапана, способного удерживать обратное давление, поэтому обратное давление протолкнуло бы загрязненную воду мимо него. Источник: AWWA M14."},
  {id:159, q:"Вакуумный прерыватель шлангового соединения (шланговый кран) обычно классифицируется как какой тип приспособления?", opts:["Устройство пониженного давления","Устройство вакуумного прерывателя давления","Устройство двойного обратного клапана","Вакуумный прерыватель атмосферного типа (только обратное сифонирование)"], re:"Вакуумный прерыватель шлангового крана (HBVB/HCVB) — это вакуумный прерыватель атмосферного типа, защищающий от обратного сифонирования, и его не следует оставлять под непрерывным давлением. Источник: AWWA M14; ASSE 1011."},
  {id:160, q:"Воздушный зазор определяется каким минимальным вертикальным разделением относительно эффективного отверстия?", opts:["Два диаметра эффективного отверстия и никогда не менее 1 in","Половина диаметра трубы","Равно диаметру трубы, без минимума","Десять диаметров трубы"], re:"Утвержденный воздушный зазор составляет не менее двух диаметров эффективного отверстия и ни в коем случае не менее 1 in. Источник: CA Title 17 §7602; AWWA M14; USC FCCCHR."},
  {id:161, q:"Среди утвержденных методов какой обеспечивает наивысший уровень защиты от обратного потока?", opts:["Атмосферный вакуумный прерыватель","Устройство двойного обратного клапана","Разделение воздушным зазором","Вакуумный прерыватель давления"], re:"Воздушный зазор (физическое разделение) обеспечивает наивысший уровень защиты, потому что ни одна механическая часть не может отказать. Источник: AWWA M14; ранжирование CA Title 17."},
  {id:162, q:"AVB является приемлемым выбором только при соблюдении каких условий?", opts:["Нет обратного давления и нет непрерывного давления (и нет запорного клапана ниже по потоку)","Присутствует обратное давление","Оно установлено ниже выпусков","Насос расположен ниже по потоку"], re:"AVB применяется только там, где нет обратного давления, нет непрерывного давления свыше 12 ч и нет клапана ниже по потоку. Источник: AWWA M14; CA Title 17."},
  {id:163, q:"Какое приспособление защищает только от обратного сифонирования и НЕ МОЖЕТ быть проверено в поле манометрами, как устройство?", opts:["RP","DC","AVB","PVB"], re:"AVB — это непроверяемое приспособление (нет испытательных кранов/запорных клапанов); RP, DC и PVB являются проверяемыми устройствами. Источник: AWWA M14; USC FCCCHR."},
  {id:164, q:"По сравнению с AVB, PVB добавляет какую возможность, оставаясь при этом защищающим только от обратного сифонирования?", opts:["Защита от обратного давления","Работа под непрерывным давлением и возможность полевой проверки (испытательные краны/запорные клапаны)","Внутренний предохранительный клапан","Воздушный зазор"], re:"PVB сохраняет воздушный впуск подпружиненным и добавляет испытательные краны/запорные клапаны, что позволяет работу под непрерывным давлением и полевую проверку, которые AVB обеспечить не может. Источник: AWWA M14; ASSE 1020."},
  {id:165, q:"Почему воздушный зазор невосприимчив к режимам отказа механических устройств?", opts:["Он содержит более прочные пружины","Это физическое (немеханическое) разделение, которое не может засориться или износиться","Он постоянно находится под давлением","Он использует два предохранительных клапана"], re:"У воздушного зазора нет подвижных частей, которые могли бы засориться, заклинить или износиться, поэтому он не может отказать, как могут обратный или предохранительный клапан. Источник: AWWA M14; USC FCCCHR."},
  {id:166, q:"Лабораторный кран с зубчатым выпуском (шланговая резьба) в здании использует какой класс приспособления точки использования для защиты от обратного сифонирования?", opts:["Только устройство пониженного давления","Вакуумный прерыватель (атмосферного типа/вакуумный прерыватель шлангового соединения)","Детекторное устройство двойного обратного клапана","Предохранительный клапан воздушного впуска"], re:"Лабораторные/хозяйственные выпуски со шланговой резьбой обычно защищаются вакуумными прерывателями шлангового соединения (атмосферного типа) от обратного сифонирования. Источник: AWWA M14; ASSE 1011."},
  {id:167, q:"Если на выпуске с опасностью, не связанной со здоровьем, который иначе мог бы использовать AVB, возможно непрерывное давление или обратное давление, надлежащим обновлением является переход на:", opts:["Заглушку шлангового крана","PVB/DC (или RP для опасности для здоровья), способное выдержать условие обслуживания","Более крупное AVB","Второе AVB последовательно"], re:"Поскольку AVB не может выдерживать непрерывное давление или обратное давление, обслуживание обновляется до PVB (обратное сифонирование, непрерывное давление) или DC/RP в зависимости от опасности и условий. Источник: AWWA M14; CA Title 17."},
  {id:168, q:"Какова цель испытательных кранов на устройстве защиты от обратного потока?", opts:["Дренировать здание","Обеспечить точки подключения манометра для полевой проверки обратных клапанов/предохранительного клапана","Сбрасывать тепловое расширение","Впускать воздух во время обратного сифонирования"], re:"Испытательные краны — это малые клапаны, позволяющие сертифицированному тестировщику подключить дифференциальный манометр для измерения герметичности обратного клапана и открытия предохранительного клапана. Источник: AWWA M14; USC FCCCHR."},
  {id:169, q:"В устройстве защиты от обратного потока запорные клапаны с эластичным седлом используются в основном для того, чтобы:", opts:["Постоянно снижать давление подачи","Изолировать устройство для проверки и обслуживания","Впускать воздух в систему","Заменять предохранительный клапан"], re:"Запорные клапаны входа и выхода изолируют устройство, чтобы его можно было проверить или обслужить. Источник: AWWA M14; стандарты ASSE."},
  {id:170, q:"Предохранительный клапан является определяющим внутренним компонентом какого устройства?", opts:["Двойной обратный клапан (DC)","Вакуумный прерыватель давления (PVB)","Принцип пониженного давления (RP)","Атмосферный вакуумный прерыватель (AVB)"], re:"Только RP содержит дифференциальный предохранительный клапан; DC, PVB и AVB его не имеют. Источник: AWWA M14."},
  {id:171, q:"Воздушный впускной клапан является определяющим внутренним компонентом какого приспособления/устройства?", opts:["Устройство пониженного давления","Вакуумные прерыватели давления/атмосферные (PVB/AVB/SVB)","Устройство двойного обратного клапана","Детекторное устройство RP"], re:"Воздушный впускной (вентиляционный) клапан — это характерный компонент вакуумных прерывателей (PVB/SVB/AVB), используемый для нарушения сифона; у DC/RP нет воздушного впуска. Источник: AWWA M14."},
  {id:172, q:"Обратные клапаны, используемые в устройствах RP и DC, характеризуются как:", opts:["Независимо действующие и принудительно нагруженные (пружиной) на закрытие","Нагруженные на открытие пружинами","Лепестковые обратные клапаны только под действием силы тяжести","С ручным управлением"], re:"Как RP, так и DC используют независимо действующие, внутренне принудительно нагруженные (пружиной) обратные клапаны, которые уплотняют против обратного потока. Источник: AWWA M14; ASSE 1013/1015."},
  {id:173, q:"'Эластичное седло' на обратном или запорном клапане означает:", opts:["Седло металл по металлу","Эластомерную (резиноподобную) уплотнительную поверхность для плотного, каплеплотного уплотнения","Керамический диск без прокладки","Резьбовую латунную пробку"], re:"Эластичные (эластомерные) седла обеспечивают каплеплотное уплотнение, требуемое для устройств защиты от обратного потока и их запорных клапанов. Источник: AWWA M14; AWWA C510/C511."},
  {id:174, q:"На устройстве с четырьмя испытательными кранами испытательный кран № 1 обычно расположен:", opts:["Ниже по потоку от второго обратного клапана","Только на предохранительном клапане","Выше по потоку от запорного клапана входа/первого обратного клапана (сторона подачи)","На воздушном впуске"], re:"По соглашению, испытательный кран № 1 находится на стороне подачи (выше по потоку от первого обратного клапана), а последующие краны пронумерованы через зону и ниже по потоку. Источник: процедуры проверки AWWA M14."},
  {id:175, q:"На RP испытательный кран, расположенный в зоне между двумя обратными клапанами, позволяет тестировщику измерить:", opts:["Потребление системы ниже по потоку","Давление зоны пониженного давления и точку открытия предохранительного клапана","Положение поплавка воздушного впуска","Расход магистрали подачи"], re:"Испытательный кран зоны считывает давление зоны пониженного давления и используется для определения перепада открытия предохранительного клапана. Источник: процедура проверки RP AWWA M14."},
  {id:176, q:"В PVB какой компонент принудительно нагружен в сторону ОТКРЫТИЯ, противоположно нагрузке обратного клапана?", opts:["Запорный клапан входа","Воздушный впускной клапан","Испытательный кран ниже по потоку","Болт крышки"], re:"Воздушный впуск PVB принудительно нагружен на открытие (обратный клапан принудительно нагружен на закрытие), поэтому он распахивается для впуска воздуха при потере давления. Источник: AWWA M14; ASSE 1020."},
  {id:177, q:"Какой компонент вы нашли бы на SVB, который НЕ встречается на стандартном PVB?", opts:["Мембранно-герметичный (устойчивый к разливу) воздушный впуск с продувочным/спускным клапаном","Второй предохранительный клапан","Два дополнительных обратных клапана","Воздушный зазор с поплавковым приводом"], re:"SVB добавляет мембранно-герметичный воздушный впуск и продувочный (спускной) клапан для удержания разлива и использует один испытательный кран. Источник: ASSE 1056."},
  {id:178, q:"Число независимо действующих обратных клапанов в RP и в DC составляет:", opts:["По одному в каждом","По два в каждом","Три в RP, два в DC","Два в RP, один в DC"], re:"Как RP, так и DC содержат два независимо действующих обратных клапана; RP дополнительно имеет предохранительный клапан между ними. Источник: AWWA M14."},
  {id:179, q:"Какова основная функция обратного клапана(ов) в любом из этих устройств?", opts:["Впускать воздух в линию","Пропускать поток в одном направлении и уплотнять против обратного потока","Снижать давление в линии до нуля","Учитывать малые расходы"], re:"Обратные клапаны пропускают прямой поток и закрываются для предотвращения обратного потока — основной барьер в DC, RP и вакуумных прерывателях. Источник: AWWA M14."},
  {id:180, q:"На RP предохранительный клапан отслеживает перепад давления, привязанный к какой точке?", opts:["Выпуск ниже по потоку","Давление подачи (на входе) относительно давления зоны","Только атмосферное давление","Воздушный впуск"], re:"Предохранительный клапан сравнивает давление подачи (на входе) с давлением зоны пониженного давления и открывается, когда этот перепад падает к ~2 psi. Источник: AWWA M14."},
  {id:181, q:"Спускной/продувочный клапан на SVB используется во время проверки для того, чтобы:", opts:["Создать давление в трубопроводе ниже по потоку","Стравить камеру крышки/воздушного впуска, чтобы можно было проверить открытие воздушного впуска","Увеличить нагрузку пружины","Дренировать все здание"], re:"Спускной (продувочный) клапан SVB сбрасывает давление в камере воздушного впуска, чтобы тестировщик мог убедиться, что воздушный впуск открывается в правильной точке. Источник: процедура проверки ASSE 1056."},
  {id:182, q:"Почему требуется, чтобы два обратных клапана в RP/DC работали НЕЗАВИСИМО?", opts:["Чтобы тестировщик должен был открыть оба одновременно","Чтобы отказ или засорение одного обратного клапана не препятствовали уплотнению другого","Чтобы разделять одну пружину","Чтобы устранить испытательные краны"], re:"Независимая работа означает, что каждый обратный клапан уплотняет самостоятельно, сохраняя резервирование, если другой засоряется или отказывает. Источник: AWWA M14; ASSE 1013/1015."},
  {id:183, q:"Какой внутренний компонент позволяет RP активно вытеснять воду из центральной зоны в атмосферу, когда защите угрожает опасность?", opts:["Обратный клапан ниже по потоку","Запорный клапан входа","Дифференциальный предохранительный клапан","Испытательный кран"], re:"Дифференциальный предохранительный клапан сбрасывает зону в атмосферу через воздушный зазор при падении перепада, что является уникальной особенностью RP. Источник: AWWA M14."},
  {id:184, q:"Ресторанный карбонатор (система напитков с CO2), подключенный к питьевому водоснабжению, требует какой защиты?", opts:["Устройство двойного обратного клапана","Устройство принципа пониженного давления (RP)","Вакуумный прерыватель давления","Атмосферный вакуумный прерыватель"], re:"Карбонатор представляет опасность для здоровья (CO2, реагирующий с медью, плюс обратное давление) и требует устройства RP. Источник: AWWA M14; таблицы опасностей CA Title 17."},
  {id:185, q:"Система полива, которая впрыскивает удобрения/пестициды (химигация), требует какого уровня защиты?", opts:["Атмосферный вакуумный прерыватель","Вакуумный прерыватель давления","Устройство двойного обратного клапана","Устройство пониженного давления (RP) или воздушный зазор"], re:"Впрыск химикатов превращает систему в опасность для здоровья, требующую устройства RP (или воздушного зазора); DC/PVB/AVB недостаточно. Источник: AWWA M14; CA Title 17."},
  {id:186, q:"При выборе устройства какие два фактора наиболее непосредственно определяют выбор?", opts:["Цвет и марка трубы","Степень опасности (для здоровья или нет) и тип обратного потока (обратное давление или только обратное сифонирование)","Только предпочтение установщика и цена","Время года и погода"], re:"Выбор определяется уровнем опасности (для здоровья/не для здоровья) и тем, может ли возникнуть обратное давление (в отличие от только обратного сифонирования). Источник: AWWA M14; CA Title 17."},
  {id:187, q:"Для обслуживания с опасностью, не связанной со здоровьем, где МОЖЕТ возникнуть обратное давление, какое устройство подходит?", opts:["Атмосферный вакуумный прерыватель","Вакуумный прерыватель давления","Устройство двойного обратного клапана","Вакуумный прерыватель шлангового крана"], re:"DC справляется с опасностями, не связанными со здоровьем, как при обратном давлении, так и при обратном сифонировании; PVB/AVB не могут выдерживать обратное давление. Источник: AWWA M14; CA Title 17."},
  {id:188, q:"PVB или AVB НЕ должно выбираться при наличии какого условия?", opts:["Только обратное сифонирование","Обратное давление (насос ниже по потоку, перепад высот или тепловое расширение)","Открытый атмосферный выпуск","Одна оросительная зона"], re:"Вакуумные прерыватели (PVB/AVB) защищают только от обратного сифонирования и никогда не должны использоваться там, где существует обратное давление. Источник: AWWA M14; CA Title 17."},
  {id:189, q:"Устройство RP должно устанавливаться в какой ориентации/расположении для правильной работы предохранительного клапана (если не сертифицировано иначе)?", opts:["Погруженным в отстойник","Горизонтально над уровнем земли с открытым портом сброса и надлежащим воздушным зазором к дренажу","Перевернутым ниже выпусков","Внутри герметичного, заполненного водой колодца"], re:"RP обычно устанавливается горизонтально над уровнем земли так, чтобы сброс предохранительного клапана был свободен от погружения и дренировался через воздушный зазор; его нельзя устанавливать там, где затопление может погрузить порт сброса. Источник: AWWA M14."},
  {id:190, q:"Достаточный зазор вокруг установленного устройства требуется в основном для того, чтобы:", opts:["Улучшить внешний вид","Обеспечить доступ для проверки, ремонта и разряда сброса/воздушного впуска","Увеличить давление воды","Уменьшить число испытательных кранов"], re:"Зазоры (например, вокруг и под устройством) требуются для того, чтобы тестировщик мог дотянуться до испытательных кранов и запорных клапанов и чтобы разряд сброса/воздушного впуска был беспрепятственным. Источник: руководство по установке AWWA M14."},
  {id:191, q:"Объект со вспомогательным (частный колодец) источником воды, перекрестно соединенным с общественным водоснабжением, как правило, требует какой защиты на вводе?", opts:["Атмосферный вакуумный прерыватель","Устройство двойного обратного клапана","Устройство пониженного давления (RP) или воздушный зазор","Никакой защиты"], re:"Неутвержденный вспомогательный источник рассматривается как опасность для здоровья, требующая устройства RP или воздушного зазора на вводном соединении. Источник: AWWA M14; CA Title 17."},
  {id:192, q:"Медицинский/стоматологический кабинет (аспираторы, стерилизаторы), подключенный к питьевой воде, обычно требует:", opts:["Устройство пониженного давления (RP)","Устройство двойного обратного клапана","Атмосферный вакуумный прерыватель","Вакуумный прерыватель шлангового крана"], re:"Медицинские/стоматологические учреждения являются опасностями для здоровья (риск обратного потока загрязнителей) и требуют защиты RP. Источник: AWWA M14; таблицы опасностей CA Title 17."},
  {id:193, q:"Чтобы PVB работало, соотношение между устройством и системой, которую оно обслуживает, должно быть:", opts:["PVB как минимум на 12 in выше самого высокого выпуска ниже по потоку","PVB ниже самого низкого выпуска","PVB на том же уровне, что и выпуски","PVB погружено для охлаждения"], re:"Воздушный впуск PVB должен находиться как минимум на 12 in выше самого высокого выпуска ниже по потоку, чтобы его нельзя было затопить обратным потоком и оно могло нарушить сифон. Источник: AWWA M14; CA Title 17 §7603(b)."},
  {id:194, q:"Почему RP никогда нельзя устанавливать в месте, подверженном затоплению, хотя оно дает наивысшую защиту среди устройств?", opts:["Воздушный зазор его сброса может оказаться погруженным, создавая перекрестное соединение","Оно потеряло бы всю свою классификацию по обратному давлению","Затопление повышает давление подачи","Испытательные краны становятся декоративными"], re:"Погружение сброса предохранительного клапана нарушает воздушный зазор и может засифонировать загрязненную паводковую воду обратно в питьевую линию; порты сброса RP должны оставаться выше уровня затопления. Источник: AWWA M14."},
  {id:195, q:"Линия пожарных спринклеров, использующая непитьевые добавки (антифриз/пена), является опасностью для здоровья и требует какого устройства?", opts:["Детекторное устройство двойного обратного клапана (DCDA)","Детекторное устройство пониженного давления (RPDA)","Атмосферный вакуумный прерыватель","Вакуумный прерыватель давления"], re:"Когда пожарная линия содержит химические добавки, она становится опасностью для здоровья, требующей защиты уровня RP, то есть RPDA (RP с детектором). Простое DCDA предназначено только для пожарных линий с опасностью, не связанной со здоровьем. Источник: AWWA M14; CA Title 17."},
  {id:196, q:"Стандартная (без добавок) линия пожарных спринклеров, которая является опасностью, не связанной со здоровьем, но требует обнаружения утечек/использования, обычно использует:", opts:["Детекторное устройство пониженного давления","Детекторное устройство двойного обратного клапана (DCDA)","Атмосферный вакуумный прерыватель","Вакуумный прерыватель шлангового крана"], re:"Пожарная линия с опасностью, не связанной со здоровьем, нуждающаяся в обнаружении, использует DCDA; RPDA зарезервировано для пожарных систем с опасностью для здоровья. Источник: AWWA M14."},
  {id:197, q:"Когда возможно обратное давление на соединении с опасностью для ЗДОРОВЬЯ, правильным выбором является:", opts:["Вакуумный прерыватель давления","Атмосферный вакуумный прерыватель","Устройство пониженного давления (RP) или воздушный зазор","Устройство двойного обратного клапана"], re:"Опасность для здоровья плюс обратное давление требуют наивысшего механического устройства (RP) или воздушного зазора; PVB/AVB не могут выдерживать обратное давление, а DC не рассчитано на опасности для здоровья. Источник: AWWA M14; CA Title 17."},
  {id:198, q:"Какая практика установки правильна для PVB, обслуживающего полив газона?", opts:["Установить его в закопанном коробе ниже спринклерных головок","Установить его вертикально как минимум на 12 in выше самой высокой головки, с доступом для проверки","Положить его на бок на уровне земли","Подключить вентиль его крышки к канализации"], re:"PVB должно быть вертикальным, как минимум на 12 in выше самого высокого выпуска ниже по потоку и доступным для ежегодной проверки. Источник: AWWA M14; ASSE 1020; CA Title 17 §7603(b)."},
  {id:199, q:"Общее ранжирование защиты от наивысшей к низшей среди утвержденных методов:", opts:["AVB > PVB > DC > RP > Воздушный зазор","Воздушный зазор > RP > PVB > DC > AVB","DC > RP > Воздушный зазор > PVB > AVB","PVB > AVB > RP > DC > Воздушный зазор"], re:"Перечислено в порядке убывания защиты: воздушный зазор, затем RP, затем PVB, затем DC, затем AVB. Источник: CA Title 17; ранжирование опасностей AWWA M14."},
  {id:200, q:"Прежде чем выбрать устройство, самым основополагающим шагом, требуемым программами контроля перекрестных соединений, является:", opts:["Заказать самое крупное доступное устройство","Оценить степень опасности и тип возможного обратного потока на соединении","Выбрать самое дешевое приспособление","Установить приспособление, а затем проверить опасность"], re:"Надлежащая защита следует за оценкой опасности: определить опасность для здоровья/не для здоровья и может ли возникнуть обратное давление или только обратное сифонирование, затем выбрать соответствующее устройство. Источник: AWWA M14; CA Title 17 §7583 et seq."},
  {id:201, q:"Что на самом деле измеряет испытательный прибор, используемый для полевого испытания узлов предотвращения обратного потока?", opts:["Разницу давления между двумя точками, в фунтах на квадратный дюйм дифференциальных (psid)","Расход воды через узел в галлонах в минуту","Абсолютное статическое давление в линии на подающей магистрали","Температуру воды на выходе предохранительного клапана"], re:"Тестер обратного потока использует дифференциальный манометр, который показывает разницу давления между его высокой и низкой сторонами в psid. Источник: Руководство AWWA M14; USC FCCCHR Field Test Procedures, 10-е изд."},
  {id:202, q:"В каком диапазоне показаний откалиброван стандартный дифференциальный манометр для обратного потока?", opts:["от 0 до 150 psid","от 0 до 15 psid","от 0 до 5 psid","от 0 до 60 psid"], re:"Полевые испытательные манометры обычно показывают 0-15 psid (0-100 кПа), что охватывает малые перепады, наблюдаемые на обратных и предохранительных клапанах. Источник: спецификация манометра Mid-West Instrument 845-5; AWWA M14."},
  {id:203, q:"В испытательном комплекте с дифференциальным манометром на 3 клапана, как обычно называются три игольчатых клапана?", opts:["Впускной, выпускной и дренажный клапаны","Красный, зелёный и синий клапаны","Управление высокой стороной, управление низкой стороной и обвод (вент/продувка)","Первичный, вторичный и третичный клапаны"], re:"Комплект на 3 клапана имеет управление высокой стороной, управление низкой стороной и обводной/продувочный (bleed) клапан. Источник: USC FCCCHR Field Test Procedures; описание испытательного комплекта с дифференциальным манометром в AWWA M14."},
  {id:204, q:"По сравнению с комплектом на 3 клапана, какие дополнительные клапаны добавляет испытательный комплект с дифференциальным манометром на 5 клапанов?", opts:["Редукционный клапан и предохранительный клапан","Второй манометр и расходомер","Только два дополнительных шланговых соединения, без добавленных клапанов","Два дополнительных продувочных клапана (продувка высокой и продувка низкой стороны)"], re:"Комплект на 5 клапанов добавляет отдельные продувочные клапаны высокой и низкой стороны к клапанам высокой, низкой стороны и обвода, упрощая удаление воздуха. Источник: комплект Mid-West 845-5 на 5 клапанов; AWWA M14."},
  {id:205, q:"Прежде чем записывать какое-либо испытание, почему необходимо стравить весь воздух из шлангов и корпуса манометра?", opts:["Потому что захваченный воздух сжимается и даёт ложное (неточное) дифференциальное показание","Чтобы шланги не замёрзли","Чтобы снизить давление в линии подачи перед испытанием","Чтобы испытательные краны не подтекали"], re:"Захваченный воздух сжимаем и искажает дифференциальное показание, поэтому шланги и манометр необходимо продуть от воздуха перед снятием показаний. Источник: USC FCCCHR Field Test Procedures; AWWA M14."},
  {id:206, q:"Где следует располагать дифференциальный манометр относительно узла во время испытания?", opts:["Не менее чем на 3 фута выше узла","Примерно на той же высоте, что и узел","Всегда ниже узла, на земле","Высота не имеет значения для дифференциальных показаний"], re:"Манометр и шланги следует держать на той же высоте, что и узел, чтобы столб воды в шлангах не добавлял ошибку высоты к дифференциальному показанию. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:207, q:"Согласно общим нормативным требованиям, как часто необходимо калибровать дифференциальный манометр тестера обратного потока?", opts:["Раз в пять лет","Только при первой покупке","Не реже одного раза в год","Раз в месяц"], re:"Большинство юрисдикций требуют калибровать дифференциальный испытательный манометр не реже одного раза в год, и дата калибровки записывается в протоколе испытания. Источник: AWWA M14; правила программ по перекрёстным соединениям штатов (например, NY DOH, протокол испытания Denver Water)."},
  {id:208, q:"Каково назначение продувочного (вент) клапана в испытательном комплекте с дифференциальным манометром?", opts:["Повышать давление подачи на узел","Перекрывать водоснабжение клиента","Измерять расход через обратный клапан № 1","Позволять захваченному воздуху и воде выходить, чтобы продуть шланги"], re:"Продувочный/вент клапан позволяет воздуху и воде выходить из комплекта и шлангов, чтобы линии можно было заполнить и сделать свободными от воздуха перед снятием показания. Источник: USC FCCCHR Field Test Procedures; AWWA M14."},
  {id:209, q:"В типичном испытательном комплекте с цветовой маркировкой шланг ВЫСОКОЙ стороны и шланг НИЗКОЙ стороны обычно какого цвета?", opts:["Высокая = красный, Низкая = зелёный (или синий)","Высокая = зелёный, Низкая = красный","Высокая = жёлтый, Низкая = чёрный","Оба шланга белые"], re:"Испытательные комплекты обычно окрашивают шланг высокой стороны в красный, а шланг низкой стороны в зелёный (или синий), чтобы тестер подключал каждый к нужному испытательному крану. Источник: AWWA M14; иллюстрации процедуры испытания PNW-AWWA."},
  {id:210, q:"Многие испытательные комплекты включают фильтрующие сетки на 90 микрон на шланговых фитингах. Каково их основное назначение?", opts:["Снижать давление воды, поступающей в манометр","Не давать накипи, песку и мусору засорять каналы манометра","Подогревать воду перед тем, как она достигнет манометра","Добавлять хлор в испытательную воду"], re:"Линейные фильтрующие сетки не дают песку, накипи и грязи попадать и засорять малые внутренние каналы дифференциального манометра. Источник: литература по испытательным комплектам Mid-West Instrument; AWWA M14."},
  {id:211, q:"Что должен сделать тестер с испытательными кранами перед подключением шлангов манометра?", opts:["Оставить их закрытыми колпачками и подключить поверх колпачков","Покрасить их, чтобы отметить, какой есть какой","Кратко открыть каждый, чтобы промыть мусор, затем подключить шланги","Полностью снять их с узла"], re:"Каждый испытательный кран кратко открывают, чтобы выдуть грязь и мусор из порта перед подключением шланга, что защищает манометр. Источник: USC FCCCHR Field Test Procedures; AWWA M14."},
  {id:212, q:"Заявленная точность типичного дифференциального манометра для обратного потока ближе всего к какому значению?", opts:["Плюс-минус 0.001 psid","Плюс-минус 2 psid","Плюс-минус 5 psid","Плюс-минус 0.2 psid"], re:"Типичный полевой манометр имеет точность около плюс-минус 0.2 psid на нисходящем показании. Источник: спецификация Mid-West Instrument 845-5; AWWA M14."},
  {id:213, q:"Когда испытательный комплект подключён со шлангами высокой и низкой стороны на одном и том же закрытом обратном клапане, какое показание должен дать правильно продутый, точный манометр?", opts:["Примерно ноль psid (нет перепада), пока давления не различаются","Полное давление в линии","Около 15 psid","Отрицательное показание, равное атмосферному давлению"], re:"Когда обе стороны воспринимают одинаковое давление и перепад не приложен, правильно продутый манометр показывает около нуля; ненулевое статическое показание сигнализирует о захваченном воздухе или проблеме манометра. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:214, q:"Какова функция 'обводного' (вент) клапана при создании условий потока через манометр во время настройки?", opts:["Он постоянно изолирует низкую сторону от высокой стороны","Он соединяет высокую и низкую стороны, чтобы вода могла проходить и продувать комплект","Он стравливает подающую магистраль в атмосферу","Он автоматически калибрует стрелку на ноль"], re:"Открытие обвода соединяет высокую и низкую камеры, чтобы вода протекала через комплект, позволяя выносить захваченный воздух при продувке. Источник: USC FCCCHR Field Test Procedures; AWWA M14."},
  {id:215, q:"Почему управляющий клапан высокой стороны обычно оставляют открытым на всё время дифференциального испытания RP или DC после настройки комплекта?", opts:["Чтобы предохранительный клапан никогда не открывался","Чтобы медленно сливать водонагреватель клиента","Чтобы давление подачи постоянно воспринималось на высокой стороне манометра","Потому что его закрытие повредит манометр"], re:"Сохранение открытым клапана высокой стороны поддерживает опорное давление выше по потоку/подачи на высокой стороне манометра в течение всего испытания. Источник: процедуры RP и DC USC FCCCHR / PNW-AWWA."},
  {id:216, q:"Производители описывают испытательный комплект на 5 клапанов как способный испытывать какие узлы?", opts:["Только узлы принципа пониженного давления (RP)","Только узлы детектора пожарной линии","Только вакуумные прерыватели давления","Узлы RP, двойного обратного клапана (DC) и вакуумного прерывателя давления (PVB)"], re:"Комплект на 5 клапанов может выполнять полевые испытания узлов RP, DC и PVB и аттестован для процедур ASSE, AWWA, CSA и USC. Источник: литература по комплекту Mid-West 845-5; AWWA M14."},
  {id:217, q:"Перед началом испытания дифференциальный манометр следует проверить, чтобы подтвердить, что он показывает что при отсутствии приложенного давления?", opts:["Ноль (стрелка покоится на отметке ноль)","Точно 15 psid","Половину шкалы","Местное барометрическое давление"], re:"При отсутствии приложенного перепада стрелка должна покоиться на нуле; стрелка вне нуля указывает, что манометру требуется внимание, прежде чем ему доверять для испытания. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:218, q:"Чтобы ПРОЙТИ, предохранительный клапан узла принципа пониженного давления (RP) должен начать открываться (сбрасывать) при перепаде давления не менее скольки?", opts:["1.0 psid","2.0 psid","5.0 psid","0.5 psid"], re:"Предохранительный клапан RP должен открываться при минимальном перепаде 2.0 psid, чтобы пройти полевое испытание. Источник: Руководство AWWA M14; USC FCCCHR Field Test Procedures, 10-е изд."},
  {id:219, q:"Чтобы узел RP прошёл, обратный клапан № 1 должен удерживать перепад давления не менее скольки в направлении потока?", opts:["1.0 psid","2.0 psid","5.0 psid","10.0 psid"], re:"Обратный клапан № 1 RP должен удерживать не менее 5.0 psid в направлении потока, чтобы пройти. Источник: AWWA M14; USC FCCCHR Field Test Procedures, 10-е изд."},
  {id:220, q:"Помимо своего минимального значения, какое соотношение должен иметь перепад обратного клапана № 1 с точкой открытия предохранительного клапана на RP?", opts:["Он должен быть равен точке открытия предохранительного клапана","У него нет требуемого соотношения с предохранительным клапаном","Он должен быть ниже точки открытия предохранительного клапана","Он должен быть не менее чем на 3 psid выше точки открытия предохранительного клапана"], re:"Первый обратный клапан должен удерживать перепад не менее чем на 3.0 psid больше точки открытия предохранительного клапана ('буфер'), чтобы предохранительный клапан открывался раньше, чем первый обратный клапан начнёт подтекать. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:221, q:"Сколько испытательных кранов у типичного узла RP?", opts:["Четыре","Два","Один","Шесть"], re:"Узел RP имеет четыре испытательных крана (№ 1 выше по потоку обратного клапана № 1, № 2 и № 3 в области зоны пониженного давления, № 4 ниже по потоку обратного клапана № 2). Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:222, q:"В процедуре RP 10-го издания USC, какой компонент испытывается ПЕРВЫМ?", opts:["Обратный клапан № 2","Точка открытия предохранительного клапана","Обратный клапан № 1","Запорный клапан ниже по потоку"], re:"10-е издание USC первым испытывает точку открытия предохранительного клапана, что также подтверждает, что узел находится в статическом состоянии перед испытанием обратных клапанов. Источник: USC FCCCHR Field Test Procedures, 10-е изд."},
  {id:223, q:"Что делает предохранительный клапан узла RP, когда перепад между подачей и зоной падает до его точки открытия?", opts:["Закрывается плотнее, чтобы удержать давление","Повышает давление подачи","Открывается и сбрасывает воду из зоны в атмосферу","Блокирует обратные клапаны в открытом положении"], re:"Когда перепад зоны падает примерно до 2 psid, предохранительный клапан открывается и сбрасывает зону пониженного давления в атмосферу, предотвращая обратный поток. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:224, q:"Во время испытания RP, для чего в основном используется испытательный кран № 4?", opts:["Регулировки пружины предохранительного клапана","Слива системы орошения клиента","Установки корпуса дифференциального манометра","Восприятия давления ниже по потоку обратного клапана № 2"], re:"Испытательный кран № 4 расположен ниже по потоку второго обратного клапана и используется для восприятия давления ниже по потоку при испытании обратного клапана № 2. Источник: AWWA M14; процедура испытания RP PNW-AWWA."},
  {id:225, q:"При испытании точки открытия предохранительного клапана, в какой момент записывается показание?", opts:["Когда предохранительный клапан впервые начинает сбрасывать (вода впервые капает/течёт из порта сброса)","После того как предохранительный клапан сбрасывал в течение пяти минут","Когда стрелка манометра достигает 15 psid","Когда запорный клапан ниже по потоку полностью открыт"], re:"Перепад считывается в момент, когда предохранительный клапан впервые открывается и вода начинает выходить из порта сброса. Источник: USC FCCCHR Field Test Procedures; AWWA M14."},
  {id:226, q:"Какой запорный клапан необходимо закрыть, чтобы изолировать узел RP для испытания обратных клапанов (чтобы можно было создать статический перепад)?", opts:["Запорный клапан № 1 (выше по потоку)","Запорный клапан № 2 (ниже по потоку)","Оба запорных клапана сразу","Ни один запорный клапан не закрывается"], re:"Запорный клапан ниже по потоку (№ 2) закрывают, чтобы изолировать узел от потребления ниже по потоку, чтобы можно было считать стабильный статический перепад на обратных клапанах. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:227, q:"Если предохранительный клапан RP непрерывно сбрасывает воду во время нормальной эксплуатации, что это обычно указывает?", opts:["Узел работает идеально","Давление подачи слишком высокое для испытания","Засорённый первый обратный клапан № 1 или проблема предохранительного клапана/зоны, вызывающая падение перепада зоны","Запорный клапан ниже по потоку открыт"], re:"Непрерывный сброс обычно означает, что перепад зоны упал (часто засорённый первый обратный клапан или подтекающее седло предохранительного клапана), и причину необходимо диагностировать и устранить. Источник: USC FCCCHR Field Test Procedures; поиск неисправностей AWWA M14."},
  {id:228, q:"Для испытания открытия предохранительного клапана на RP с помощью манометра, какие испытательные краны обычно используются для восприятия высокого (подача) и зонного давлений?", opts:["Для этого шага испытательные краны не используются","Только испытательный кран № 1 и испытательный кран № 4","Только испытательный кран № 4","Испытательный кран № 2 (высокая/сторона подачи) и испытательный кран № 3 (сторона зоны)"], re:"Шланг высокой стороны воспринимает область подачи/первого обратного клапана (№ 2), а шланг низкой стороны воспринимает зону (№ 3), чтобы манометр отслеживал перепад зоны по мере открытия предохранительного клапана. Источник: процедура испытания RP PNW-AWWA / USC."},
  {id:229, q:"В процедуре RP USC, после испытания предохранительного клапана, какой обратный клапан испытывается перед первым обратным клапаном?", opts:["Обратный клапан № 2 (с противодавлением)","Второго обратного клапана для испытания нет","Предохранительный клапан испытывается повторно","Обводной обратный клапан"], re:"Последовательность USC испытывает предохранительный клапан, затем обратный клапан № 2 под противодавлением и завершает обратным клапаном № 1 в направлении потока. Источник: USC FCCCHR Field Test Procedures, 10-е изд."},
  {id:230, q:"Почему первый обратный клапан RP должен удерживать БОЛЕЕ ВЫСОКИЙ перепад, чем точка открытия предохранительного клапана?", opts:["Чтобы манометр показывал ноль","Чтобы предохранительный клапан сбросил раньше, чем первый обратный клапан начнёт пропускать назад, сохраняя зону безопасной","Чтобы второй обратный клапан никогда не должен был закрываться","Чтобы снизить давление подачи"], re:"Буфер гарантирует, что предохранительный клапан сбросит зону раньше, чем первый обратный клапан сможет пропустить воду назад, сохраняя защиту пониженного давления. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:231, q:"Предохранительный клапан RP открывается точно при 2.0 psid, а обратный клапан № 1 удерживает 4.0 psid. Проходит ли узел?", opts:["Да, оба значения отвечают всем требованиям","Да, потому что важен только предохранительный клапан","Нет, потому что первый обратный клапан должен удерживать не менее 5.0 psid И быть на 3 psid выше открытия сброса","Нет, потому что предохранительный клапан открылся слишком низко"], re:"Предохранительный клапан (2.0 psid) проходит, но обратный клапан № 1 при 4.0 psid не отвечает минимуму 5.0 psid и правилу буфера в 3 psid, поэтому узел не проходит. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:232, q:"Что необходимо сделать перед началом полевого испытания RP в отношении клиента?", opts:["Ничего; испытание никогда не влияет на обслуживание","Отсоединить водяной счётчик","Отключить электричество клиента","Уведомить клиента, что водоснабжение будет прервано во время испытания"], re:"Тестер должен уведомить клиента, потому что запорный клапан ниже по потоку закрывается и обслуживание прерывается во время испытания. Источник: USC FCCCHR Field Test Procedures; процедуры RP штатов (например, GAWP)."},
  {id:233, q:"Если предохранительный клапан RP открывается всего при 1.5 psid во время испытания, каков результат?", opts:["Не проходит, потому что точка открытия ниже минимума 2.0 psid","Проходит, потому что он открылся","Проходит, если обратные клапаны герметичны","Показание следует игнорировать"], re:"Точка открытия ниже 2.0 psid не отвечает требованию к предохранительному клапану, и узел не может пройти, пока не будет отремонтирован. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:234, q:"На RP, где расположен испытательный кран № 1?", opts:["Ниже по потоку второго обратного клапана","Выше по потоку первого обратного клапана (сторона подачи)","Внутри предохранительного клапана","На запорном клапане ниже по потоку"], re:"Испытательный кран № 1 находится на стороне подачи, выше по потоку первого обратного клапана, и используется для считывания давления в линии подачи. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:235, q:"Чтобы узел двойного обратного клапана (DC) прошёл, какой перепад давления должен удерживать каждый обратный клапан как минимум в направлении потока?", opts:["5.0 psid","2.0 psid","1.0 psid","0.5 psid"], re:"Каждый обратный клапан узла DC должен удерживать минимум 1.0 psid в нормальном направлении потока, чтобы пройти. Источник: Руководство AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:236, q:"Сколько испытательных кранов у типичного узла двойного обратного клапана?", opts:["Один","Два","Восемь","Четыре"], re:"Узел DC имеет четыре испытательных крана: № 1 выше по потоку обратного клапана 1, № 2 между запором и обратным клапаном 1, № 3 между обратными клапанами и № 4 ниже по потоку обратного клапана 2. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:237, q:"При испытании обратного клапана № 1 DC на герметичность, между какими двумя испытательными кранами измеряется перепад?", opts:["Испытательный кран № 2 (высокая) и испытательный кран № 3 (низкая)","Испытательный кран № 1 и испытательный кран № 4","Только испытательный кран № 4","Только испытательный кран № 3, с вентилированием"], re:"Герметичность обратного клапана № 1 считывается со шлангом высокой стороны на стороне выше по потоку (испытательный кран № 2) и шлангом низкой стороны между обратными клапанами (испытательный кран № 3). Источник: AWWA M14; процедура испытания DC PNW-AWWA."},
  {id:238, q:"При испытании обратного клапана № 2 DC на герметичность, куда обычно подключаются шланги манометра?", opts:["Шланг высокой стороны к испытательному крану № 1 и шланг низкой стороны к испытательному крану № 2","Шланг высокой стороны к испытательному крану № 3 и шланг низкой стороны к испытательному крану № 4","Оба шланга к испытательному крану № 1","Ни один шланг; это визуальное испытание"], re:"Герметичность обратного клапана № 2 считывается со шлангом высокой стороны между обратными клапанами (испытательный кран № 3) и шлангом низкой стороны ниже по потоку (испытательный кран № 4). Источник: AWWA M14; процедура испытания DC PNW-AWWA."},
  {id:239, q:"Обратный клапан DC удерживает 1.0 psid в направлении потока. Что заключается о его герметичности при обратном потоке?", opts:["Он будет подтекать в обратном направлении и не проходит","Обратный поток нельзя вывести, и второе испытание обязательно","Предполагается, что он также удержит герметичность в обратном направлении потока","Он должен удерживать 5.0 psid в обратном направлении, чтобы пройти"], re:"AWWA M14 считает, что если обратный клапан уплотняется при 1.0 psid или более в нормальном направлении, предполагается, что он удержит герметичность против обратного потока. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:240, q:"Какой запорный клапан закрывают, чтобы изолировать узел DC, чтобы можно было считать статический перепад на обратных клапанах?", opts:["Никакой запор не закрывается","Запорный клапан № 1 (выше по потоку)","Оба запора одновременно","Запорный клапан № 2 (ниже по потоку)"], re:"Запорный клапан ниже по потоку (№ 2) закрывают, чтобы устранить потребление ниже по потоку и создать статическое состояние для дифференциальных показаний. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:241, q:"Когда показание манометра стабилизируется и вода перестаёт течь из испытательного крана ниже по потоку во время испытания обратного клапана DC, что записывается?", opts:["Стабилизированное показание psid, и обратный клапан записывается как удерживающий герметичность при этом значении","Давление в линии подачи","Расход в gpm","Температура воды"], re:"Когда поток прекращается и стрелка устанавливается, записывается стабилизированный перепад; если он 1.0 psid или более, обратный клапан записывается как герметичный. Источник: AWWA M14; процедура испытания DC PNW-AWWA."},
  {id:242, q:"Обратный клапан № 1 DC удерживает 0.8 psid, а обратный клапан № 2 удерживает 2.5 psid. Каков общий результат испытания?", opts:["Проход, потому что два обратных клапана в среднем выше 1.0 psid","Не проход, потому что обратный клапан № 1 ниже минимума 1.0 psid","Проход, потому что хотя бы один обратный клапан превышает 1.0 psid","Не проход, потому что обратный клапан № 2 удержал слишком много"], re:"Каждый обратный клапан оценивается независимо; обратный клапан № 1 при 0.8 psid ниже минимума 1.0 psid, поэтому узел не проходит. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:243, q:"Какое утверждение об узле DC верно по сравнению с RP?", opts:["DC имеет предохранительный клапан, как RP","DC имеет только один обратный клапан","DC не имеет предохранительного клапана; он полагается на два независимо работающих обратных клапана","DC вентилирует в атмосферу между обратными клапанами, как RP"], re:"DC имеет два независимых подпружиненных обратных клапана и не имеет атмосферного предохранительного клапана, поэтому он не сбрасывает в атмосферу, как это делает RP. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:244, q:"На DC, что показывает испытательный кран № 1?", opts:["Давление между двумя обратными клапанами","Сброс предохранительного клапана","Давление ниже по потоку второго обратного клапана","Давление в линии подачи, выше по потоку первого обратного клапана"], re:"Испытательный кран № 1 находится выше по потоку обратного клапана № 1 и используется для считывания давления в линии подачи. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:245, q:"Почему необходимо стравить воздух из шлангов манометра перед считыванием любого обратного клапана DC?", opts:["Потому что сжимаемый воздух даёт ложно низкое или нестабильное дифференциальное показание","Чтобы искусственно поднять перепад","Чтобы охладить узел","Чтобы открыть второй обратный клапан"], re:"Воздух в линиях сжимается и искажает малый измеряемый перепад, поэтому шланги необходимо продуть перед считыванием перепада обратного клапана. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:246, q:"'Подтекающий запорный клапан № 2' может повлиять на испытание обратного клапана № 2 DC. Какая особенность защищает испытание от этого?", opts:["Полное открытие испытательного крана № 1","Установка продувочного клапана на испытательном кране высокой стороны для процедуры с одним шлангом","Полное снятие манометра","Закрытие вместо этого запора выше по потоку"], re:"Процедура USC добавляет продувочный клапан на испытательный кран высокой стороны, чтобы подтекающий запор № 2 не делал недействительным показание обратного клапана № 2 с одним шлангом. Источник: USC FCCCHR Field Test Procedures, 10-е изд."},
  {id:247, q:"Во время испытания обратного клапана № 2 DC методом одного шланга, какой испытательный кран открывают в атмосферу со стороны ниже по потоку?", opts:["Испытательный кран № 2","Испытательный кран № 1","Испытательный кран № 4","Порт предохранительного клапана"], re:"Когда шланг высокой стороны на испытательном кране № 3, испытательный кран № 4 открывают, чтобы сторона ниже по потоку воспринимала атмосферу для перепада обратного клапана № 2. Источник: AWWA M14; процедура испытания DC PNW-AWWA."},
  {id:248, q:"Если при испытании обратного клапана № 1 DC перепад не нарастает и вода продолжает двигаться, какова вероятная причина?", opts:["Первый обратный клапан уплотняется идеально","Давление ниже по потоку равно нулю по конструкции","Диапазон манометра слишком высок","Первый обратный клапан засорён/подтекает или запор пропускает воду"], re:"Невозможность нарастить и удержать перепад указывает на подтекающий первый обратный клапан или пропускающий запорный клапан, что необходимо диагностировать. Источник: поиск неисправностей AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:249, q:"Для DC давление в линии подачи для протокола обычно считывается в какой точке?", opts:["На испытательном кране № 1 с открытым запором № 1","На испытательном кране № 4 с обоими закрытыми запорами","На предохранительном клапане","Только на испытательном кране № 3"], re:"Давление подачи/линии считывается на испытательном кране № 1 на стороне подачи. Источник: AWWA M14; инструкции к протоколу испытания штата (например, Denver Water)."},
  {id:250, q:"Оба обратных клапана DC должны закрываться 'каплегерметично'. В терминах испытания, что на самом деле требуется для прохождения?", opts:["Каждый обратный клапан удерживает не менее 5.0 psid","Каждый обратный клапан удерживает не менее 1.0 psid статического перепада в направлении потока","Обратные клапаны вместе удерживают 1.0 psid","Никакой измеримый перепад не допускается"], re:"Каждый обратный клапан проходит, когда удерживает статический перепад 1.0 psid или более в направлении потока, что подтверждает плотное уплотнение. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:251, q:"В узле двойного обратного клапана ДЕТЕКТОРНОГО типа (DCDA), малая обводная линия счётчика также содержит что для испытания?", opts:["Вообще никакой защиты от обратного потока","Предохранительный клапан, идентичный RP","Свой собственный узел двойного обратного клапана, который также необходимо испытать","Только вакуумный прерыватель давления"], re:"Детекторный узел двойного обратного клапана имеет обвод со счётчиком, который содержит свой собственный двойной обратный клапан, испытываемый по тем же критериям 1.0 psid на обратный клапан. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:252, q:"Чтобы вакуумный прерыватель давления (PVB) прошёл, воздуховпускной клапан должен начать открываться при давлении не менее скольки выше атмосферного?", opts:["0.5 psi","2.0 psi","5.0 psi","1.0 psi"], re:"Воздуховпуск PVB должен открываться, когда внутреннее давление не менее 1.0 psi выше атмосферного, чтобы пройти. Источник: Руководство AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:253, q:"Чтобы PVB прошёл, единственный обратный клапан должен удерживать перепад давления не менее скольки?", opts:["1.0 psid","2.0 psid","5.0 psid","0.5 psid"], re:"Обратный клапан PVB должен удерживать не менее 1.0 psid, чтобы пройти. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:254, q:"Сколько испытательных кранов у типичного PVB?", opts:["Один","Два","Четыре","Шесть"], re:"PVB имеет два испытательных крана, по одному с каждой стороны, используемых для испытания обратного клапана и точки открытия воздуховпуска. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:255, q:"Чем брызгозащищённый вакуумный прерыватель (SVB) структурно отличается от PVB для испытания?", opts:["SVB имеет четыре испытательных крана","SVB имеет предохранительный клапан, как RP","SVB имеет один испытательный кран плюс вент (продувочный) клапан вместо двух испытательных кранов","SVB не имеет воздуховпуска"], re:"SVB имеет только один испытательный кран вместе с вент/продувочным клапаном, тогда как PVB имеет два испытательных крана. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:256, q:"Чтобы SVB прошёл, воздуховпуск должен открываться при минимуме скольки, и также должен делать что?", opts:["Минимум 5.0 psi, и сбрасывать воду","Минимум 2.0 psi, и только приоткрываться","Минимум 0.5 psi, и оставаться закрытым","Минимум 1.0 psi, и воздуховпуск должен открываться полностью"], re:"Воздуховпуск SVB должен открываться при 1.0 psi или более и должен открываться полностью. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:257, q:"Для SVB, какой перепад должен удерживать обратный клапан как минимум, чтобы пройти?", opts:["1.0 psid","2.0 psid","3.0 psid","0.5 psid"], re:"Обратный клапан SVB должен удерживать не менее 1.0 psid, чтобы пройти. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:258, q:"На PVB, какой запорный клапан закрывают при изоляции узла для испытания обратного клапана и воздуховпуска?", opts:["Только запор выше по потоку","Запор ниже по потоку (при подтверждённо открытом запоре выше по потоку)","Оба запора сразу","Никакой; у PVB нет запоров"], re:"Запор ниже по потоку закрывают (и подтверждают, что запор выше по потоку открыт), чтобы корпус можно было изолировать для испытаний воздуховпуска и обратного клапана. Источник: AWWA M14; процедура испытания PVB PNW-AWWA."},
  {id:259, q:"Из-за того, как работает PVB, где он должен быть установлен относительно всех выходов ниже по потоку?", opts:["Ниже самого низкого выхода","На том же уровне, что и выходы","Не менее чем на 12 дюймов выше всех трубопроводов и выходов ниже по потоку, которые он защищает","Под землёй в колодце"], re:"PVB должен устанавливаться не менее чем на 12 дюймов выше всех трубопроводов/выходов ниже по потоку, потому что он защищает только от обратного сифонирования, а не от противодавления. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:260, q:"Почему PVB или SVB НЕЛЬЗЯ использовать там, где может возникнуть противодавление?", opts:["Он бы показывал слишком высоко на манометре","Он работает только на горячей воде","У него слишком много испытательных кранов","Его воздуховпуск обеспечивает защиту только от обратного сифонирования, а не от противодавления"], re:"Узлы PVB и SVB защищают только от обратного сифонирования; при противодавлении воздуховпуск не может предотвратить обратный поток, поэтому их нельзя использовать там, где может существовать противодавление. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:261, q:"В стандартной последовательности испытания PVB/SVB, что испытывается первым?", opts:["Сначала обратный клапан, затем точка открытия воздуховпуска","Точка открытия воздуховпуска, затем обратный клапан","Оба одновременно","Предохранительный клапан, затем обратный клапан"], re:"Процедуры USC и AWWA испытывают сначала обратный клапан, а затем точку открытия воздуховпуска. Источник: AWWA M14; USC FCCCHR Field Test Procedures (SVB/PVB)."},
  {id:262, q:"Во время испытания воздуховпуска PVB, в какой момент снимается показание?", opts:["После того как воздуховпуск был открыт в течение 10 минут","Когда воздуховпуск впервые открывается (точка, в которой воздух начинает поступать / тарелка поднимается)","Когда манометр достигает 15 psid","Когда обратный клапан закрывается"], re:"Перепад считывается в момент открытия воздуховпуска, наблюдаемого визуально по подъёму тарелки или поступлению воздуха. Источник: AWWA M14; процедура испытания PVB PNW-AWWA."},
  {id:263, q:"При испытании обратного клапана PVB, шланг высокой стороны подключается к какому испытательному крану?", opts:["Ни к какому; считывается на воздуховпуске","К испытательному крану № 1","К испытательному крану № 2","К обоим испытательным кранам сразу"], re:"Для испытания обратного клапана PVB шланг высокой стороны подключается к испытательному крану № 2 (ниже по потоку обратного клапана), затем открывают продувку, чтобы считать перепад обратного клапана. Источник: AWWA M14; процедура испытания PVB PNW-AWWA."},
  {id:264, q:"При испытании обратного клапана SVB, когда записывается показание манометра?", opts:["Когда давление подачи достигает 80 psi","Как только подключён шланг","После отказа воздуховпуска","Когда вода перестаёт сливаться из вент-клапана"], re:"Для SVB продувку открывают медленно, пока вода не перестанет сливаться из вент-клапана; это стабилизированное показание (1.0 psi или более) записывается для обратного клапана. Источник: AWWA M14; процедура испытания SVB Mid-West."},
  {id:265, q:"Воздуховпуск PVB открывается при 0.7 psi во время испытания. Каков результат?", opts:["Не проход, потому что точка открытия ниже минимума 1.0 psi","Проход, потому что он вообще открылся","Проход, если обратный клапан удерживает 1.0 psid","Показание отбрасывается"], re:"Точка открытия воздуховпуска ниже 1.0 psi не отвечает требованию; PVB не может пройти, пока не будет отремонтирован. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:266, q:"Какое преимущество имеет SVB ('брызгозащищённый') перед стандартным PVB?", opts:["Его можно устанавливать ниже уровня грунта","Он спроектирован сопротивляться проливу воды из воздуховпуска во время нормального пуска/наддува","Он обеспечивает защиту от противодавления","Он не нуждается в испытании"], re:"SVB сконструирован, чтобы минимизировать пролив воды через воздуховпуск во время наддува, который стандартный PVB может выпускать. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:267, q:"Для испытания воздуховпуска PVB, продувку высокой стороны открывают медленно, наблюдая за чем?", opts:["Водяным счётчиком клиента","Манометром давления подающей магистрали","Тарелкой воздуховпуска, чтобы поймать показание манометра в момент его открытия","Сбросом предохранительного клапана"], re:"Тестер медленно стравливает давление, наблюдая за воздуховпуском, и записывает показание манометра в момент открытия впуска. Источник: AWWA M14; процедура испытания PVB PNW-AWWA."},
  {id:268, q:"При испытании SVB, где должны удерживаться испытательный комплект и шланг?", opts:["Не менее чем на 5 футов выше SVB","Высота не имеет значения для SVB","Ниже SVB","На том же уровне (высоте), что и SVB"], re:"Испытательный комплект и шланг удерживают на том же уровне, что и SVB, чтобы высота не добавляла ошибку к показаниям. Источник: AWWA M14; процедура испытания SVB Mid-West."},
  {id:269, q:"При считывании перепада обратного клапана стрелка манометра продолжает дрейфовать вниз и не стабилизируется. Что это вероятнее всего означает?", opts:["Обратный клапан подтекает (не удерживает герметичность) или в линиях остаётся воздух","Обратный клапан уплотняется идеально","Давление подачи точно правильное","Предохранительный клапан прошёл"], re:"Стрелка, которая не удерживается и дрейфует вниз, указывает на подтекающий обратный клапан или остаточный воздух; проходящий обратный клапан удерживает стабильный перепад. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:270, q:"Дифференциальное показание описывается как 'кажущееся', если существует какое условие?", opts:["Манометр совершенно новый","Шланги всё ещё содержат захваченный воздух, влияющий на показание","Вода холодная","Узел является RP"], re:"Захваченный воздух делает показание 'кажущимся', а не истинным; линии необходимо полностью стравить, чтобы манометр показывал реальный перепад. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:271, q:"Когда продувку высокой стороны открывают во время испытания обратного клапана № 1 RP и стрелка поднимается, а затем удерживается устойчиво, что представляет удержанное значение?", opts:["Барометрическое давление","Расход через узел","Статический перепад, который удерживает первый обратный клапан","Скорость утечки запора ниже по потоку"], re:"Устойчивое удержанное значение - это статический перепад на первом обратном клапане; он должен быть 5.0 psid или более (и на 3 psid выше открытия сброса), чтобы пройти на RP. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:272, q:"Если во время испытания обратного клапана DC манометр показывает отрицательный или нулевой перепад, который нельзя поднять, что это указывает?", opts:["Обратный клапан удерживает герметичность","Предохранительный клапан открылся","Манометр вышел за диапазон","Обратный клапан не удерживает (он пропускает воду) или подключение неправильное"], re:"Перепад, который остаётся на нуле или ниже, сигнализирует, что обратный клапан не уплотняется (пропускает) или шланги подключены неправильно. Источник: поиск неисправностей AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:273, q:"Во время испытания открытия предохранительного клапана на RP, устойчиво ПАДАЮЩАЯ стрелка, за которой вы наблюдаете для точки открытия, что представляет?", opts:["Перепад зоны, уменьшающийся к точке открытия предохранительного клапана","Увеличение давления подачи","Скорость утечки обратного клапана № 2","Открытие воздуховпуска"], re:"По мере того как тестер стравливает высокую сторону, манометр показывает падение перепада зоны; показание фиксируется, когда предохранительный клапан открывается (около 2 psid). Источник: USC FCCCHR Field Test Procedures; AWWA M14."},
  {id:274, q:"Вода, непрерывно капающая из порта сброса RP при попытке считать перепад обратного клапана, что наиболее прямо говорит тестеру?", opts:["Манометр откалиброван","Зона пониженного давления вентилируется; первый обратный клапан или седло сброса могут пропускать","Второй обратный клапан идеален","Подача перекрыта"], re:"Сброс во время считывания обратного клапана показывает, что зона вентилируется (обычно засорённый первый обратный клапан или подтекающее седло сброса), что необходимо диагностировать перед действительным результатом. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:275, q:"При испытании воздуховпуска PVB, если стрелка падает до значения и воздуховпуск там видимо открывается, как это значение записывается?", opts:["Как давление в линии подачи","Как герметичность обратного клапана","Как точка открытия воздуховпуска","Как настройка предохранительного клапана"], re:"Значение манометра в момент открытия воздуховпуска записывается как точка открытия воздуховпуска и должно быть 1.0 psi или более. Источник: AWWA M14; процедура испытания PVB PNW-AWWA."},
  {id:276, q:"Почему тестер должен считать перепад при ПЕРВОМ признаке сброса предохранительного клапана, а не позже?", opts:["Потому что давление подачи возрастает после","Потому что манометр работает только кратко","Потому что клиент ждёт","Потому что точка открытия определяется моментом, когда клапан впервые сбрасывает"], re:"Точка открытия по определению - это перепад, при котором клапан впервые открывается; считывание позже занижает истинную точку открытия. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:277, q:"Манометр, который показывает от 2 до 3 psid перепада, даже когда оба шланга в одной точке, указывает на что?", opts:["Захваченный воздух, засорённый манометр или манометр вне калибровки","Правильно обнулённый манометр","Проходящий предохранительный клапан RP","Нормальное поведение, которое следует игнорировать"], re:"Ложное статическое смещение указывает на захваченный воздух или манометр, который нуждается в продувке или перекалибровке, прежде чем ему можно доверять. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:278, q:"Во время испытания RP, внезапный скачок стрелки к нулю при открытии сброса интерпретируется как что?", opts:["Неисправный манометр","Предохранительный клапан, вентилирующий зону (нормальное событие, отмечающее открытие)","Удвоение давления подачи","Уплотнение обратного клапана № 1"], re:"Когда сброс открывается, он сбрасывает зону, и перепад обрушивается к нулю; это ожидаемое поведение, используемое для отметки точки открытия. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:279, q:"Если обратный клапан DC удерживает значительно выше 1.0 psid, но стрелка беспорядочно скачет, что следует заподозрить в ПЕРВУЮ очередь?", opts:["Слишком затянутый запор ниже по потоку","Проходящий предохранительный клапан","Остаточный воздух в шлангах, требующий дополнительной продувки","Раскалиброванный воздуховпуск"], re:"Беспорядочное движение стрелки обычно означает, что в линиях остаётся воздух; продуйте снова и перечитайте перед оценкой обратного клапана. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:280, q:"Что говорит вам стабильный, удержанный перепад 1.0 psid или более на обратном клапане DC?", opts:["Обратный клапан подтекает","Подача перекрыта","Предохранительный клапан открылся","Обратный клапан удерживает герметичность и проходит эту часть испытания"], re:"Устойчивый перепад 1.0 psid или более означает, что обратный клапан плотно уплотняется и этот обратный клапан проходит. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:281, q:"При испытании предохранительного клапана, почему важно создать статическое условие (без потока) перед считыванием?", opts:["Чтобы перепад отражал сам узел, а не перепад давления, вызванный потоком","Чтобы манометр показывал 15 psid","Чтобы вода клиента включилась","Чтобы воздуховпуск открылся"], re:"Статическое условие гарантирует, что измеренный перепад исходит от пружин/сёдел узла, а не от потока, что даёт действительное показание точки открытия. Источник: USC FCCCHR Field Test Procedures; AWWA M14."},
  {id:282, q:"Во время испытания обратного клапана SVB, вода, которая НЕ перестаёт сливаться из вент-клапана при продувке, указывает на что?", opts:["Обратный клапан удерживает идеально","Обратный клапан подтекает/пропускает и может не отвечать критерию 1.0 psid","Манометр вышел за диапазон","Воздуховпуск заклинило в закрытом положении"], re:"Если слив не прекращается, обратный клапан пропускает воду и, вероятно, не проходит; герметичный обратный клапан позволяет венту прекратить слив при 1.0 psi или более. Источник: AWWA M14; процедура испытания SVB Mid-West."},
  {id:283, q:"Показание, снятое с манометром, удерживаемым значительно ВЫШЕ узла, по сравнению с показанием на той же высоте, как будет затронуто?", opts:["Никак","Удвоением истинного значения","Ошибкой высоты (напора), которая смещает перепад","Всегда становясь отрицательным"], re:"Удержание манометра вне высоты узла добавляет ошибку столба воды к перепаду, поэтому комплект необходимо держать на одном уровне с узлом. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:284, q:"Если давление в линии подачи, считанное на испытательном кране № 1, необычно низкое или колеблется, что должен сделать тестер?", opts:["Записать любое значение и пропустить узел","Полностью игнорировать давление подачи","Увеличить диапазон манометра до 150 psid","Отметить это и устранить условие подачи, поскольку нестабильная подача может искажать дифференциальные показания"], re:"Нестабильное или ненормальное давление подачи может искажать испытание, поэтому условие отмечают и устраняют перед тем, как доверять дифференциальным результатам. Источник: AWWA M14; руководство к протоколу испытания штата."},
  {id:285, q:"На RP, если обратный клапан № 1 удерживает 6 psid, но предохранительный клапан открывается при 4 psid, что означает разрыв в 2 psid?", opts:["Недостаточный буфер, потому что буфер должен быть не менее 3 psid","Здоровый буфер значительно выше минимума","Что узел является SVB","Что манометр сломан"], re:"Хотя оба значения превышают свои собственные минимумы, буфер в 2 psid ниже требуемой разницы в 3 psid между первым обратным клапаном и открытием сброса, поэтому этот пункт не проходит. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:286, q:"Какой набор минимальных значений прохождения верен для узла RP?", opts:["Предохранительный клапан открывается при >= 1.0 psid; каждый обратный клапан удерживает >= 1.0 psid","Предохранительный клапан открывается при >= 2.0 psid; обратный клапан № 1 удерживает >= 5.0 psid и >= 3 psid выше открытия сброса","Предохранительный клапан открывается при >= 5.0 psid; обратный клапан № 1 удерживает >= 2.0 psid","Воздуховпуск открывается при >= 1.0 psi; обратный клапан удерживает >= 1.0 psid"], re:"RP проходит, когда сброс открывается при 2.0 psid или более и первый обратный клапан удерживает 5.0 psid или более с буфером не менее 3 psid над открытием сброса. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:287, q:"Какой набор минимальных значений прохождения верен для узла DC?", opts:["Воздуховпуск открывается при >= 1.0 psi","Предохранительный клапан открывается при >= 2.0 psid","Каждый обратный клапан удерживает >= 1.0 psid в направлении потока","Обратный клапан № 1 удерживает >= 5.0 psid"], re:"DC проходит, когда каждый обратный клапан независимо удерживает 1.0 psid или более в направлении потока. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:288, q:"Какой набор минимальных значений прохождения верен для узла PVB?", opts:["Воздуховпуск открывается при >= 2.0 psi; без испытания обратного клапана","Предохранительный клапан открывается при >= 2.0 psid; обратный клапан удерживает >= 5.0 psid","Каждый из двух обратных клапанов удерживает >= 1.0 psid","Воздуховпуск открывается при >= 1.0 psi; обратный клапан удерживает >= 1.0 psid"], re:"PVB проходит, когда воздуховпуск открывается при 1.0 psi или более и обратный клапан удерживает 1.0 psid или более. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:289, q:"Какой набор минимальных значений прохождения верен для узла SVB?", opts:["Обратный клапан удерживает >= 1.0 psid; воздуховпуск открывается при >= 1.0 psi и открывается полностью","Предохранительный клапан открывается при >= 2.0 psid","Два обратных клапана каждый удерживают >= 1.0 psid","Воздуховпуск открывается при >= 5.0 psi"], re:"SVB проходит, когда обратный клапан удерживает 1.0 psid или более и воздуховпуск открывается при 1.0 psi или более и открывается полностью. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:290, q:"Какая информация ОБЯЗАТЕЛЬНА в протоколе испытания узла предотвращения обратного потока?", opts:["Любимый цвет клиента","Серийный номер, марка, модель и размер узла","Счёт за домашний телефон тестера","Марка водонагревателя клиента"], re:"Протокол должен идентифицировать узел по марке, модели, размеру и серийному номеру (который должен совпадать с клеймом на устройстве). Источник: AWWA M14; формы протоколов штатов (например, NY DOH, Denver Water)."},
  {id:291, q:"Почему серийный номер, записанный в протоколе, должен совпадать с выбитым на узле?", opts:["Только для украшения","Чтобы установить давление подачи","Чтобы доказать, что был фактически испытан правильный, установленный узел","Чтобы откалибровать манометр"], re:"Совпадающие серийные номера документируют, что был испытан конкретный установленный узел, предотвращая мошенничество или путаницу. Источник: AWWA M14; инструкции к протоколам программ по перекрёстным соединениям штатов."},
  {id:292, q:"Помимо даты испытания, какая дата обычно требуется в протоколе относительно манометра тестера?", opts:["Дата манометра не требуется","Дата цены покупки манометра","Дата чистки манометра","Дата калибровки манометра"], re:"Дата калибровки манометра записывается, чтобы орган власти мог подтвердить, что манометр был в пределах своей годовой калибровки при использовании. Источник: AWWA M14; формы протоколов штатов (например, Denver Water)."},
  {id:293, q:"Что идентифицирует лицо, выполнившее испытание, в протоколе?", opts:["Имя сертифицированного тестера и номер сертификации/лицензии","Только имя","Только подпись клиента","Логотип производителя"], re:"Имя сертифицированного тестера и номер сертификации (лицензии) должны присутствовать, чтобы орган власти мог убедиться, что тестер квалифицирован. Источник: AWWA M14; формы протоколов штатов."},
  {id:294, q:"Если узел НЕ ПРОХОДИТ и затем ремонтируется, что протокол также должен документировать?", opts:["Ничего больше не нужно","Выполненный ремонт, использованные детали и пройденное повторное испытание после ремонта","Только время суток","Пароль учётной записи клиента"], re:"После ремонта протокол документирует, что было отремонтировано/заменено, и результаты пройденного повторного испытания. Источник: AWWA M14; формы протоколов штатов (раздел ремонта)."},
  {id:295, q:"Обратный клапан № 1 DC показывает точно 1.0 psid. Как это записывается?", opts:["Как непрохождение, потому что он должен превышать 1.0 psid","Как не требующий записи","Как прохождение, потому что он отвечает минимуму 1.0 psid (>= 1.0 psid)","Как показание предохранительного клапана"], re:"Критерий - 1.0 psid или более, поэтому точно 1.0 psid отвечает минимуму и обратный клапан проходит. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:296, q:"При записи результата RP, какие показания вносятся в протокол?", opts:["Только давление подачи","Только значение воздуховпуска","Только значение предохранительного клапана","Перепад обратного клапана № 1, результат обратного клапана № 2 и значение открытия предохранительного клапана"], re:"Протокол RP записывает перепад первого обратного клапана, результат второго обратного клапана и перепад открытия предохранительного клапана, плюс прохождение/непрохождение. Источник: AWWA M14; образцы форм полевых испытаний (USC FCCCHR)."},
  {id:297, q:"Для PVB, какие два результата записываются в протоколе?", opts:["Значение открытия воздуховпуска и перепад обратного клапана","Два перепада обратного клапана","Открытие предохранительного клапана и обратный клапан","Только давление подачи"], re:"Протокол PVB записывает точку открытия воздуховпуска и перепад обратного клапана, с прохождением/непрохождением. Источник: AWWA M14; процедура испытания PVB PNW-AWWA / поля протокола."},
  {id:298, q:"Каково правильное решение, если любое единичное требуемое показание на узле падает ниже своего минимума?", opts:["Записать узел как прошедший в любом случае","Записать узел как НЕ ПРОШЕДШИЙ, пока он не будет отремонтирован и повторно испытан с прохождением","Усреднить все показания для решения","Оставить протокол пустым"], re:"Любое показание ниже своего требуемого минимума означает, что узел не проходит и должен быть отремонтирован и повторно испытан, прежде чем его можно записать как прошедший. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:299, q:"Какое состояние запорных клапанов обычно отмечается в протоколе?", opts:["Только их цвет","Их вес","Работоспособны/удерживают ли запоры № 1 и № 2 (например, герметичны или подтекают)","Крутящий момент, использованный для их открытия"], re:"Протоколы отмечают состояние запорных клапанов (например, удерживают герметичность или подтекают), поскольку удерживающий запор влияет на действительность испытания и изоляцию. Источник: AWWA M14; формы протоколов штатов."},
  {id:300, q:"После завершения испытания, что должен сделать тестер перед тем, как покинуть объект?", opts:["Оставить запор ниже по потоку закрытым, а испытательные краны открытыми","Слить водонагреватель клиента","Снять узел с линии","Восстановить узел в эксплуатацию (запоры и испытательные краны возвращены в их нормальные рабочие положения)"], re:"Тестер возвращает узел в нормальную эксплуатацию: испытательные краны закрыты/закрыты колпачками, а запорные клапаны восстановлены в их надлежащие рабочие положения. Источник: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:301, q:"Столб воды высотой примерно сколько футов создаёт давление 1 psi у своего основания?", opts:["2.31 ft","1.0 ft","0.433 ft","14.7 ft"], re:"Столб воды на 1 psi имеет высоту 2.31 ft (1 / 0.433). Это преобразование давления в напор является фундаментом гидравлики, используемым во всём AWWA M14 и в расчётах насоса/высоты."},
  {id:302, q:"Какое давление создаёт у основания каждый фут вертикального столба воды?", opts:["1.0 psi","0.433 psi","2.31 psi","4.33 psi"], re:"Вода весит 62.4 lb/ft3, поэтому столб 1 ft x 1 in2 весит около 0.433 lb, то есть 0.433 psi на каждый фут напора (величина, обратная 2.31 ft/psi)."},
  {id:303, q:"Один кубический фут воды весит приблизительно:", opts:["8.34 lb","100 lb","62.4 lb","2.31 lb"], re:"Пресная вода весит около 62.4 lb/ft3 (и 8.34 lb на галлон). Этот удельный вес лежит в основе преобразований напора 0.433 psi/ft и 2.31 ft/psi."},
  {id:304, q:"Подъём выхода узла на 23 фута выше входа добавляет примерно какое статическое давление, которое подача должна преодолеть?", opts:["Около 5 psi","Около 50 psi","Около 23 psi","Около 10 psi"], re:"Потеря на высоту = высота x 0.433 psi/ft. 23 ft x 0.433 = около 10 psi. Стандартное гидравлическое преобразование напора (гидравлика AWWA M14)."},
  {id:305, q:"Статическое давление воды — это давление, измеренное, когда вода:", opts:["Не течёт (в покое)","Течёт при максимальном спросе","Закачивается вверх по склону","Сбрасывается из предохранительного клапана"], re:"Статическое давление — это давление в линии при отсутствии расхода. Как только вода движется, трение и скорость снижают его до более низкого динамического (остаточного) давления. Базовая гидравлика, AWWA M14."},
  {id:306, q:"Когда вода начинает течь по трубе, давление ниже по потоку по сравнению со статическим давлением обычно:", opts:["Остаётся точно таким же","Снижается из-за потерь на трение","Увеличивается","Становится атмосферным"], re:"Расход создаёт трение и скоростной напор, поэтому динамическое (остаточное) давление ниже статического. Чем быстрее поток, тем больше падение. Гидравлика AWWA M14."},
  {id:307, q:"Потери на трение в данной трубе возрастают наиболее резко, когда:", opts:["Вода перестаёт течь","Труба укорачивается","Расход (скорость) увеличивается","Давление снимается"], re:"Потери на трение растут примерно пропорционально квадрату скорости, поэтому больший расход через фиксированную трубу вызывает гораздо большее падение давления. Поэтому увеличение диаметра снижает потери напора. AWWA M14."},
  {id:308, q:"По мере того как вода ускоряется в суженном проходе, её скорость растёт, а статическое давление:", opts:["Растёт","Удваивается","Остаётся постоянным","Падает"], re:"Согласно принципу энергии/Бернулли, более быстро движущаяся вода обменивает энергию давления на энергию скорости, поэтому статическое давление падает там, где скорость наибольшая. Гидравлика AWWA M14."},
  {id:309, q:"Падение давления на первом обратном клапане узла RP при высоком расходе в основном является результатом:", opts:["Нагрузки пружины плюс трения/скорости через клапан","Теплового расширения","Погрешности манометра","Атмосферного выпуска"], re:"Вода должна толкнуть нагруженный клапан, чтобы открыть его и пройти мимо; нагрузка пружины плюс трение потока создают перепад. Если это падение превышает уставку сброса, сброс может подтекать. AWWA M14 / USC FCCCHR."},
  {id:310, q:"Узел, который недоразмерен для спроса здания, скорее всего вызовет:", opts:["Избыточное статическое давление","Чрезмерные потери напора и низкое давление ниже по потоку при пиковом расходе","Полное отсутствие расхода во все времена","Более высокую точность манометра"], re:"Слишком малый узел вызывает высокую скорость и большие потери на трение при пиковом спросе, обедняя приборы и иногда поднимая предохранительный клапан RP. Подбирайте по спросу согласно AWWA M14."},
  {id:311, q:"Перепад давления на обратном клапане определяется как:", opts:["Давление подачи плюс давление зоны","Только атмосферное давление","Разница между давлением выше по потоку и давлением ниже по потоку на этом клапане","Давление на выходе предохранительного клапана"], re:"Перепад давления — это давление выше по потоку минус давление ниже по потоку на клапане. Манометр испытательного комплекта считывает его напрямую при подключении к испытательным кранам. AWWA M14 / USC FCCCHR."},
  {id:312, q:"Нормальное давление муниципальной водопроводной подачи, поставляемое в большинство зданий, обычно находится в диапазоне:", opts:["от 5 до 15 psi","Более 300 psi","от 150 до 200 psi","от 40 до 80 psi"], re:"Системы общественного водоснабжения обычно подают примерно 40-80 psi; PRV добавляется там, где уличное давление выше. Узлы должны герметизировать в этом диапазоне рабочего давления. AWWA M14."},
  {id:313, q:"Обратный поток под противодавлением возникает, когда давление ниже по потоку становится:", opts:["Выше давления подачи","Ниже давления подачи","Равным атмосферному","Точно нулевым"], re:"Противодавление — это давление ниже по потоку, превышающее давление подачи (от насосов, котлов, высоты, теплового расширения), которое может толкнуть воду обратно к магистрали. AWWA M14."},
  {id:314, q:"Стандартное атмосферное давление на уровне моря составляет приблизительно:", opts:["7.0 psi","14.7 psi","29.9 psi","50.0 psi"], re:"Стандартное атмосферное давление на уровне моря составляет около 14.7 psia (1 атмосфера). Обратное сифонирование и эффекты вакуума отсчитываются относительно атмосферного давления. — основы гидравлики / AWWA M14."},
  {id:315, q:"Зона пониженного давления между двумя обратными клапанами узла RP обычно поддерживается как, относительно подачи?", opts:["При более высоком давлении, чем подача","Точно равном подаче","По меньшей мере примерно на 2 psi ниже подачи","При полном атмосферном давлении во все времена"], re:"Первый обратный клапан поддерживает центральную зону по меньшей мере примерно на 2 psi ниже подачи; если этот запас теряется, предохранительный клапан открывается, чтобы удержать зону ниже подачи. USC FCCCHR / AWWA M14."},
  {id:316, q:"Манометр, который показывает 'psig', измеряет давление относительно:", opts:["Абсолютного вакуума","Уставки предохранительного клапана","Давления подачи","Атмосферного давления"], re:"Манометрическое давление (psig) отсчитывается относительно местного атмосферного давления; показание 0 psig означает атмосферное. Показания перепада обратного потока являются манометрическими. Общая гидравлика."},
  {id:317, q:"Скорость в трубе при заданном расходе увеличивается, когда диаметр трубы:", opts:["Уменьшается","Увеличивается","Остаётся неизменным","Изолируется"], re:"При фиксированном расходе меньшее поперечное сечение вызывает более высокую скорость (неразрывность). Более высокая скорость повышает потери на трение и может увеличить перепад на клапане. Гидравлика AWWA M14."},
  {id:318, q:"На узле RP непрерывный сброс из предохранительного клапана при системе в покое (нет расхода) чаще всего указывает на:", opts:["Идеально герметичный первый обратный клапан","Загрязнённый первый обратный клапан, который не закрывается плотно","Нормальную работу","Завышенный по размеру узел"], re:"В статике без расхода непрерывный сброс означает, что первый обратный клапан подтекает и не может удержать зону ниже подачи, поэтому сброс открывается. Первый клапан нуждается в обслуживании. Поиск неисправностей USC FCCCHR / AWWA M14."},
  {id:319, q:"Самой распространённой причиной загрязнённого обратного клапана, который не садится, является:", opts:["Правильное натяжение пружины","Откалиброванный манометр","Мусор, осадок или накипь, застрявшие на седле или диске","Правильная высота установки"], re:"Песок, трубная накипь и мусор, застрявшие между диском и седлом, являются основной причиной клапана, который не закрывается плотно; решение — очистить или заменить поражённые детали. AWWA M14 / руководство производителя."},
  {id:320, q:"Непрерывный сброс, который появляется только когда сторона ниже по потоку находится под противодавлением, указывает на загрязнённый:", opts:["Первый обратный клапан","Входной запорный клапан","Игольчатый клапан манометра","Второй обратный клапан"], re:"Если второй клапан загрязняется и противодавление толкает воду обратно в зону, давление зоны растёт, сброс открывается и сброс продолжается под этим противодавлением. Поиск неисправностей AWWA M14."},
  {id:321, q:"Прерывистый сброс, который начинается и прекращается по мере того, как давление подачи растёт и падает, обычно означает, что узел:", opts:["Правильно реагирует на колеблющееся давление подачи","Выходит из строя и нуждается в замене","Имеет треснувший корпус","Считывает неисправный манометр"], re:"Когда входное давление кратковременно падает, сброс выпускает, чтобы удержать зону ниже подачи, затем снова садится, когда давление восстанавливается. Этот докучливый сброс следует за колебаниями подачи. AWWA M14 / USC FCCCHR."},
  {id:322, q:"В закрытой системе ниже по потоку предохранительный клапан RP, который капает после длительного использования горячей воды или за ночь, обычно вызван:", opts:["Ослабленным испытательным краном","Тепловым расширением, повышающим давление ниже по потоку","Завышенным по размеру первым обратным клапаном","Изменениями атмосферного давления"], re:"Нагретая вода в замкнутом контуре расширяется и повышает давление ниже по потоку, толкая обратно через второй клапан и поднимая сброс. Правильно заряженный расширительный бак обычно устраняет это. AWWA M14."},
  {id:323, q:"Ударная волна гидроудара, достигающая узла RP, может заставить предохранительный клапан:", opts:["Герметизировать плотнее навсегда","Необратимо изменить направление потока","Кратковременно открыться и сбросить воду","Самокалиброваться"], re:"Внезапный скачок давления может кратковременно нарушить перепад зоны и поднять сброс; для гашения применяют гасители или демпфирующий клапан. AWWA M14 / полевой поиск неисправностей."},
  {id:324, q:"Изношенные или затвердевшие резиновые диски обратных клапанов обычно выходят из строя потому, что:", opts:["Становятся более гибкими со временем","Снижают потери на трение","Становятся больше и герметизируют лучше","Теряют упругость и больше не герметизируют по седлу"], re:"Резина приобретает остаточную деформацию, твердеет, трескается или рвётся с возрастом и от воздействия хлора, поэтому диск не может прилегать к седлу и клапан подтекает. Замените резину. AWWA M14 / производитель."},
  {id:325, q:"Предохранительный клапан, который вообще не открывается (нет сброса, даже когда должен), опасен, потому что может:", opts:["Маскировать условие обратного потока и допустить загрязнение зоны","Экономить воду","Улучшать точность манометра","Повышать давление подачи"], re:"Заклинивший в закрытом положении сброс сводит на нет последнюю линию защиты RP; зона может быть загрязнена без предупреждения. Оба клапана и сброс должны проверяться при каждом испытании. USC FCCCHR / AWWA M14."},
  {id:326, q:"Нарастание минеральной накипи на седле обратного клапана со временем, скорее всего:", opts:["Не имеет эффекта","Помешает диску полностью сесть и вызовет утечку","Увеличит давление открытия сброса","Затянет уплотнение"], re:"Накипь от жёсткой воды на седле удерживает диск над седлом, создавая путь утечки; удаление накипи или замена седла/диска восстанавливает уплотнение. Обслуживание AWWA M14 / производитель."},
  {id:327, q:"Морозная погода чаще всего повреждает надземный узел путём:", opts:["Улучшения уплотнений","Калибровки манометра","Растрескивания корпуса, крышки или предохранительного клапана от расширения льда","Снижения уставки сброса"], re:"Вода расширяется при замерзании и может расколоть литой корпус, крышку или корпус сброса. Требуется защита от мороза или слив на зиму. Руководство по установке AWWA M14."},
  {id:328, q:"Сломанная или усталостная пружина обратного клапана обычно проявляется на испытании как:", opts:["Перепад на клапане выше нормы","Отсутствие влияния на показание","Предохранительный клапан, который открывается позже","Клапан, который не удерживает минимальный перепад"], re:"Слабая или сломанная пружина не может прижать диск к седлу, поэтому клапан не удерживает свой минимальный перепад удержания на испытании. Замените пружину/модуль. AWWA M14 / производитель."},
  {id:329, q:"Узел, установленный со стрелкой потока, направленной в неправильную сторону:", opts:["Не сможет защитить, потому что клапаны обращены в неправильном направлении","Будет работать нормально","Покажет более высокий перепад","Будет открывать сброс реже"], re:"Установленные наоборот, клапаны противодействуют предполагаемому потоку и узел не может функционировать; ориентация должна совпадать со стрелкой потока на корпусе. Установка AWWA M14."},
  {id:330, q:"Мусор, скорее всего, загрязнит узел сразу после:", opts:["Длительного периода без использования","Близких работ на магистрали, ремонтов или промывки, которые поднимают осадок","Калибровки манометра","Покраски здания"], re:"Прорывы магистрали, ремонты, промывка гидрантов и новое строительство срывают накипь и песок, которые движутся ниже по потоку и оседают в клапанах и сбросе. Ожидайте загрязнения после возмущения. AWWA M14."},
  {id:331, q:"Прокол или разрыв в резиновой мембране дифференциального предохранительного клапана обычно заставит сброс:", opts:["Оставаться герметичным постоянно","Открываться при более высоком давлении","Подтекать или сбрасывать непрерывно, потому что он не может удержать свой перепад","Не иметь никаких симптомов"], re:"Мембрана сброса воспринимает перепад подача-зона; разорванная мембрана не может его удержать, поэтому сброс подтекает. Замените модуль/мембрану сброса. AWWA M14 / производитель."},
  {id:332, q:"Если предохранительный клапан RP сбрасывает только в течение нескольких минут пикового утреннего спроса, наиболее вероятное объяснение:", opts:["Треснувший корпус узла","Слишком затянутый входной запорный клапан","Замёрзший предохранительный клапан","Высокий расход, опускающий перепад первого клапана ниже уставки сброса (часто недоразмер)"], re:"При пиковом расходе падение давления на первом клапане может опуститься ниже перепада сброса и сброс выпускает; правильный подбор размера или больший узел решает это. USC FCCCHR / AWWA M14."},
  {id:333, q:"Оба клапана загрязнены и подтекают на RP высокой опасности — это наиболее серьёзно, потому что:", opts:["Устраняет барьер против загрязнения, хотя сброс всё ещё выпускает зону","Только тратит немного воды","Улучшает защиту","Не имеет последствий"], re:"При обоих подтекающих клапанах узел не может блокировать обратный поток; сброс, выпускающий зону в атмосферу, является оставшейся защитой, но узел должен быть отремонтирован немедленно. AWWA M14."},
  {id:334, q:"Импульсная линия или проход предохранительного клапана, забитый мусором, скорее всего заставит сброс:", opts:["Реагировать быстрее","Реагировать медленно или не открываться/закрываться при надлежащем перепаде","Улучшить точность","Снизить давление подачи"], re:"Сброс реагирует на давление, подаваемое через его импульсный проход; если этот проход загрязнён, сброс не может воспринять истинный перепад и работает неправильно. Очистите проход. Поиск неисправностей AWWA M14."},
  {id:335, q:"При полевом испытании RP первый обратный клапан признаётся удовлетворительным, когда удерживает перепад не менее:", opts:["1.0 psid","2.0 psid","5.0 psid","10.0 psid"], re:"Первый клапан RP должен удерживать не менее 5.0 psid (и сброс не должен быть открыт), чтобы сохранять безопасный запас выше точки открытия сброса. Критерии испытания USC FCCCHR / AWWA M14."},
  {id:336, q:"Каждый обратный клапан узла двойного обратного клапана (DCVA) должен удерживать перепад не менее:", opts:["0.0 psid","2.0 psid","5.0 psid","1.0 psid"], re:"На DCVA каждый клапан должен удерживать не менее 1.0 psid в направлении потока; если он удерживает 1.0 psid вперёд, считается, что он герметичен против обратного потока. AWWA M14 / USC FCCCHR."},
  {id:337, q:"Первый обратный клапан, который удерживает только 3.5 psid на испытании RP, следует записать как:", opts:["Не прошедший, потому что он ниже минимума 5.0 psid","Прошедший","Прошедший, если сброс закрыт","Не поддающийся испытанию"], re:"Ниже минимума 5.0 psid первый клапан не проходит, даже если нет видимой утечки; он больше не сохраняет требуемый запас выше открытия сброса. Отремонтируйте и испытайте повторно. USC FCCCHR / AWWA M14."},
  {id:338, q:"Во время испытания обратного клапана вода продолжает вытекать из дренажной/смотровой линии и манометр не стабилизируется. Это указывает, что клапан:", opts:["Удерживает плотно","Подтекает (не закрывается плотно)","Слишком затянут","Заморожен открытым по конструкции"], re:"Клапан записывается как герметичный только когда расход прекращается и перепад стабилизируется. Продолжающийся расход означает, что диск не герметизирует — подтекающий клапан. Метод испытания AWWA M14."},
  {id:339, q:"Предположение, лежащее в основе испытания клапана только в направлении потока, состоит в том, что если он удерживает минимальный перепад вперёд, он:", opts:["Будет подтекать в обратном направлении","Всё равно потребует замены","Удержит плотно в обратном (без расхода) направлении","Откроет предохранительный клапан"], re:"Логика испытания AWWA M14 предполагает, что клапан, удерживающий свой минимальный перепад в направлении потока, также герметизирует против обратного потока — условие, которое важно для защиты от обратного потока. AWWA M14."},
  {id:340, q:"Захваченный воздух в шлангах испытательного комплекта во время испытания клапана, скорее всего, сделает показание перепада:", opts:["Ложно низким","Отрицательным","Точно правильным","Ложно высоким"], re:"Воздух в шлангах заставляет манометр показывать более высокий перепад, чем реально существует, что может скрыть подтекающий клапан (ложное прохождение). Стравите весь воздух перед считыванием. Руководство по испытательному комплекту BAVCO / AWWA M14."},
  {id:341, q:"Чтобы определить, какой клапан подтекает на DCVA, испытатель считывает каждый клапан отдельно, используя:", opts:["Соответствующие испытательные краны и дифференциальный манометр для каждого клапана","Только входной запорный клапан","Сброс предохранительного клапана","Манометр давления только со стороны здания"], re:"Четыре испытательных крана позволяют испытателю считывать клапан 1 и клапан 2 независимо дифференциальным манометром, выявляя, какой клапан не проходит свой минимум 1.0 psid. AWWA M14 / USC FCCCHR."},
  {id:342, q:"Обратный клапан, который проходит испытание один день, но затем выходит из строя прерывисто, скорее всего имеет:", opts:["Постоянно разорванный диск","Прерывистый мусор, который оседает и счищается на седле","Замёрзший корпус","Только неоткалиброванный манометр"], re:"Свободный песок, который иногда падает на седло, а иногда смывается, создаёт прерывистую утечку; диск и седло следует осмотреть и очистить. Поиск неисправностей AWWA M14."},
  {id:343, q:"На RP, если первый клапан не проходит, но второй клапан герметичен, узел:", opts:["Всё равно полностью проходит","Не требует действий","Не проходит и должен быть отремонтирован и испытан повторно","Должен иметь снятый сброс"], re:"Любой неисправный компонент проваливает узел. Неисправный первый клапан (даже с хорошим вторым клапаном) должен быть отремонтирован, а узел испытан повторно перед возвратом в эксплуатацию. USC FCCCHR / AWWA M14."},
  {id:344, q:"Качающийся или шарнирный диск клапана, который больше не качается свободно (заедает на своей оси), скорее всего:", opts:["Будет герметизировать идеально","Не будет иметь влияния на испытание","Увеличит давление подачи","Застрянет частично открытым или закрытым и не сядет должным образом"], re:"Диск, который заедает на корродированном или загрязнённом шарнире/оси, не может полностью сесть или открыться, вызывая утечку или ограничение. Освободите, очистите или замените подвижные части. AWWA M14 / производитель."},
  {id:345, q:"При записи испытания клапана записываемое значение — это перепад в момент, когда:", opts:["Расход прекращается и манометр стабилизируется (клапан закрыт плотно)","Расход впервые начинается","Сброс открывается","Запорный клапан закрывается"], re:"Записываемое число — это стабилизированный перепад после того, как расход через смотровую линию прекращается, что означает, что клапан закрылся плотно. Метод отчётности AWWA M14."},
  {id:346, q:"Диск клапана, который исправен, но сидит на изъязвлённом или корродированном седле, будет:", opts:["Всё равно удерживать плотно","Подтекать по повреждённой поверхности седла","Повышать уставку сброса","Останавливать весь расход"], re:"Даже исправный диск не может герметизировать по изъязвлённому, поцарапанному или корродированному седлу; седло должно быть очищено, восстановлено или заменено. Руководство по ремонту AWWA M14 / производитель."},
  {id:347, q:"Если оба клапана DCVA показывают выше 1.0 psid и удерживают стабильно, испытатель записывает узел как:", opts:["Не прошедший","Требующий замены сброса","Прошедший","Не поддающийся испытанию"], re:"Оба клапана, удерживающие минимум 1.0 psid или выше со стабильными показаниями, — это результат прохождения DCVA. Критерии AWWA M14 / USC FCCCHR."},
  {id:348, q:"Подтекающий первый клапан на RP иногда можно подтвердить, потому что предохранительный клапан будет:", opts:["Оставаться сухим","Закрывать вход","Показывать более высокое давление","Сбрасывать в статике без расхода, пока клапан не обслужен"], re:"Первый клапан, который подтекает в покое, позволяет зоне подняться к подаче, поэтому сброс непрерывно сбрасывает в статическом состоянии — характерный признак загрязнения первого клапана. USC FCCCHR / AWWA M14."},
  {id:349, q:"Прежде чем забраковать подтекающий клапан, испытатель должен сначала убедиться, что утечка не вызвана:", opts:["Воздухом в шлангах или не полностью севшим испытательным краном/игольчатым клапаном","Правильной калибровкой манометра","Занятостью здания","Правильным направлением потока"], re:"Захваченный воздух или подтекающее испытательное соединение могут имитировать подтекающий клапан (ложный отказ или странное показание); убедитесь, что комплект стравлен и затянут, прежде чем судить об узле. BAVCO / AWWA M14."},
  {id:350, q:"Обратные клапаны в узле RP или DC подпружинены, чтобы они:", opts:["Открывались только при обратном потоке","Закрывались положительно против обратного потока даже при низком перепаде","Оставались открытыми во все времена","Постоянно дросселировали расход"], re:"Подпружинивание прижимает диск к седлу, поэтому клапан закрывается против обратного потока ещё до того, как нарастёт противодавление, в отличие от ненагруженного качающегося клапана. AWWA M14 / USC FCCCHR."},
  {id:351, q:"Клапан, который удерживает гораздо более высокий перепад, чем нормально (очень тугой), может указывать на:", opts:["Ничего плохого, всегда идеально","Разорванную мембрану","Засорённый проход или заедающий/перегруженный диск, добавляющий ограничение","Севшую батарею манометра"], re:"Аномально высокий перепад может означать ограничение мусором или заедающий диск, добавляющий потери напора; осмотрите на предмет загрязнения или механического заедания, даже если он 'удерживает'. Поиск неисправностей AWWA M14."},
  {id:352, q:"При полевом испытании RP предохранительный клапан должен начать открываться (точка открытия сброса) при перепаде не менее:", opts:["0.5 psid","1.0 psid","5.0 psid","2.0 psid"], re:"Дифференциальный предохранительный клапан RP должен открываться при не менее 2.0 psid между подачей и зоной. Ниже 2.0 psid открытия он не проходит. Критерии испытания USC FCCCHR / AWWA M14."},
  {id:353, q:"Предохранительный клапан, записанный как открывающийся при 1.4 psid на испытании RP, следует отметить:", opts:["Не прошедшим, потому что он ниже минимума 2.0 psid","Прошедшим","Прошедшим, если клапаны исправны","Неприменимым"], re:"Точка открытия ниже 2.0 psid не проходит; сброс должен открываться при 2.0 psid или выше, чтобы выпустить зону прежде, чем она сможет подняться до давления подачи. USC FCCCHR / AWWA M14."},
  {id:354, q:"Предохранительный клапан всегда должен открываться при перепаде, который каким образом соотносится со значением удержания первого клапана?", opts:["Выше значения клапана","Ниже значения клапана, оставляя запас безопасности","Точно равным ему","Отрицательным"], re:"Точка открытия сброса (>=2.0 psid) должна оставаться ниже удержания первого клапана (>=5.0 psid), чтобы клапан удерживал зону безопасно выше уставки сброса. Требование запаса USC FCCCHR / AWWA M14."},
  {id:355, q:"Чтобы доказать, что сброс на сбрасывающем RP сам работает, испытатель может создать расход через испытательный кран № 4; если сброс прекращается, это показывает, что сброс:", opts:["Сломан","Открылся слишком поздно","Закрылся и функционирует — утечка была из загрязнённого клапана","Имеет разорванную мембрану"], re:"При обоих клапанах, удерживаемых открытыми расходом через № 4, сброс, который затем садится, доказывает, что сброс исправен, а предшествующий сброс был из загрязнённого клапана. Если он всё ещё подтекает, подозревайте сброс или его импульсный проход. AWWA M14 / Backflow Prevention Journal."},
  {id:356, q:"Если сброс RP всё ещё сбрасывает, пока вода вытекает из испытательного крана № 4 (оба клапана удерживаются открытыми), неисправность, скорее всего:", opts:["Первый обратный клапан","Второй обратный клапан","Входной запорный клапан","Мусор в предохранительном клапане или его импульсной линии"], re:"При обоих клапанах, принудительно открытых расходом через № 4, клапаны исключены из уравнения; продолжающаяся утечка сброса указывает на мусор в сбросе или его импульсном проходе. AWWA M14 / Backflow Prevention Journal."},
  {id:357, q:"Предохранительный клапан, который правильно открывается, но затем не садится обратно (остаётся открытым), скорее всего:", opts:["Загрязнён или имеет изношенную резину на седле","Совершенно исправен","Настроен слишком высоко","Заморожен в закрытом положении"], re:"Сброс, который открывается, но не может сесть обратно, обычно имеет мусор или изношенную/разорванную резину на седле сброса; очистите или замените модуль сброса. Руководство по ремонту AWWA M14 / производитель."},
  {id:358, q:"Дифференциальный предохранительный клапан RP воспринимает разницу между давлением подачи и:", opts:["Атмосферным давлением снаружи","Давлением в зоне между двумя обратными клапанами","Давлением здания ниже по потоку","Напряжением батареи манометра"], re:"Сброс непрерывно сравнивает давление подачи с давлением центральной зоны; когда зона поднимается примерно до 2 psi от подачи, сброс открывается. USC FCCCHR / AWWA M14."},
  {id:359, q:"При испытании PVB (вакуумный прерыватель давления) воздухоприёмный клапан должен открываться при перепаде не менее:", opts:["5.0 psid","2.0 psid","1.0 psid","0.0 psid"], re:"Воздухоприёмный клапан PVB должен открываться при 1.0 psid или более (и клапан должен быть нагружен по меньшей мере до 1.0 psid). Критерии PVB USC FCCCHR / AWWA M14."},
  {id:360, q:"Предохранительный клапан, который кратко 'плюётся', а затем садится обратно во время падения давления подачи:", opts:["Выходит из строя и должен быть заменён","Считывает неисправный манометр","Заклинил открытым","Функционирует нормально, выпуская и садясь обратно"], re:"Краткий выпуск с последующим возвратом по мере колебаний подачи — это нормальное защитное поведение, а не отказ — оно удерживает зону ниже подачи. Постоянный сброс — это проблема, которую надо отслеживать. AWWA M14 / USC FCCCHR."},
  {id:361, q:"Чтобы проверить точку открытия сброса испытательным комплектом, испытатель медленно стравливает давление подачи и отмечает перепад, при котором сброс:", opts:["Впервые начинает сбрасывать (открывается)","Полностью закрывается","Достигает давления подачи","Показывает ноль"], re:"Точка открытия — это перепад, при котором сброс только начинает сбрасывать по мере стравливания подачи; он должен быть 2.0 psid или выше. Процедура USC FCCCHR / AWWA M14."},
  {id:362, q:"Модуль предохранительного клапана с затвердевшей, деформированной резиновой мембраной чаще всего будет:", opts:["Открываться позже и герметизировать лучше","Не удерживать свой перепад и подтекать или открываться в неправильной точке","Не иметь симптомов","Увеличивать перепад клапана"], re:"Мембрана, потерявшая упругость, не может точно удерживать перепад подача-зона, поэтому сброс подтекает или открывается вне спецификации. Замените модуль сброса. AWWA M14 / производитель."},
  {id:363, q:"Сбросной порт (воздушный зазор) предохранительного клапана должен поддерживаться:", opts:["Плотно закрытым колпачком","Забитым мусором","Свободным и не погружённым и не подключённым напрямую к дренажу","Ниже уровня воды напольного трапа"], re:"Сброс должен сбрасывать через открытый воздушный зазор; закрытие его колпачком или погружение выхода сводит на нет воздушный зазор и может вызвать перекрёстное соединение. Установка AWWA M14 / USC FCCCHR."},
  {id:364, q:"Предохранительный клапан RP, который открывается в правильной точке и чисто садится обратно, когда устанавливается расход, записывается как:", opts:["Не прошедший","Не поддающийся испытанию","Требующий замены","Прошедший"], re:"Сброс, который открывается при 2.0 psid или выше и садится обратно правильно, отвечает критериям и записывается как прошедший, при условии что оба клапана также проходят. USC FCCCHR / AWWA M14."},
  {id:365, q:"Предохранительный клапан, сбрасывающий устойчиво, хотя оба клапана по отдельности проходят испытание как герметичные, указывает, что проблема:", opts:["Внутри самого предохранительного клапана или его импульсного прохода","Определённо в первом клапане","В размере трубопровода ниже по потоку","Только в калибровке манометра"], re:"Если оба клапана проходят, но сброс продолжает сбрасывать, неисправность в модуле сброса, его мембране или его импульсном проходе, и его следует обслужить. Поиск неисправностей AWWA M14."},
  {id:366, q:"Цель открытия предохранительного клапана, когда перепад падает к 2 psi, состоит в том, чтобы:", opts:["Повысить давление ниже по потоку","Сбросить зону в атмосферу, чтобы загрязнённая вода не могла достичь подачи","Перекалибровать клапаны","Остановить показание манометра"], re:"Выпуская центральную зону в атмосферу, сброс обеспечивает, что любая утечка мимо второго клапана выливается наружу, а не возвращается в питьевую подачу. USC FCCCHR / AWWA M14."},
  {id:367, q:"Распространённая полевая ошибка, из-за которой исправный предохранительный клапан выглядит неисправным, — это:", opts:["Правильное стравливание шлангов","Запись точки открытия","Незамеченное тепловое расширение или колебание подачи, вызывающее законный сброс","Закрытие входного запорного клапана последним"], re:"Законный докучливый сброс от теплового расширения или колебаний подачи можно принять за дефектный сброс; подтвердите причину прежде, чем забраковать сброс. Поиск неисправностей AWWA M14 / USC FCCCHR."},
  {id:368, q:"На PVB обратный клапан должен быть внутренне нагружен и герметичен против капель в направлении потока по меньшей мере с:", opts:["10.0 psid","2.0 psid","5.0 psid","1.0 psid"], re:"Клапан PVB должен быть нагружен и герметичен против капель по меньшей мере до 1.0 psid в направлении потока; воздухоприёмник должен открываться при 1.0 psid или более. Критерии PVB USC FCCCHR / AWWA M14."},
  {id:369, q:"Правильный первый шаг перед открытием узла для замены внутренних деталей — это:", opts:["Закрыть запорные клапаны и сбросить (стравить давление) узел через испытательный кран","Полностью открыть все испытательные краны","Снять крышку предохранительного клапана под давлением","Отсоединить манометр"], re:"Всегда изолируйте запорными клапанами и стравите давление через испытательный кран перед разборкой; открывать узел под давлением небезопасно. Процедура обслуживания AWWA M14 / производитель."},
  {id:370, q:"Фирменный 'резиновый комплект' производителя для узла RP обычно содержит:", opts:["Новый манометр и шланги","Запасные диски/уплотнения клапанов, кольцевые уплотнения и резину предохранительного клапана","Только новый запорный клапан","Калибровочные гири"], re:"Резиновые ремонтные комплекты поставляют изнашиваемые детали — диски/уплотнения клапанов, кольцевые уплотнения и резину мембраны/седла сброса — чтобы изношенную или загрязнённую резину можно было обновить. Перечни ремонтных комплектов производителя (Watts/Febco)."},
  {id:371, q:"При переборке обратного клапана задранное или изъязвлённое седло, по которому диск не может герметизировать, следует:", opts:["Оставить как есть","Закрасить","Очистить, восстановить или заменить согласно производителю","Затянуть сильнее"], re:"Повреждённое седло будет подтекать даже с новым диском; очистите, восстановите (если это предусмотрено) или замените его, следуя инструкциям производителя. Руководство по ремонту AWWA M14 / производитель."},
  {id:372, q:"Слабая или сломанная пружина клапана исправляется:", opts:["Растягиванием старой пружины","Переворачиванием диска","Добавлением шайб под седло","Установкой запасной пружины или модуля клапана от производителя"], re:"Пружины, которые ослабли или сломались, заменяют правильной пружиной/модулем производителя, чтобы клапан нагружался должным образом и удерживал свой минимальный перепад. Руководство по ремонту производителя."},
  {id:373, q:"При замене деталей использование неоригинальных (не OEM) или несоответствующих компонентов может:", opts:["Аннулировать одобрение узла и заставить его выйти из строя или испытываться неправильно","Всегда улучшать характеристики","Не иметь эффекта","Безопасно повышать уставку сброса"], re:"Только детали, указанные производителем, удерживают узел в рамках его одобрения USC/ASSE; неправильные детали могут изменить нагрузки пружин и посадку и аннулировать допуск. USC FCCCHR / производитель."},
  {id:374, q:"Перед повторной сборкой очищенного клапана техник должен:", opts:["Оставить мусор на месте","Промыть песок и осмотреть диск, седло и пружину на предмет повреждений","Пропустить осмотр для экономии времени","Нанести трубную пасту на резину"], re:"Промывка оставшегося мусора и осмотр каждой детали обеспечивает, что перебранный клапан сядет; нефтепродуктов на резине избегают, так как они её разрушают. AWWA M14 / производитель."},
  {id:375, q:"Предохранительный клапан на RP обслуживается путём:", opts:["Заваривания его наглухо","Снятия его навсегда","Замены модуля сброса / мембраны и резины седла и очистки импульсного прохода","Закрытия его выхода колпачком"], re:"Проблемы сброса устраняются обновлением резины/мембраны модуля сброса и седла и прочисткой импульсного прохода, чтобы он правильно воспринимал перепад. Руководство по ремонту производителя / AWWA M14."},
  {id:376, q:"Смазка, используемая на кольцевых уплотнениях во время переборки защиты от обратного потока, должна быть:", opts:["Нефтяной смазкой","Герметиком для резьбы труб","Моторным маслом","Одобренной нетоксичной, безопасной для воды (FDA/NSF) смазкой, совместимой с резиной"], re:"Используются только безопасные для питьевой воды, совместимые с резиной смазки; нефтепродукты разбухают и разрушают уплотнения и могут загрязнить воду. Руководство производителя / NSF."},
  {id:377, q:"Если ремонтные детали больше недоступны или корпус треснул, правильное действие — это:", opts:["Заменить весь узел одобренным изделием","Импровизировать детали","Оставить его вне эксплуатации на неопределённый срок без плана","Закрыть сброс колпачком и использовать повторно"], re:"Треснувший корпус или устаревшее изделие без деталей должно быть заменено действующим одобренным узлом; импровизированные в поле детали не допускаются. AWWA M14 / USC FCCCHR."},
  {id:378, q:"При повторной установке внутренних деталей затягивание болтов неравномерно или с избыточным моментом может:", opts:["Улучшить уплотнение","Деформировать крышку/седло и вызвать утечки","Перекалибровать сброс","Не иметь эффекта"], re:"Неравномерный или избыточный момент коробит крышки и сёдла и защемляет кольцевые уплотнения, создавая утечки; следуйте схеме и значениям момента затяжки производителя. Руководство по обслуживанию производителя."},
  {id:379, q:"После очистки загрязнённого предохранительного клапана вода, которая всё ещё подтекает из него, обычно означает:", opts:["Работа выполнена","Клапаны неисправны","Резина седла или мембрана сброса изношена и должна быть заменена, а не просто очищена","Манометр неисправен"], re:"Если очистка не останавливает подтекание, резина сброса приобрела остаточную деформацию или повреждена, и модуль/мембрану следует заменить. AWWA M14 / производитель."},
  {id:380, q:"Запорные клапаны (задвижка или шаровой кран с упругим седлом) узла испытываются перед обратными клапанами, потому что испытатель должен убедиться, что они:", opts:["Покрашены","Считывают манометр","Открывают сброс","Закрываются герметично против капель, чтобы можно было изолировать узел для точного испытания"], re:"Запорные клапаны должны садиться плотно; подтекающий запорный клапан № 1 или № 2 позволяет подаче или противодавлению обойти испытание и искажает показания. Процедура AWWA M14 / USC FCCCHR."},
  {id:381, q:"Во время разборки поддержание деталей в порядке и следование развёрнутому виду производителя помогает обеспечить:", opts:["Правильную ориентацию и то, что ни пружина, ни диск, ни кольцевое уплотнение не пропущены при сборке","Более медленную работу","Открытие сброса ниже","Перекалибровку манометра"], re:"Следование схеме деталей производителя предотвращает перевёрнутые диски, отсутствующие пружины или защемлённые кольцевые уплотнения, которые провалили бы перебранный узел. Руководство по обслуживанию производителя."},
  {id:382, q:"Изношенный первый клапан, который не удаётся довести до 5.0 psid после очистки, следует:", opts:["Вернуть в эксплуатацию как есть","Перебрать с новым диском/уплотнением и пружиной (или модулем), пока он не достигнет минимума","Оставить подтекающим","Обойти"], re:"Если одна очистка не восстановит минимум 5.0 psid, обновите диск/уплотнение и пружину (или замените модуль клапана), чтобы клапан отвечал критериям. AWWA M14 / производитель."},
  {id:383, q:"Нефтяные масла или смазки держат вдали от резиновых деталей защиты от обратного потока, потому что они:", opts:["Помогают резине служить дольше","Улучшают уставку сброса","Разбухают, размягчают и разрушают резину, вызывая утечки","Очищают седло"], re:"Нефтепродукты несовместимы с резиной, используемой в клапанах и мембранах сброса; они вызывают разбухание и отказ. Используйте только одобренные безопасные для воды смазки. Руководство производителя / NSF."},
  {id:384, q:"При медленном возврате отремонтированного узла в эксплуатацию правильная последовательность обычно состоит в том, чтобы:", opts:["Открыть запорный клапан ниже по потоку (№ 2) первым, быстро","Оставить вход закрытым","Открыть оба полностью сразу","Открыть запорный клапан выше по потоку (№ 1) медленно первым для заполнения, затем открыть нижний по потоку (№ 2)"], re:"Откройте запорный клапан выше по потоку медленно для заполнения и подачи давления в узел, затем откройте запорный клапан ниже по потоку; это предотвращает скачок и гидроудар, которые могли бы поднять сброс. Пуск AWWA M14 / производитель."},
  {id:385, q:"Любая утечка, замеченная за испытательным краном или фитингом после переборки, должна быть устранена, потому что она может:", opts:["Исказить последующие показания испытания и указывать, что узел не собран до конца","Быть проигнорирована","Улучшить точность","Безопасно снизить давление подачи"], re:"Утечки на испытательных кранах или фитингах и тратят воду, и искажают будущие показания перепада; повторно загерметизируйте или замените фитинг, чтобы узел был герметичен. AWWA M14 / производитель."},
  {id:386, q:"Дифференциальный испытательный манометр обратного потока должен поддерживать точность не менее:", opts:["+/- 2.0 psid","+/- 0.2 psid","+/- 5.0 psid","+/- 10 psid"], re:"Полевой испытательный манометр должен показывать в пределах +/- 0.2 psid (согласно ASSE 1064 / отраслевому руководству), чтобы критерии 2 psid и 5 psid можно было оценивать надёжно. BAVCO / TCEQ / ASSE 1064."},
  {id:387, q:"Как часто обычно требуется проверять точность / калибровать испытательный комплект обратного потока?", opts:["Каждые 5 лет","Только когда он ломается","По меньшей мере раз в год (ежегодно)","Один раз за срок службы комплекта"], re:"Большинство юрисдикций и отраслевое руководство требуют проверки точности манометра по меньшей мере ежегодно (и повторной калибровки, если он отклоняется более чем на +/- 0.2 psid). BAVCO / TCEQ."},
  {id:388, q:"Калибровка испытательного манометра обратного потока должна быть прослеживаема до:", opts:["Местного счёта за воду","Давления здания","Кода краски производителя","Эталона, прослеживаемого до NIST"], re:"Проверка точности должна прослеживаться до эталона с калибровкой, прослеживаемой до NIST, чтобы показания были обоснованными. TCEQ / BAVCO / ASSE 1064."},
  {id:389, q:"Испытательный манометр, который показывает 0.5 psid завышенно, наиболее опасным образом заставит испытателя:", opts:["Пропустить сброс или клапан, который на самом деле ниже своего минимума","Проваливать только исправные узлы","Не иметь реального эффекта","Считывать давление подачи"], re:"Манометр, показывающий завышенно, может заставить сброс или клапан ниже минимума казаться отвечающим критериям 2.0/5.0/1.0 psid, пропуская небезопасный узел. Отсюда предел +/- 0.2 psid и ежегодная проверка. BAVCO / TCEQ."},
  {id:390, q:"Перед каждым испытанием испытатель должен стравить весь воздух из шлангов комплекта, потому что захваченный воздух:", opts:["Занижает показание","Завышает показание перепада и может скрыть подтекающий клапан","Не имеет эффекта","Калибрует манометр"], re:"Воздух в линиях считывается как лишний перепад (ложно высокий), маскируя подтекающий клапан; стравливание верхнего и нижнего шлангов даёт истинное показание. Руководство по испытательному комплекту BAVCO / AWWA M14."},
  {id:391, q:"После любого ремонта или замены детали узел должен быть:", opts:["Возвращён в эксплуатацию без испытания","Покрашен","Испытан повторно и показано прохождение перед повторным вводом в эксплуатацию","Оставлен до следующего ежегодного испытания"], re:"Замена уплотнения, пружины, клапана или сброса меняет внутреннюю динамику; прошедшее повторное испытание и отчёт обязательны прежде, чем узел вернётся в эксплуатацию. AWWA M14 / нормативное требование."},
  {id:392, q:"Один дифференциальный манометр с 3 или 5 клапанами предпочтительнее двух отдельных манометров давления, потому что он:", opts:["Дешевле в доставке","Считывает только давление подачи","Не нуждается в калибровке","Напрямую считывает малый перепад, избегая ошибки вычитания двух больших показаний"], re:"Вычитание двух манометров высокого диапазона усиливает ошибку при малых значениях 1-5 psid, которые важны; дифференциальный манометр считывает разницу напрямую и точно. Руководство по испытательному комплекту BAVCO / AWWA M14."},
  {id:393, q:"Испытательный комплект, который роняли или который показывает беспорядочные показания, следует:", opts:["Снять с эксплуатации и повторно проверить/откалибровать перед дальнейшими испытаниями","Оставить в эксплуатации","Использовать только на малых узлах","Покрасить и использовать повторно"], re:"Физический удар может сместить калибровку; проверьте точность по прослеживаемому эталону прежде, чем снова доверять комплекту. Беспорядочные показания делают результаты недействительными. BAVCO / TCEQ."},
  {id:394, q:"Отчёт об испытании после ремонта и повторного испытания должен записывать:", opts:["Только имя испытателя","Окончательные прошедшие показания (перепады клапанов и точку открытия сброса) и что он прошёл","Цвет краски","Только давление подачи"], re:"Отчёт о повторном испытании документирует фактические окончательные показания (каждый перепад клапана и точку открытия сброса), доказывая, что узел отвечает критериям после ремонта. AWWA M14 / нормативная отчётность."},
  {id:395, q:"Если свежеоткалиброванный манометр и тщательное испытание всё ещё показывают открытие сброса ниже 2.0 psid, правильный вывод состоит в том, что:", opts:["Манометр снова неисправен","Испытание не может быть выполнено","Предохранительный клапан выходит из строя и должен быть отремонтирован и испытан повторно","Давление подачи слишком высокое"], re:"После подтверждения точности манометра открытие сброса ниже 2.0 psid является реальным отказом сброса, требующим обслуживания и прошедшего повторного испытания. USC FCCCHR / AWWA M14."},
  {id:396, q:"Запись или наклейка калибровки на испытательном комплекте служит для того, чтобы:", opts:["Украсить комплект","Заменить отчёт об испытании","Увеличить уставку сброса","Задокументировать последнюю дату проверки точности и что манометр в пределах допуска"], re:"Наклейка/сертификат калибровки доказывает, что манометр был проверен в пределах +/- 0.2 psid к определённой дате, что требуют регуляторы и поставщики воды. TCEQ / BAVCO."},
  {id:397, q:"Во время испытания точки открытия сброса игольчатые клапаны манометра (управляющие клапаны) используются для того, чтобы:", opts:["Медленно стравливать давление, чтобы можно было считать точный перепад открытия","Покрасить манометр","Увеличить давление подачи","Закрыть сброс навсегда"], re:"Игольчатые/управляющие клапаны комплекта позволяют испытателю стравливать давление постепенно и зафиксировать перепад, при котором сброс впервые открывается. Процедура AWWA M14 / USC FCCCHR."},
  {id:398, q:"Повторное испытание, которое не проходит после ремонта, означает, что техник должен:", opts:["Всё равно представить его как прошедшее","Диагностировать и устранить оставшуюся неисправность, затем испытывать повторно, пока не пройдёт","Оставить его в эксплуатации","Снять предохранительный клапан"], re:"Узел может быть возвращён в эксплуатацию только после прошедшего испытания; провалившееся повторное испытание означает дополнительный ремонт (например, пропущенную изношенную деталь) и ещё одно испытание. AWWA M14 / нормативное требование."},
  {id:399, q:"Подключение верхнего и нижнего шлангов дифференциального манометра к общей точке в идеале должно показывать:", opts:["Около 2 psid","Около 5 psid","Около 0 psid (ноль), подтверждая, что манометр правильно обнуляется","Давление подачи"], re:"При обоих шлангах на одном давлении перепада нет, поэтому исправный манометр должен показывать около нуля; ненулевое показание сигнализирует о проблеме калибровки или стравливания воздуха. BAVCO / AWWA M14."},
  {id:400, q:"Фундаментальная причина, почему точность манометра и прошедшее повторное испытание так важны, состоит в том, что:", opts:["Они ускоряют бумажную работу","Они повышают давление подачи","Они снижают счета за воду","Неточный манометр или пропущенное повторное испытание могут оставить в эксплуатации загрязнённый или неисправный узел"], re:"Весь смысл испытания — защита здоровья населения; неправильный манометр или отсутствующее повторное испытание могут оставить провалившийся узел высокой опасности защищающим питьевую воду. USC FCCCHR / AWWA M14."},
  {id:401, q:"В Калифорнии какой документ, принятый State Water Resources Control Board, теперь регулирует контроль перекрёстных соединений и заменяет прежние нормативные требования по перекрёстным соединениям Title 17?", opts:["Cross-Connection Control Policy Handbook (CCCPH)","Uniform Plumbing Code","California Fire Code","OSHA 29 CFR 1910"], re:"SWRCB приняла Cross-Connection Control Policy Handbook (CCCPH), который заменяет Разделы 7583-7586 и 7601-7605 Title 17 CCR в части, касающейся контроля перекрёстных соединений. Источник: веб-страница CCCPH SWRCB; CCCPH (2023)."},
  {id:402, q:"Какова дата вступления в силу калифорнийского Cross-Connection Control Policy Handbook (CCCPH)?", opts:["1 января 2000 г.","1 июля 2024 г.","1 января 1985 г.","1 июля 2030 г."], re:"CCCPH был принят 19 декабря 2023 г. и вступил в силу 1 июля 2024 г. Источник: история нормотворчества Cross-Connection Control Policy Handbook SWRCB."},
  {id:403, q:"Какое государственное ведомство Калифорнии приняло и администрирует Cross-Connection Control Policy Handbook?", opts:["U.S. EPA","Департамент транспорта Калифорнии","State Water Resources Control Board (Division of Drinking Water)","Федеральное FMCSA"], re:"State Water Resources Control Board (SWRCB) через своё подразделение Division of Drinking Water приняла и администрирует CCCPH. Источник: веб-страница CCCPH SWRCB."},
  {id:404, q:"До CCCPH какие разделы Title 17 California Code of Regulations содержали требования по контролю перекрёстных соединений?", opts:["Разделы 1000-1100","Разделы 5000-5050","Разделы 60000-60050","Разделы 7583-7605"], re:"Разделы 7583-7605 Title 17 CCR содержали калифорнийские нормативные требования по контролю перекрёстных соединений; CCCPH заменил Разделы 7583-7586 и 7601-7605. Источник: Title 17 CCR; CCCPH SWRCB."},
  {id:405, q:"Согласно калифорнийским правилам контроля перекрёстных соединений, как часто минимально должно проводиться полевое испытание устройства предотвращения обратного потока?", opts:["Не реже одного раза в год (каждые 12 месяцев)","Только один раз при установке","Каждые пять лет","Каждые десять лет"], re:"Калифорнийские правила (Title 17 и теперь CCCPH) требуют, чтобы устройства предотвращения обратного потока проходили полевое испытание при установке и не реже одного раза в год после этого, или чаще, если того требует поставщик воды / орган здравоохранения. Источник: CCCPH; прежний Title 17 CCR §7605."},
  {id:406, q:"Помимо испытания при установке и ежегодно, когда ещё Калифорния требует испытания устройства предотвращения обратного потока?", opts:["Только при продаже недвижимости","После ремонта, перемещения или замены устройства","Только каждый високосный год","Никогда больше после установки"], re:"Калифорния требует испытания при установке, после любого ремонта, перемещения или замены, и не реже одного раза в год. Затронутое устройство должно быть повторно проверено перед возвратом в эксплуатацию. Источник: CCCPH; AWWA M14."},
  {id:407, q:"Какие калифорнийские законодательные акты (Health & Safety Code) предоставляют правовую основу для государственных требований штата по контролю перекрёстных соединений и безопасной питьевой воде?", opts:["Vehicle Code §1000-1100","Penal Code §187","Health & Safety Code §116800-116820","Civil Code §1500"], re:"Разделы 116800-116820 California Health & Safety Code (в составе California Safe Drinking Water Act) уполномочивают требования по контролю перекрёстных соединений, реализуемые через Title 17/CCCPH. Источник: CA Health & Safety Code §116800 и далее."},
  {id:408, q:"Согласно калифорнийским нормативным требованиям, кто несёт основную правовую обязанность по защите системы общественного водоснабжения от загрязнения через перекрёстные соединения?", opts:["Налоговый оценщик округа","Только индивидуальный тестировщик","Государственный начальник пожарной охраны штата","Поставщик воды (система общественного водоснабжения / поставщик)"], re:"Поставщик воды (система общественного водоснабжения) должен защищать общественное водоснабжение от загрязнения путём реализации программы контроля перекрёстных соединений. Источник: прежний Title 17 CCR §7584; обязанности PWS в CCCPH."},
  {id:409, q:"Title 17 / CCCPH требует, чтобы тип устанавливаемой защиты от обратного потока основывался на каком факторе?", opts:["Степень опасности, которую помещения клиента представляют для системы общественного водоснабжения","Возраст здания","Цвет наружной краски","Ежемесячный счёт клиента за воду"], re:"Требуемый тип защиты (воздушный зазор, RP, DC и т. д.) определяется степенью опасности, которую помещения пользователя представляют для системы общественного водоснабжения. Источник: положения CCCPH об оценке опасности; прежний Title 17 CCR §7585."},
  {id:410, q:"Согласно CCCPH, сертификаты сертифицированных тестировщиков обратного потока должны признаваться каким органом начиная с 1 июля 2026 г.?", opts:["Местная торговая палата","State Water Resources Control Board (SWRCB)","U.S. Department of Labor","Шериф округа"], re:"С 1 июля 2026 г. тестировщики должны иметь сертификат от организации, признанной SWRCB, для соответствия CCCPH. Источник: страница Сертификации тестировщиков обратного потока и специалистов по контролю перекрёстных соединений SWRCB."},
  {id:411, q:"Согласно CCCPH, начиная с 1 июля 2027 г. сертифицирующие организации тестировщиков, используемые для соответствия, также должны быть аккредитованы по какому стандарту?", opts:["NFPA 13","Только ISO 9001","Аккредитация ANSI по ISO/IEC 17024","Котловой кодекс ASME"], re:"С 1 июля 2027 г. для соответствия CCCPH могут использоваться только сертифицирующие организации, аккредитованные ANSI по ISO/IEC 17024 (сертификация персонала). Источник: страница Сертификации тестировщиков обратного потока SWRCB."},
  {id:412, q:"Какой из следующих НЕ является методом защиты, признанным калифорнийскими правилами контроля перекрёстных соединений?", opts:["Воздушный зазор (AG)","Устройство принципа пониженного давления (RP)","Устройство двойного обратного клапана (DC)","Свободно намотанная тряпка поверх трубы"], re:"Признанные методы включают воздушный зазор, устройства принципа пониженного давления, устройства двойного обратного клапана и вакуумные прерыватели. Тряпка не является одобренным методом. Источник: CCCPH; прежний Title 17 CCR §7603-7604."},
  {id:413, q:"Почему Калифорния заменила прежние положения Title 17 о перекрёстных соединениях на CCCPH?", opts:["Потому что Title 17 оставался практически без изменений с 1980-х годов и нуждался в модернизации","Чтобы убрать все требования к испытаниям","Чтобы устранить роль поставщиков воды","Чтобы сделать устройства обратного потока необязательными"], re:"CCCPH модернизирует требования, которые оставались практически без изменений с момента первоначального принятия Title 17 в 1980-х годах, расширяя и обновляя стандарты программы. Источник: материалы о принятии CCCPH SWRCB."},
  {id:414, q:"Согласно калифорнийским правилам, кто отвечает за обеспечение того, чтобы устройство предотвращения обратного потока клиента было испытано и поддерживалось в надлежащем рабочем состоянии?", opts:["Непосредственно State Water Board","Клиент-потребитель воды / владелец устройства","Владелец соседней недвижимости","Производитель устройства"], re:"Обеспечение ежегодного испытания устройства и поддержание его в надлежащем рабочем состоянии в любое время является обязанностью клиента-потребителя воды. Источник: CCCPH; программы контроля перекрёстных соединений поставщиков воды Калифорнии."},
  {id:415, q:"Для помещений, где обращаются с материалами, опасными для здоровья (опасность для здоровья), какой уровень защиты Калифорния требует на сервисном подключении?", opts:["Защита не требуется","Только вакуумный прерыватель шлангового крана","Воздушный зазор (AG) или устройство принципа пониженного давления (RP)","Простой запорный клапан"], re:"Помещения, представляющие опасность для здоровья (загрязнитель-контаминант), должны быть защищены одобренным воздушным зазором или устройством принципа пониженного давления. Источник: положения CCCPH об опасности; прежний Title 17 CCR §7604 Таблица 1."},
  {id:416, q:"Воздушные зазоры, используемые для контроля перекрёстных соединений в Калифорнии, должны соответствовать минимальным размерам какого упомянутого стандарта?", opts:["FMVSS 121 (пневматические тормоза)","NFPA 70 (National Electrical Code)","ASTM A36 (конструкционная сталь)","ASME A112.1.2 (минимальные воздушные зазоры)"], re:"CCCPH ссылается на ASME A112.1.2 для минимальных воздушных зазоров для сантехнических приборов. Источник: CCCPH; ASME A112.1.2."},
  {id:417, q:"Согласно CCCPH, кого система общественного водоснабжения может назначить для выполнения задач контроля перекрёстных соединений, таких как обследования опасностей?", opts:["Сертифицированного специалиста по контролю перекрёстных соединений","Любого, без каких-либо квалификаций","Только губернатора штата","Только подрядчиков из других штатов"], re:"CCCPH требует, чтобы PWS использовала сертифицированных специалистов по контролю перекрёстных соединений для выполнения задач программы, таких как обследования и оценки опасностей. Источник: статья CCCPH о специалистах; страница сертификации специалистов SWRCB."},
  {id:418, q:"Что такое AWWA Manual M14?", opts:["Федеральный закон","Руководство AWWA по рекомендуемым практикам в области предотвращения обратного потока и контроля перекрёстных соединений","Законодательный акт штата Калифорния","Разрешение OSHA на замкнутое пространство"], re:"AWWA M14, 'Backflow Prevention and Cross-Connection Control: Recommended Practices' — это отраслевое руководство по практике водоснабжения, а не закон. Источник: AWWA Manual M14."},
  {id:419, q:"Какова текущая редакция AWWA Manual M14?", opts:["Первая редакция","Вторая редакция","Пятая редакция (опубликована в 2024 г.)","Системы редакций не существует"], re:"Пятая редакция AWWA M14 была опубликована в 2024 г. (ссылка ANSI AWWA M14-2024). Источник: магазин AWWA; листинг ANSI webstore AWWA M14-2024."},
  {id:420, q:"С юридической точки зрения стандарты и руководства AWWA, такие как M14, лучше всего описать как какие из следующих?", opts:["Секретные отраслевые документы","Федеральные уголовные законы","Автоматически обязательные в каждом штате","Документы добровольного консенсуса, которые не заменяют применимое право"], re:"Стандарты AWWA являются документами добровольного консенсуса и не заменяют и не вытесняют применимые законы, нормативные требования или кодексы; они становятся обязательными только когда их принимает соответствующий орган власти. Источник: заявление о программе стандартов AWWA."},
  {id:421, q:"Чем в основном занимается USC FCCCHR (Foundation for Cross-Connection Control and Hydraulic Research)?", opts:["Оценивает и одобряет устройства предотвращения обратного потока и публикует процедуры полевых испытаний","Устанавливает пределы выбросов транспортных средств","Выдаёт водительские права","Регулирует электропроводку"], re:"USC FCCCHR ведёт программу одобрения (лабораторная и полевая оценка) устройств предотвращения обратного потока и публикует Manual of Cross-Connection Control с процедурами полевых испытаний. Источник: веб-страницы одобрения и списка USC FCCCHR."},
  {id:422, q:"Как долго действительно одобрение устройства предотвращения обратного потока в Списке USC FCCCHR, прежде чем его необходимо обновить?", opts:["Один год","Три года","Десять лет","Бессрочно; оно никогда не обновляется"], re:"Одобрения USC FCCCHR предоставляются на срок три года и подлежат обновлению. Источник: List of Approved Backflow Prevention Assemblies USC FCCCHR."},
  {id:423, q:"Какое отличительное требование включает программа одобрения USC FCCCHR, которого нет у многих других программ одобрения?", opts:["50-летнюю гарантию","Требование, чтобы устройство было окрашено в красный цвет","Обязательную годичную полевую оценку перед внесением в список","Одобрение Президентом США"], re:"Отмечается, что USC FCCCHR является единственной программой одобрения обратного потока, которая требует годичной полевой оценки в дополнение к лабораторным испытаниям перед внесением устройства в список. Источник: описание программы одобрения USC FCCCHR."},
  {id:424, q:"'Список' USC FCCCHR идентифицирует каждое одобренное устройство по всему перечисленному, КРОМЕ:", opts:["Тип устройства и производитель","Модель и размер","Даты одобрения и обновления","Домашний адрес владельца недвижимости"], re:"Список идентифицирует каждое устройство по типу, производителю, модели, размеру, редакции руководства, по которой оно было одобрено, и датам одобрения/обновления — но не по адресам клиентов. Источник: List USC FCCCHR."},
  {id:425, q:"Какой документ, опубликованный USC FCCCHR, широко используется для стандартизации того, как тестировщики выполняют полевые испытания устройств обратного потока?", opts:["Manual of Cross-Connection Control (процедуры полевых испытаний, напр., 10-я редакция)","National Electrical Code","Федеральный налоговый кодекс","MUTCD"], re:"Manual of Cross-Connection Control USC FCCCHR (с процедурами полевых испытаний, текущая 10-я редакция) стандартизирует методы полевых испытаний тестировщиков, используемые во многих программах. Источник: USC FCCCHR; руководство 10-й редакции USC."},
  {id:426, q:"AWWA M14 объясняет, что два основных типа обратного потока — это какая пара?", opts:["Прямой поток и обратный осмос","Обратное сифонирование (backsiphonage) и обратное давление (backpressure)","Испарение и конденсация","Кавитация и гидроудар"], re:"AWWA M14 описывает два типа обратного потока как обратное сифонирование (backsiphonage) (вызванное отрицательным давлением подачи) и обратное давление (backpressure) (давление ниже по потоку превышает давление подачи). Источник: AWWA M14."},
  {id:427, q:"Какова основная цель AWWA Manual M14?", opts:["Установить пределы рабочего времени водителей коммерческого транспорта","Регулировать обращение с хладагентами","Описать причины и предотвращение обратного потока и перекрёстных соединений в системах питьевой воды","Установить правила минимальной заработной платы"], re:"M14 описывает причины и предотвращение обратного потока и перекрёстных соединений и помогает системам водоснабжения построить программу контроля перекрёстных соединений. Источник: описание AWWA M14."},
  {id:428, q:"С каким университетом связан USC FCCCHR (Foundation for Cross-Connection Control and Hydraulic Research)?", opts:["University of Texas","New York University","University of Florida","University of Southern California (в Калифорнии)"], re:"Foundation связан с University of Southern California (USC) в Калифорнии. Источник: USC FCCCHR (fccchr.usc.edu)."},
  {id:429, q:"Устройство предотвращения обратного потока должно успешно пройти какие две фазы, чтобы получить одобрение USC FCCCHR?", opts:["Лабораторную оценку и полевую оценку","Маркетинговую проверку и план продаж","Дегустацию и проверку цвета","Проверку шума и проверку веса"], re:"Одобрение USC FCCCHR требует успешного прохождения как лабораторной оценки, так и полевой оценки под надзором Foundation. Источник: программа одобрения USC FCCCHR."},
  {id:430, q:"Какое утверждение лучше всего описывает отношения между документами AWWA M14 / USC FCCCHR и местным поставщиком воды?", opts:["Они автоматически заменяют все местные правила","Поставщик или юрисдикция может принять или сослаться на них, придавая им обязательную силу на местном уровне","Они запрещают поставщикам иметь какую-либо программу","Они применяются только за пределами Соединённых Штатов"], re:"Это справочные документы; они приобретают обязательную силу там, где поставщик, штат или юрисдикция принимает их или ссылается на них в своих правилах. Источник: программа стандартов AWWA; использование программы USC FCCCHR ведомствами."},
  {id:431, q:"Согласно AWWA M14, полноценная программа контроля перекрёстных соединений помогает системе водоснабжения сделать что из следующего?", opts:["Проектировать дорожные развязки","Подавать декларации о подоходном налоге","Выбирать, устанавливать и обслуживать соответствующую защиту от обратного потока","Сертифицировать сварщиков"], re:"M14 помогает системе водоснабжения выбирать, устанавливать и обслуживать устройства предотвращения обратного потока как часть общей программы контроля перекрёстных соединений. Источник: описание AWWA M14."},
  {id:432, q:"Когда устройство обратного потока указано в Списке USC FCCCHR, в листинге также отмечается редакция какого документа, по которому устройство было одобрено?", opts:["Руководство по эксплуатации транспортного средства","Местная газета","Федеральный бюджет","USC Foundation Manual of Cross-Connection Control"], re:"Для каждого внесённого устройства отмечается редакция руководства USC Foundation (спецификации/процедуры полевых испытаний), по которой оно было одобрено. Источник: List USC FCCCHR."},
  {id:433, q:"Почему тестировщику важно использовать Список USC FCCCHR или одобренный список поставщика при проверке устройства?", opts:["Чтобы подтвердить, что модель устройства является одобренным типом для данного применения","Чтобы узнать цену акций производителя","Чтобы выбрать цвета краски","Чтобы установить сумму счёта за воду"], re:"Одобренный список подтверждает, что марка/модель является одобренным типом устройства, приемлемым для установки; неодобренные устройства могут не удовлетворять поставщика или нормативные требования. Источник: List USC FCCCHR; правила программы поставщика."},
  {id:434, q:"AWWA M14 публикуется как часть какой серии AWWA?", opts:["Федеральный Code of Regulations","Manual of Water Supply Practices (серия M)","Серия информационных программ OSHA","Кодекс транспортных средств штата"], re:"M14 входит в состав Manual of Water Supply Practices AWWA (серия 'M' руководств по рекомендуемым практикам). Источник: Руководства AWWA / листинг M14."},
  {id:435, q:"Согласно калифорнийским правилам, какой из следующих является обязательным элементом программы контроля перекрёстных соединений системы общественного водоснабжения?", opts:["Запрет на внутреннюю сантехнику","Требование, чтобы все клиенты красили свои дома","Принятие операционных правил или постановления для реализации программы","Бесплатная бутилированная вода для всех жителей"], re:"Программа контроля перекрёстных соединений должна включать операционные правила, постановления или резолюцию для её реализации. Источник: прежний Title 17 CCR §7584; элементы программы CCCPH."},
  {id:436, q:"В рамках своей программы что должен проводить поставщик воды для выявления помещений, где вероятно возникновение перекрёстных соединений?", opts:["Проверку кредитоспособности","Исследование трафика","Опрос на вкус","Обследования / оценки опасностей помещений клиентов"], re:"Поставщики должны обследовать свою зону обслуживания и проводить оценки опасностей для выявления фактических или потенциальных перекрёстных соединений и степени опасности. Источник: Глава 3 CCCPH об оценке опасностей; прежний Title 17 CCR §7584."},
  {id:437, q:"Программа поставщика воды должна обеспечивать наличие как минимум одного лица, обученного/сертифицированного в какой области?", opts:["Контроль перекрёстных соединений","Подготовка налогов","Проектирование дорог","Общественное питание"], re:"Программа должна обеспечивать наличие как минимум одного лица, обученного/сертифицированного в области контроля перекрёстных соединений, для её выполнения. Источник: прежний Title 17 CCR §7584; требование к специалисту CCCPH."},
  {id:438, q:"Что из следующего должен установить поставщик воды в рамках своей программы контроля перекрёстных соединений?", opts:["Парк грузовиков доставки","Процедуру или систему испытания устройств предотвращения обратного потока","Розничный магазин","Радиостанцию"], re:"Программа должна устанавливать процедуру или систему испытания устройств предотвращения обратного потока (включая учёт и уведомления о ежегодном испытании). Источник: прежний Title 17 CCR §7584; программа испытаний CCCPH."},
  {id:439, q:"CCCPH требует, чтобы система общественного водоснабжения вела записи программы, включающие сведения о каждом устройстве предотвращения обратного потока. Какие сведения требуются?", opts:["История голосования владельца","Любимый цвет владельца","Тип, производитель, модель, размер, местоположение, владелец, дата установки и серийный номер","Марка транспортного средства владельца"], re:"Записи должны включать опасность/применение, местоположение, владельца, тип, производителя, модель, размер, дату установки и серийный номер каждого устройства. Источник: требования к ведению записей CCCPH."},
  {id:440, q:"Согласно CCCPH, сколько самых последних оценок опасности на каждом объекте поставщик должен хранить в своих записях?", opts:["Пятьдесят","Ни одной","Только самую первую из когда-либо проведённых","Две самые последние оценки опасности"], re:"CCCPH требует, чтобы программа хранила две самые последние оценки опасности, проведённые на каждом объекте. Источник: требования к ведению записей CCCPH."},
  {id:441, q:"Если клиент не обеспечивает испытание или ремонт требуемого устройства обратного потока, какую меру принуждения может в конечном итоге принять поставщик воды согласно своему постановлению?", opts:["Прекратить (отключить) водоснабжение до достижения соответствия","Эвакуировать автомобиль клиента","Аннулировать водительские права клиента","Повысить налог с продаж"], re:"Постановления поставщиков обычно разрешают прекращение водоснабжения за несоблюдение требований к испытанию или установке после уведомления. Источник: принуждение по программе CCCPH/Title 17; постановления поставщиков о перекрёстных соединениях."},
  {id:442, q:"Программа контроля перекрёстных соединений поставщика воды предназначена в первую очередь для защиты чего?", opts:["Рекламного бюджета поставщика","Системы общественного водоснабжения питьевой водой от загрязнения","Местной спортивной команды","Цены на хладагент"], re:"Основная цель программы — защитить систему общественного водоснабжения питьевой водой от загрязнения обратным потоком. Источник: CCCPH; прежний Title 17 CCR §7584."},
  {id:443, q:"Согласно калифорнийским правилам, с кем поставщик воды может заключить договор для реализации всей или части своей программы контроля перекрёстных соединений?", opts:["С иностранным правительством","С любым случайным человеком без лицензии","С местным органом здравоохранения или другим ведомством, одобренным органом здравоохранения","С анонимной онлайн-учётной записью"], re:"Поставщик воды может реализовать программу напрямую или по договору с местным органом здравоохранения или другим ведомством, одобренным органом здравоохранения. Источник: прежний Title 17 CCR §7584; CCCPH."},
  {id:444, q:"Поставщик воды решает, какая защита от обратного потока нужна клиенту, на основе оценки опасности, которая классифицирует помещения как какие из следующих?", opts:["Только новое строительство или реконструкция","Только жилое или коммерческое зонирование","Только занимаемые владельцем или арендуемые","Опасность для здоровья (контаминант) или не связанная со здоровьем опасность (загрязнитель / pollutant)"], re:"Оценки опасности классифицируют степень опасности — опасность для здоровья (контаминант) против не связанной со здоровьем опасности (pollutant) — что определяет требуемую защиту. Источник: CCCPH; AWWA M14."},
  {id:445, q:"Какой тип защиты от обратного потока поставщик обычно требует для помещений, классифицированных только как не связанная со здоровьем опасность (pollutant)?", opts:["Как минимум устройство двойного обратного клапана (DC)","Никакой защиты вообще","Только воздушный зазор, никогда ничего другого","Простую задвижку"], re:"Не связанные со здоровьем опасности (pollutant) обычно защищаются одобренным устройством двойного обратного клапана, тогда как опасности для здоровья требуют AG или RP. Источник: CCCPH; прежний Title 17 CCR §7604 Таблица 1."},
  {id:446, q:"Многие поставщики отправляют клиентам ежегодное напоминание/уведомление с какой целью?", opts:["Только чтобы рекламировать новые тарифы на воду","Чтобы напомнить клиенту о том, что подошёл срок ежегодного испытания устройства обратного потока","Чтобы попросить клиента подстричь газон","Чтобы собрать пароль электронной почты клиента"], re:"Поставщики отслеживают устройства и уведомляют клиентов о наступлении срока ежегодного испытания — ключевая часть процедуры испытания, требуемой от программы. Источник: программа испытаний CCCPH; программы поставщиков."},
  {id:447, q:"Внутри системы общественного водоснабжения лицо, управляющее обследованиями, оценками опасностей и программой в целом, обычно является сертифицированным кем?", opts:["Налоговым аудитором","Оператором тяжёлой техники","Специалистом по контролю перекрёстных соединений","Фармацевтом"], re:"Сертифицированный специалист по контролю перекрёстных соединений управляет функциями программы, такими как обследования и оценки опасностей; это отдельная сертификация, отличная от сертификации тестировщика устройств. Источник: сертификация специалистов SWRCB; CCCPH."},
  {id:448, q:"Согласно CCCPH, тестировщики и специалисты, на которых полагается система общественного водоснабжения, должны быть кем?", opts:["Лицензированными агентами по недвижимости","Друзьями совета по водоснабжению","Несертифицированными добровольцами","Сертифицированными организацией, признанной (и позднее аккредитованной ANSI) согласно CCCPH"], re:"PWS должна обеспечить, чтобы все тестировщики устройств обратного потока и специалисты по контролю перекрёстных соединений, которых она использует, были сертифицированы согласно CCCPH (признанные организации, позднее аккредитованные по ANSI/ISO 17024). Источник: статья CCCPH о сертификации; SWRCB."},
  {id:449, q:"Программа поставщика воды должна обеспечивать, чтобы фактические и потенциальные перекрёстные соединения устранялись по возможности или иным образом контролировались с помощью чего?", opts:["Установки одобренных устройств предотвращения обратного потока или воздушных зазоров","Только размещения предупреждающих знаков","Покраски счётчика воды","Рассылки ежегодного информационного бюллетеня"], re:"Программы должны устранять перекрёстные соединения там, где это осуществимо, или контролировать их с помощью одобренных устройств предотвращения обратного потока или воздушных зазоров в соответствии с CCCPH. Источник: требования к защите CCCPH."},
  {id:450, q:"Какой уровень власти наиболее непосредственно требует от поставщиков воды Калифорнии вести программу контроля перекрёстных соединений?", opts:["Организация Объединённых Наций","Штат Калифорния (SWRCB) согласно законодательству штата и CCCPH","Ассоциация домовладельцев","Частная страховая компания"], re:"Законодательство штата (Health & Safety Code) и CCCPH SWRCB требуют, чтобы системы общественного водоснабжения Калифорнии реализовывали программы контроля перекрёстных соединений. Источник: CA Health & Safety Code §116800 и далее; CCCPH."},
  {id:451, q:"Когда устройство обратного потока не проходит ежегодное испытание, чего программа поставщика ожидает от клиента?", opts:["Навсегда удалить устройство","Игнорировать неудачу до следующего года","Отремонтировать устройство и повторно испытать его, затем подать протокол успешного испытания","Покрасить устройство и больше ничего не делать"], re:"Устройство, не прошедшее испытание, должно быть отремонтировано (или заменено) и повторно испытано, с подачей протокола успешного испытания поставщику для восстановления защиты. Источник: положения CCCPH об испытании/ремонте; программы поставщиков."},
  {id:452, q:"После завершения испытания устройства обратного потока кому обычно должен подаваться протокол испытания сертифицированного тестировщика?", opts:["Местной газете","Диспетчеру пожарной части","Государственному департаменту парков штата","Поставщику воды (системе общественного водоснабжения)"], re:"Протоколы испытаний подаются поставщику воды, отвечающему за программу контроля перекрёстных соединений (и копия хранится у тестировщика/владельца). Источник: отчётность CCCPH; правила программы поставщика."},
  {id:453, q:"Большинство поставщиков воды требуют, чтобы испытательный манометр, используемый сертифицированным тестировщиком, был откалиброван в течение какого срока?", opts:["В течение предыдущих 12 месяцев","В течение предыдущих 10 лет","Только один раз при покупке","Калибровка никогда не требуется"], re:"Большинство поставщиков требуют, чтобы дифференциальный испытательный манометр был откалиброван в течение предыдущих 12 месяцев, и дата калибровки должна быть записана в протоколе. Источник: требования поставщика к протоколу испытания; процедуры полевых испытаний AWWA M14/USC."},
  {id:454, q:"Какую информацию должен записать сертифицированный тестировщик в протоколе испытания для идентификации конкретного испытанного устройства?", opts:["Счёт за домашний телефон тестировщика","Серийный номер устройства (совпадающий с клеймом на устройстве)","Номерной знак автомобиля клиента","Прогноз погоды"], re:"В протоколе должен быть записан серийный номер устройства, который должен совпадать с серийным номером, выбитым на устройстве, вместе с типом, маркой, моделью и размером. Источник: стандартные поля протокола испытания обратного потока; программы поставщиков."},
  {id:455, q:"Какая идентифицирующая информация о тестировщике должна присутствовать в протоколе испытания устройства обратного потока?", opts:["Размер обуви тестировщика","Любимая еда тестировщика","Имя и номер сертификата тестировщика (и срок его действия)","Планы тестировщика на отпуск"], re:"Протоколы должны включать имя сертифицированного тестировщика, номер его сертификата и дату истечения срока действия сертификата, чтобы поставщик мог проверить полномочия. Источник: стандартные поля протокола испытания; программы поставщиков."},
  {id:456, q:"В протоколе испытания тестировщик должен чётко указать какой результат испытания?", opts:["Фазу луны","Индекс фондового рынка","Настроение тестировщика","Пройдено или Не пройдено (и любые выполненные ремонты)"], re:"В протоколе должен быть указан результат «пройдено/не пройдено» и задокументированы любые очистки или ремонты, выполненные перед окончательным результатом. Источник: стандартные поля протокола испытания обратного потока."},
  {id:457, q:"Что должен записать сертифицированный тестировщик в протоколе об использованном испытательном оборудовании?", opts:["Марку/модель испытательного набора, серийный номер и дату калибровки","Цену, за которую был куплен набор","Магазин, где был куплен набор","Ничего об оборудовании"], re:"В протоколе должны быть записаны марка и модель испытательного набора/манометра, его серийный номер и дата его калибровки. Источник: стандартные поля протокола испытания; требования поставщика."},
  {id:458, q:"Если тестировщик обнаруживает, что установленное устройство не является одобренной моделью для данного применения, каково надлежащее действие?", opts:["Сфальсифицировать протокол, показав, что оно прошло испытание","Отметить это и сообщить о несоответствии поставщику; устройство может нуждаться в замене","Игнорировать это, потому что важен только результат испытания","Удалить клеймо серийного номера"], re:"Тестировщики должны сообщать о несоответствиях, включая неодобренные устройства или устройства неправильного применения, поставщику; честная отчётность защищает здоровье населения. Источник: обязанности тестировщика по CCCPH; использование одобренного списка USC FCCCHR."},
  {id:459, q:"Основную этическую обязанность сертифицированного тестировщика устройств обратного потока лучше всего описать как какую из следующих?", opts:["Испытывать только устройства, до которых легко добраться","Всегда давать оценку «пройдено» каждому устройству, чтобы угодить клиенту","Сообщать результаты испытаний правдиво и точно","Держать все результаты в тайне от поставщика"], re:"Поскольку на кону питьевая вода населения, тестировщик должен сообщать результаты правдиво и точно; фальсификация протокола обратного потока может поставить под угрозу здоровье и является основанием для лишения сертификата. Источник: CCCPH; кодексы поведения сертификации тестировщиков."},
  {id:460, q:"Прежде чем вернуть отремонтированное или вновь установленное устройство в эксплуатацию, что должен сделать сертифицированный тестировщик?", opts:["Подождать один год перед испытанием","Просто предположить, что оно работает","Закрасить испытательные краны","Провести полевое испытание для проверки правильной работы устройства"], re:"Вновь установленные, отремонтированные, перемещённые или заменённые устройства должны пройти полевое испытание для проверки правильной работы, прежде чем на них можно будет полагаться. Источник: CCCPH; требования к полевым испытаниям AWWA M14."},
  {id:461, q:"Чтобы оставаться квалифицированным для проведения испытаний в Калифорнии согласно CCCPH, тестировщик должен сделать что из следующего?", opts:["Поддерживать действующий сертификат от признанной (и позднее аккредитованной ANSI) организации","Продлить лицензию на рыбную ловлю","Зарегистрировать новое транспортное средство","Подписаться на журнал"], re:"Тестировщики должны поддерживать действующий сертификат от организации, признанной SWRCB (аккредитованной по ANSI/ISO 17024 с 1 июля 2027 г.), чтобы проводить испытания на соответствие CCCPH. Источник: страница Сертификации тестировщиков обратного потока SWRCB; CCCPH."},
  {id:462, q:"Многие программы сертификации тестировщиков требуют повторной сертификации с какой периодичностью?", opts:["Один раз в жизни, без обновления","Периодически (обычно каждые три года)","Каждую неделю","Каждые 30 лет"], re:"Сертификаты тестировщиков обратного потока имеют ограниченный срок действия и обычно требуют повторной сертификации с периодической частотой (обычно каждые три года). Источник: описания программ сертификации тестировщиков Калифорнии (напр., CA-NV AWWA, ASSE)."},
  {id:463, q:"Почему серийный номер в протоколе испытания должен совпадать с серийным номером, выбитым на устройстве?", opts:["Чтобы зарегистрировать автомобиль тестировщика","Чтобы установить счёт за воду","Чтобы подтвердить, что было фактически испытано правильное, конкретное устройство","Чтобы выбрать цвет краски"], re:"Совпадающие серийные номера доказывают, что протокол соответствует конкретному устройству на месте, предотвращая мошенничество и ошибки учёта. Источник: требования поставщика к протоколу испытания."},
  {id:464, q:"Если испытательный манометр тестировщика не откалиброван, что должен сделать тестировщик?", opts:["Одолжить напольные весы клиента","Всё равно использовать его и угадывать показания","Округлить показания в большую сторону","Остановиться и откалибровать манометр, прежде чем сообщать результаты как действительные"], re:"Неоткалиброванный манометр даёт ненадёжные показания; тестировщик должен откалибровать его перед проведением действительных, подлежащих отчётности испытаний. Источник: требования поставщика к калибровке; процедуры полевых испытаний."},
  {id:465, q:"Сертифицированный тестировщик, как правило, должен хранить копию выполненных протоколов испытаний по какой причине?", opts:["Для ведения записей и документирования соответствия","Для продажи рекламодателям","Чтобы оклеить ими офис","Хранить их нет причин"], re:"Тестировщики хранят копии протоколов для ведения записей и документирования того, что требуемые испытания были выполнены и о них было сообщено. Источник: практика ведения записей по программе поставщика; CCCPH."},
  {id:466, q:"Что должен сделать сертифицированный тестировщик, если клиент просит его отметить не прошедшее испытание устройство как «пройдено»?", opts:["Отметить как «пройдено», чтобы клиент был доволен","Отказаться; сообщить истинный результат «не пройдено»","Отметить как «пройдено», но никому не говорить","Оставить протокол пустым"], re:"Тестировщик должен отказаться фальсифицировать протокол; истинный результат («не пройдено») должен быть сообщён, чтобы устройство было отремонтировано и водоснабжение защищено. Источник: кодексы поведения сертификации тестировщиков; CCCPH."},
  {id:467, q:"В протоколе испытания дата последней калибровки манометра требуется для того, чтобы поставщик мог подтвердить что?", opts:["Марку автомобиля клиента","Возраст тестировщика","Что калибровка манометра актуальна (обычно в течение 12 месяцев)","Местную погоду"], re:"Дата калибровки позволяет поставщику проверить, что манометр имел актуальную калибровку (обычно в течение 12 месяцев) на момент проведения испытания. Источник: требования поставщика к протоколу испытания."},
  {id:468, q:"Какая информация идентифицирует местоположение, к которому относится испытание, в протоколе испытания устройства обратного потока?", opts:["Столица штата","День рождения тестировщика","Штаб-квартира производителя","Сервисный адрес и местоположение устройства на объекте"], re:"Протоколы фиксируют сервисный адрес и конкретное местоположение устройства, чтобы поставщик мог сопоставить его с записями программы. Источник: стандартные поля протокола испытания; ведение записей CCCPH."},
  {id:469, q:"Чтобы воздушный зазор был эффективным, каково минимальное вертикальное расстояние, требуемое между выпуском подачи и краем перелива принимающего сосуда?", opts:["Не менее удвоенного диаметра трубы подачи, и никогда не менее 1 дюйма","Ровно 1/8 дюйма","Только равное диаметру трубы","Десятикратный диаметр трубы, минимум 3 фута"], re:"Эффективный (одобренный) воздушный зазор должен быть не менее удвоенного диаметра трубы подачи, измеренного по вертикали над краем перелива, и ни в коем случае не менее 1 дюйма. Источник: AWWA M14; ASME A112.1.2."},
  {id:470, q:"Устройство принципа пониженного давления (RP) НЕ должно устанавливаться в каком месте?", opts:["Над уровнем земли в хорошо дренируемой зоне","В приямке или любом месте, подверженном затоплению/погружению","В помещении с адекватным дренажом","На ровной площадке выше точки сброса предохранительного клапана"], re:"Устройство RP не должно погружаться или устанавливаться там, где оно может затопиться; его предохранительный клапан должен сбрасывать в воздух, а погружение свело бы на нет защиту и создало бы риск загрязнения. Источник: AWWA M14; нормы монтажа производителя/поставщика."},
  {id:471, q:"Напорный вакуумный прерыватель (PVB) должен устанавливаться как минимум на какой высоте над самым высоким нижерасположенным выпуском/трубопроводом, который он обслуживает?", opts:["Не менее 6 футов выше","На уровне земли или ниже","Не менее 12 дюймов выше самого высокого нижерасположенного выпуска","Не имеет значения, где он установлен"], re:"PVB должен устанавливаться не менее чем на 12 дюймов выше самого высокого нижерасположенного трубопровода/выпуска, чтобы воздухозаборник не мог погрузиться и воздушный разрыв мог функционировать. Источник: AWWA M14; ASSE 1020 / инструкции производителя."},
  {id:472, q:"От какого условия НЕ предназначен защищать напорный вакуумный прерыватель (PVB)?", opts:["Низкий спрос ниже по потоку","Обратное сифонирование (backsiphonage)","Воздух, поступающий через воздухозаборник","Обратное давление (backpressure)"], re:"PVB защищает только от обратного сифонирования (backsiphonage); его нельзя использовать там, где в нижерасположенном трубопроводе может развиться обратное давление (backpressure). Источник: AWWA M14; руководство по применению PVB."},
  {id:473, q:"Почему устройство предотвращения обратного потока должно устанавливаться так, чтобы оно было доступным?", opts:["Чтобы его можно было ежегодно испытывать и обслуживать или ремонтировать","Чтобы его можно было скрыть от глаз","Чтобы дети могли играть на нём","Чтобы его можно было полностью закопать"], re:"Устройства должны быть доступны для требуемого ежегодного испытания, обслуживания и ремонта; закапывание или замуровывание их без доступа сводит на нет программу. Источник: AWWA M14; нормы монтажа поставщика."},
  {id:474, q:"Чтобы установленное устройство предотвращения обратного потока было приемлемым в калифорнийской программе, оно, как правило, должно быть каким?", opts:["Самым дешёвым доступным устройством","Одобренной моделью (напр., в Списке USC FCCCHR или одобренном списке поставщика)","Любым самодельным устройством","Окрашенным в определённый цвет независимо от одобрения"], re:"Установленные устройства должны быть одобренными моделями, приемлемыми для поставщика — обычно теми, что в Списке USC FCCCHR или одобренном списке ведомства. Источник: List USC FCCCHR; требования CCCPH/поставщика."},
  {id:475, q:"Предохранительный клапан устройства принципа пониженного давления (RP) сбрасывает в атмосферу главным образом для того, чтобы сделать что?", opts:["Повысить давление ниже по потоку","Охладить здание","Сбросить воду из зоны для предотвращения обратного потока, когда обратные клапаны не уплотняют","Фильтровать воду"], re:"Предохранительный клапан RP открывается для сброса зоны пониженного давления в атмосферу, предотвращая обратный поток загрязнённой воды, когда обратные клапаны не удерживают. Источник: AWWA M14; процедуры полевых испытаний USC."},
  {id:476, q:"Поскольку предохранительный клапан устройства RP может сбрасывать воду, монтаж должен предусматривать что?", opts:["Полное отсутствие дренажа","Герметично запечатанную камеру","Погружение в зумпф","Адекватный дренаж/воздушный зазор у сброса предохранительного клапана"], re:"Монтаж RP должен обеспечивать адекватный дренаж и воздушный зазор у выпуска предохранительного клапана для обработки периодического или катастрофического сброса без затопления или обратного потока. Источник: AWWA M14; нормы монтажа."},
  {id:477, q:"Устройство двойного обратного клапана (DC) подходит для какого типа опасности?", opts:["Не связанных со здоровьем (pollutant), малоопасных применений","Высокоопасных для здоровья применений, таких как химические заводы","Подключений очистных сооружений сточных вод","Опасностей для здоровья в моргах и больницах"], re:"Устройство DC используется для не связанных со здоровьем (pollutant) малоопасных применений; опасности для здоровья (контаминанты) требуют AG или RP. Источник: AWWA M14; таблицы опасностей CCCPH/Title 17."},
  {id:478, q:"Какое устройство обеспечивает защиту как от обратного сифонирования, так и от обратного давления для подключения с опасностью для здоровья?", opts:["Напорный вакуумный прерыватель (PVB)","Устройство принципа пониженного давления (RP)","Только атмосферный (защищённый от выплёскивания) вакуумный прерыватель","Только вакуумный прерыватель шлангового крана"], re:"Устройство RP защищает как от обратного сифонирования, так и от обратного давления и приемлемо для подключений с опасностью для здоровья (контаминант); PVB/AVB защищают только от обратного сифонирования. Источник: AWWA M14; положения CCCPH об опасности."},
  {id:479, q:"Минимальные размеры воздушного зазора, используемого для контроля перекрёстных соединений, определены в каком стандарте, на который ссылается Калифорния?", opts:["NFPA 70E","Котловой кодекс и кодекс сосудов под давлением ASME","ASME A112.1.2","FMVSS 121"], re:"ASME A112.1.2 определяет минимальные воздушные зазоры для сантехнических приборов и упомянут в CCCPH для воздушных зазоров. Источник: CCCPH; ASME A112.1.2."},
  {id:480, q:"Воздушный зазор может быть сведён на нет (стать неэффективным) из-за чего из следующего?", opts:["Очистки раковины","Покраски прибора","Увеличения зазора значительно выше минимума","Погружения выпуска подачи или уменьшения зазора ниже минимума"], re:"Воздушный зазор перестаёт работать, если выпуск погружается или вертикальное расстояние уменьшается ниже требуемого минимума (2x диаметра трубы, минимум 1 дюйм). Источник: AWWA M14; ASME A112.1.2."},
  {id:481, q:"Почему устройства предотвращения обратного потока, как правило, должны устанавливаться в правильной ориентации (напр., RP и DC обычно горизонтально, если не одобрено иное)?", opts:["Потому что одобрение и правильная внутренняя работа зависят от монтажа согласно листингу/инструкциям производителя","Потому что вертикальные трубы незаконны","Чтобы соответствовать цвету здания","Ориентация никогда не имеет значения"], re:"Устройства одобряются и должны устанавливаться согласно их листингу и инструкциям производителя, включая ориентацию; неправильная ориентация может аннулировать одобрение и ухудшить работу/испытание. Источник: одобрение USC FCCCHR; AWWA M14; инструкции производителя."},
  {id:482, q:"Монтаж нового устройства предотвращения обратного потока в калифорнийской программе, как правило, требует чего, прежде чем на него можно будет полагаться?", opts:["Совершенно ничего","Разрешения/одобрения, требуемого поставщиком, и первоначального полевого испытания","Только устной договорённости","10-летнего периода ожидания"], re:"Новые установки подлежат одобрению/разрешению поставщика по мере необходимости и должны пройти первоначальное полевое испытание, прежде чем на них можно будет полагаться для защиты. Источник: CCCPH; требования поставщика к монтажу/разрешению."},
  {id:483, q:"Какое устройство, как правило, ограничено ситуациями только обратного сифонирования низкой-умеренной опасности и должно устанавливаться выше нижерасположенного трубопровода?", opts:["Воздушный зазор на подключении сточных вод","Устройство принципа пониженного давления (RP)","Напорный вакуумный прерыватель (PVB)","Двойной детекторный обратный клапан (пожарный) на химической подаче"], re:"PVB защищает только от обратного сифонирования, обычно ограничен применениями меньшей опасности и должен устанавливаться не менее чем на 12 дюймов выше самого высокого нижерасположенного выпуска. Источник: AWWA M14; руководство по применению/монтажу PVB."},
  {id:484, q:"Монтаж устройства предотвращения обратного потока ниже уровня земли в колодце без надлежащего дренажа создаёт какой риск?", opts:["Автоматическое соответствие всем кодексам","Улучшение вкуса воды","Более низкое давление воды, которое всегда желательно","Устройство может быть погружено в загрязнённую воду, сводя на нет защиту и функцию сброса"], re:"Установки ниже уровня земли/в колодце без дренажа рискуют погрузить устройство (и сбросной вентиль RP) в загрязнённую воду, сводя на нет защиту и создавая опасность обратного потока. Источник: AWWA M14; нормы монтажа."},
  {id:485, q:"Согласно OSHA, атмосфера считается обеднённой кислородом, когда концентрация кислорода падает ниже какого уровня?", opts:["19.5 процента кислорода по объёму","30 процентов кислорода по объёму","5 процентов кислорода по объёму","50 процентов кислорода по объёму"], re:"OSHA определяет обеднённую кислородом атмосферу как содержащую менее 19.5% кислорода по объёму. Источник: OSHA 29 CFR 1910.146 (Замкнутые пространства, требующие разрешения)."},
  {id:486, q:"Подземный колодец устройства обратного потока, достаточно большой, чтобы войти, с ограниченными средствами входа/выхода и не предназначенный для постоянного пребывания, лучше всего классифицировать как что?", opts:["Открытое поле","Замкнутое пространство","Стандартный офис","Кабину транспортного средства"], re:"Колодец/приямок, в который можно войти телом, с ограниченным входом/выходом и не предназначенный для постоянного пребывания, соответствует определению замкнутого пространства OSHA (и может требовать разрешения). Источник: определения OSHA 29 CFR 1910.146."},
  {id:487, q:"Перед входом в замкнутое пространство, требующее разрешения, внутренняя атмосфера должна быть проверена откалиброванным прибором прямого считывания в каком порядке?", opts:["Сначала горючие, затем токсичные, затем кислород","Сначала токсичные, затем кислород, затем горючие","Сначала кислород, затем горючие газы/пары, затем токсичные загрязнители","Порядок не имеет значения"], re:"OSHA требует проводить проверку в порядке: сначала содержание кислорода, затем горючие газы и пары, затем потенциальные токсичные загрязнители воздуха. Источник: OSHA 29 CFR 1910.146 Приложение B."},
  {id:488, q:"Почему кислород проверяется первым при оценке атмосферы замкнутого пространства?", opts:["Это произвольная традиция без причины","Кислород — единственная опасность, которая имеет значение","Токсичные вещества вообще нельзя измерить","Большинство измерителей горючих газов зависят от кислорода и дают ненадёжные показания при низком содержании кислорода"], re:"Кислород проверяется первым, потому что большинство измерителей горючих (взрывоопасных) газов зависят от кислорода и не дают надёжных показаний в обеднённой кислородом атмосфере. Источник: OSHA 29 CFR 1910.146 Приложение B."},
  {id:489, q:"Какая характеристика делает замкнутое пространство «требующим разрешения» замкнутым пространством согласно OSHA?", opts:["Оно содержит или могло бы содержать опасную атмосферу","В нём хорошее освещение","Оно недавно покрашено","Оно находится рядом со стоянкой"], re:"Замкнутое пространство, требующее разрешения, имеет одну или несколько опасностей: опасную атмосферу, потенциал поглощения, сходящуюся внутрь конфигурацию/возможность защемления или любую другую признанную серьёзную опасность. Источник: определения OSHA 29 CFR 1910.146."},
  {id:490, q:"Работник, испытывающий устройство обратного потока на проезжей части, должен носить светоотражающую защитную одежду, соответствующую какому требованию?", opts:["Никакой специальной одежды","ANSI/ISEA 107 Класс эффективности 2 или 3","Простую белую футболку","Тёмную одежду для скрытности"], re:"Работники, подвергающиеся воздействию транспорта в полосе отвода, должны носить светоотражающую одежду, соответствующую ANSI/ISEA 107 Класс эффективности 2 или 3. Источник: MUTCD Часть 6 (Временное регулирование движения); ANSI/ISEA 107."},
  {id:491, q:"Временное регулирование движения вокруг рабочей зоны на дороге общего пользования регулируется каким национальным документом?", opts:["Руководство AWWA M14","National Electrical Code","Manual on Uniform Traffic Control Devices (MUTCD), Часть 6","Правила EPA по хладагентам"], re:"MUTCD Часть 6 устанавливает стандарты для схем временного регулирования движения (рабочей зоны) на дорогах. Источник: FHWA MUTCD Часть 6."},
  {id:492, q:"Предохранительный клапан устройства RP может выбросить внезапную струю или брызги воды во время испытания. Что эта опасность означает для тестировщика?", opts:["Это гарантирует, что испытание пройдено","Это безвредно и может быть проигнорировано","Это означает, что манометр сломан","Быть готовым к выбросу воды и избегать травм глаз/лица и опасности поскользнуться"], re:"Вода под давлением может выбрасываться из предохранительного клапана или испытательных кранов; тестировщики должны защищать глаза/лицо, управлять опасностью поскользнуться и контролировать сброс. Источник: руководство по безопасности AWWA M14; инструкции производителя."},
  {id:493, q:"Почему тестировщик должен быть осторожен с обратным потоком загрязнённой воды при обслуживании устройства, защищающего помещения с опасностью для здоровья?", opts:["Загрязнённая вода может представлять серьёзный риск для здоровья, если достигнет тестировщика или питьевого водоснабжения","Это влияет только на счёт за воду","Загрязнённую воду всегда безопасно пить","Это улучшает качество воды"], re:"Устройства на подключениях с опасностью для здоровья могут удерживать загрязнённую воду; неправильное обращение во время обслуживания может подвергнуть тестировщика или питьевое водоснабжение воздействию, поэтому требуются осторожность и изоляция. Источник: AWWA M14; контекст опасности CCCPH."},
  {id:494, q:"Для входа в замкнутое пространство, требующее разрешения, OSHA требует наличия лица, размещённого снаружи пространства, для наблюдения за входящими. Как называется это лицо?", opts:["Сторонний наблюдатель","Дежурный (attendant)","Клиент","Сигнальщик (flagger)"], re:"OSHA требует наличия дежурного (attendant), размещённого снаружи замкнутого пространства, требующего разрешения, для наблюдения за входящими и приказа об эвакуации при необходимости. Источник: OSHA 29 CFR 1910.146."},
  {id:495, q:"Если замкнутое пространство, требующее разрешения, содержит опасную атмосферу, какой контроль OSHA требует до и во время входа там, где это осуществимо?", opts:["Добавление горючего газа","Герметичное запечатывание пространства","Принудительную вентиляцию для устранения/контроля опасной атмосферы","Удаление всего оборудования для мониторинга"], re:"Когда применяется, принудительная вентиляция из чистого источника должна устранять опасную атмосферу и продолжаться, пока работники находятся внутри; атмосфера должна оставаться безопасной во время пребывания. Источник: OSHA 29 CFR 1910.146."},
  {id:496, q:"Чтобы безопасно изолировать устройство обратного потока для ремонта, тестировщик, как правило, должен сделать что в первую очередь?", opts:["Повысить давление подачи","Открыть все испытательные краны под полным давлением и уйти","Немедленно перерезать трубу","Закрыть запорные клапаны выше и ниже по потоку для сброса давления с устройства"], re:"Изоляция устройства путём закрытия его запорных клапанов сбрасывает с него давление для безопасного обслуживания и предотвращает неконтролируемый выброс воды. Источник: AWWA M14; процедуры полевых испытаний/обслуживания USC."},
  {id:497, q:"Какова основная цель разрешения на вход для замкнутого пространства, требующего разрешения?", opts:["Задокументировать опасности, средства контроля и авторизацию перед входом","Собрать плату за парковку","Рекламировать работу","Заменить проверку атмосферы"], re:"Разрешение на вход документирует пространство, опасности, результаты проверки атмосферы, средства контроля и авторизацию и должно быть оформлено перед входом; оно дополняет, а не заменяет проверку. Источник: OSHA 29 CFR 1910.146."},
  {id:498, q:"Когда сигнальщики используются для регулирования движения в рабочей зоне, каково их основное устройство ручной сигнализации согласно MUTCD?", opts:["Только фонарик","Лопатка STOP/SLOW (СТОП/МЕДЛЕННО) (не менее 18 дюймов)","Только их голые руки","Только свисток"], re:"MUTCD требует, чтобы сигнальщики использовали лопатку STOP/SLOW (СТОП/МЕДЛЕННО) (не менее 18 дюймов) в качестве основного устройства ручной сигнализации и носили светоотражающую одежду. Источник: FHWA MUTCD Часть 6, Глава 6E (Регулирование сигнальщиком)."},
  {id:499, q:"При работе с водой под давлением как тестировщик должен обращаться с испытательными кранами и фитингами?", opts:["Бить по ним молотком, чтобы ослабить","Открывать их с максимальной скоростью","Открывать и закрывать их осторожно, предвидя выброс воды под давлением","Предполагать, что они никогда не находятся под давлением"], re:"Испытательные краны и фитинги могут внезапно выбросить воду под давлением; их медленное и аккуратное открывание/закрывание предотвращает травмы от брызг и потерю контроля над сбросом. Источник: руководство по безопасности AWWA M14; процедуры полевых испытаний."},
  {id:500, q:"В целом меры безопасности, которые соблюдает сертифицированный тестировщик (меры предосторожности в замкнутых пространствах, регулирование движения и контроль воды под давлением/загрязнённой воды), предназначены для защиты кого?", opts:["Никого в частности","Только прибыли водоснабжающей организации","Только производителя оборудования","Тестировщика, населения и системы питьевого водоснабжения"], re:"Меры безопасности на рабочем месте защищают тестировщика, население вокруг рабочей зоны и целостность системы питьевого водоснабжения, для защиты которой существует предотвращение обратного потока. Источник: OSHA 29 CFR 1910.146; MUTCD Часть 6; AWWA M14."}
];
